window.COURSE_REGISTRY = window.COURSE_REGISTRY || {};
window.COURSE_REGISTRY["backflow"] = [
  {id:1, block:1, sec:"What Is a Cross-Connection", q:"What is a cross-connection?", opts:["Any actual or potential connection between the potable water system and a source of pollution or contamination","A pipe joint that leaks under pressure","A valve that reduces water pressure at a service","An air gap between an outlet and a fixture rim"], correct:0, re:"EPA Cross-Connection Control Manual and AWWA M14 define a cross-connection as any actual or potential connection between a potable water system and any source of pollution or contamination."},
  {id:2, block:1, sec:"What Is a Cross-Connection", q:"A garden hose left submerged in a bucket of soapy water is an example of:", opts:["A code-approved air gap","An indirect cross-connection","A premises isolation assembly","A direct connection only"], correct:1, re:"EPA CCC Manual: a hose submerged in a non-potable source is a classic indirect (submerged-inlet) cross-connection that can permit backsiphonage."},
  {id:3, block:1, sec:"What Is a Cross-Connection", q:"A direct (solid-pipe) cross-connection is one in which:", opts:["There is always an air gap present","Water only spills through air into a vessel","The potable line is physically and permanently piped to the non-potable system","No backflow can ever occur"], correct:2, re:"AWWA M14 / EPA CCC Manual: a direct cross-connection is a permanent piped connection between potable and non-potable systems, and it can experience both backpressure and backsiphonage."},
  {id:4, block:1, sec:"What Is a Cross-Connection", q:"An indirect cross-connection (such as a submerged inlet) is generally subject to:", opts:["Neither backsiphonage nor backpressure","Backpressure only","Electrolysis only","Backsiphonage only"], correct:3, re:"USC FCCCHR / EPA CCC Manual: submerged-inlet (indirect) cross-connections open to atmosphere can experience backsiphonage only, whereas direct connections can see both modes."},
  {id:5, block:1, sec:"What Is a Cross-Connection", q:"Which situation is a cross-connection hazard?", opts:["A chemical-feed line solidly connected to the potable supply","A faucet spout terminating well above the sink rim","An air gap above a mop-sink rim","A pressure gauge teed into a clean water line"], correct:0, re:"EPA CCC Manual: a chemical-feed or process line connected to potable piping is a cross-connection because the non-potable substance can reverse into the drinking water."},
  {id:6, block:1, sec:"What Is a Cross-Connection", q:"Why are cross-connections a public-health concern?", opts:["They increase the water bill","They can allow non-potable substances to enter the drinking water supply","They only reduce water pressure","They cause pipe noise"], correct:1, re:"EPA CCC Manual: under backflow conditions, a cross-connection can draw or push contaminants and pollutants into the potable supply, threatening public health."},
  {id:7, block:1, sec:"What Is a Cross-Connection", q:"A lawn-irrigation system tied into a building's potable water is considered a cross-connection because:", opts:["Irrigation water is always cleaner than tap water","Sprinklers cannot hold pressure","Soil, fertilizer, and pesticides can be drawn back into the drinking water","It uses less water than fixtures"], correct:2, re:"EPA CCC Manual: irrigation systems are common cross-connections; backflow can pull contaminated water containing soil bacteria, fertilizer, or pesticides into the potable supply."},
  {id:8, block:1, sec:"What Is a Cross-Connection", q:"The term 'potable water' means water that is:", opts:["Stored in a non-pressurized tank","Used only for irrigation","Recycled from a cooling tower","Safe for human consumption and meets drinking-water standards"], correct:3, re:"AWWA M14: potable water is water that is safe for human consumption and meets applicable drinking-water quality standards."},
  {id:9, block:1, sec:"What Is a Cross-Connection", q:"'Non-potable water' is best described as water that is:", opts:["Not safe or not approved for human consumption","Always visibly dirty","Identical to potable water","Only found in fire lines"], correct:0, re:"AWWA M14: non-potable water is water that is not safe to drink or not of approved drinking-water quality, regardless of how it looks."},
  {id:10, block:1, sec:"What Is a Cross-Connection", q:"Which of the following is the most common everyday cross-connection in a home?", opts:["A buried copper service line","A garden hose","A pressure-reducing valve","A water meter"], correct:1, re:"EPA CCC Manual / USC FCCCHR: the ordinary garden hose is the most common residential cross-connection because it is easily submerged in contaminated sources."},
  {id:11, block:1, sec:"What Is a Cross-Connection", q:"A boiler with chemically treated water that is piped to the potable supply for make-up water represents:", opts:["A safe arrangement needing no protection","An approved air gap by itself","A cross-connection that must be protected against backflow","A condition that only affects hot water taste"], correct:2, re:"EPA CCC Manual: a treated-boiler make-up line is a cross-connection; treated boiler water is a hazard that must be isolated by an appropriate backflow preventer."},
  {id:12, block:1, sec:"What Is a Cross-Connection", q:"Which best distinguishes a direct from an indirect cross-connection?", opts:["There is no real difference","Direct ones are always temporary","Indirect ones are always larger pipes","Direct ones are piped together; indirect ones discharge through open atmosphere or a submerged inlet"], correct:3, re:"AWWA M14 / EPA CCC Manual: a direct cross-connection is a permanent piped link; an indirect one occurs at an open or submerged inlet such as a hose or tank fill."},
  {id:13, block:1, sec:"What Is a Cross-Connection", q:"A wash basin where the faucet outlet sits below the flood-level rim creates:", opts:["A submerged inlet, which is a cross-connection","A proper air gap","A premises isolation point","A reduced-pressure zone"], correct:0, re:"EPA CCC Manual: when an outlet can be submerged below the flood rim, the required air gap is lost and a submerged-inlet cross-connection exists."},
  {id:14, block:1, sec:"What Is a Cross-Connection", q:"Cross-connection control is primarily concerned with protecting:", opts:["The customer's water heater warranty","The public potable water supply from contamination","The water meter from freezing","Sewer pipes from collapse"], correct:1, re:"EPA CCC Manual / CA SWRCB Cross-Connection Control Policy Handbook: the goal of cross-connection control is to protect the public potable water supply from contamination by backflow."},
  {id:15, block:1, sec:"What Is a Cross-Connection", q:"Which statement about cross-connections is correct?", opts:["Only industrial sites can have them","They exist only when actively flowing backward","A potential connection counts even if backflow is not occurring right now","They are always visible to the customer"], correct:2, re:"AWWA M14 / EPA CCC Manual: a cross-connection includes any actual OR potential connection; the hazard exists whether or not backflow is happening at the moment."},
  {id:16, block:1, sec:"What Is a Cross-Connection", q:"A fire-protection sprinkler system connected to the potable supply is a cross-connection mainly because:", opts:["Sprinkler water is under higher pressure than the main at all times","It removes the need for a meter","Sprinkler pipe is always metal","Stagnant water and additives in the system can flow back into the potable supply"], correct:3, re:"EPA CCC Manual / AWWA M14: fire systems hold stagnant water and sometimes additives; without protection, that water can backflow into the potable supply."},
  {id:17, block:1, sec:"What Is a Cross-Connection", q:"The phrase 'auxiliary water supply' in cross-connection work refers to:", opts:["Any water source other than the public water system, such as a well or stored water","A second potable meter","A backup electrical supply","The fire department connection only"], correct:0, re:"AWWA M14 / CA Title 17: an auxiliary water supply is any source other than the public water system (well, pond, reclaimed, stored water) that could backflow into the potable supply."},
  {id:18, block:1, sec:"Backsiphonage vs Backpressure", q:"Backflow is best defined as:", opts:["The normal forward flow of water in a main","The undesirable reversal of flow from its intended direction through a cross-connection","Water hammer in a closed system","The pressure drop across a meter"], correct:1, re:"AWWA M14 / EPA CCC Manual: backflow is the undesirable reversal of the normal direction of flow of water or other substances through a cross-connection into the potable supply."},
  {id:19, block:1, sec:"Backsiphonage vs Backpressure", q:"Backsiphonage is caused by:", opts:["A downstream pump pushing water back","A check valve held open by debris","Negative (sub-atmospheric) pressure in the supply piping","Thermal expansion of hot water"], correct:2, re:"EPA CCC Manual / AWWA M14: backsiphonage results from negative or reduced pressure (a partial vacuum) in the supply system, which siphons water back through a cross-connection."},
  {id:20, block:1, sec:"Backsiphonage vs Backpressure", q:"Backpressure backflow occurs when:", opts:["Supply pressure exceeds downstream pressure","The water main is shut off","An air gap is installed","Downstream pressure becomes greater than the supply pressure"], correct:3, re:"AWWA M14 / EPA CCC Manual: backpressure backflow happens when pressure on the customer side (from a pump, boiler, or elevated tank) exceeds the supply pressure and overcomes it."},
  {id:21, block:1, sec:"Backsiphonage vs Backpressure", q:"Which event is a typical cause of backsiphonage?", opts:["A water-main break or heavy firefighting demand nearby","A booster pump on the customer's side","An elevated storage tank on the roof","A steam boiler"], correct:0, re:"EPA CCC Manual: main breaks, hydrant flushing, and high firefighting demand drop the supply pressure and can create the partial vacuum that causes backsiphonage."},
  {id:22, block:1, sec:"Backsiphonage vs Backpressure", q:"Which source most commonly creates backpressure?", opts:["A nearby fire hydrant being opened","A pump, boiler, or elevated tank on the customer's side","A break in the city main","Flushing of the distribution system"], correct:1, re:"AWWA M14 / EPA CCC Manual: pumps, boilers, pressure vessels, and elevated piping or tanks on the customer side raise downstream pressure above the main and cause backpressure."},
  {id:23, block:1, sec:"Backsiphonage vs Backpressure", q:"The everyday analogy of 'drinking through a straw' best describes:", opts:["Backpressure","An air gap","Backsiphonage","Water hammer"], correct:2, re:"EPA CCC Manual: backsiphonage works like sipping through a straw, where reduced pressure (suction) pulls liquid back up the line."},
  {id:24, block:1, sec:"Backsiphonage vs Backpressure", q:"A direct cross-connection can experience:", opts:["Backsiphonage only","Backpressure only","Neither condition","Both backsiphonage and backpressure"], correct:3, re:"AWWA M14 / USC FCCCHR: because a direct cross-connection is solidly piped, it can be subject to both backpressure and backsiphonage."},
  {id:25, block:1, sec:"Backsiphonage vs Backpressure", q:"During a large water-main break, the loss of pressure in the distribution system can cause:", opts:["Backsiphonage that pulls contaminants toward the main","Backpressure from boilers","An increase in chlorine residual","Water hammer in fire lines only"], correct:0, re:"EPA CCC Manual: a main break lowers system pressure and can create a vacuum, drawing contaminated water back through unprotected cross-connections (backsiphonage)."},
  {id:26, block:1, sec:"Backsiphonage vs Backpressure", q:"Backpressure is most likely where the customer's system includes:", opts:["Only gravity-fed fixtures","A pressure source such as a pump or pressurized vessel","A single hose bibb","A simple kitchen faucet"], correct:1, re:"AWWA M14: backpressure requires a downstream source of higher pressure, such as a booster pump, recirculation pump, or pressurized tank or boiler."},
  {id:27, block:1, sec:"Backsiphonage vs Backpressure", q:"Which is a common cause of negative pressure leading to backsiphonage?", opts:["Slowly filling a storage tank","A closed isolation valve at a single fixture","A high-demand event such as firefighting that draws the main down","Normal nighttime low demand"], correct:2, re:"EPA CCC Manual: sudden high withdrawal (firefighting, main flushing) or a main break can drop pressure below atmospheric, producing backsiphonage."},
  {id:28, block:1, sec:"Backsiphonage vs Backpressure", q:"The two recognized types of backflow are:", opts:["Static and dynamic flow","Backflow and overflow","Siphon and gravity flow","Backsiphonage and backpressure"], correct:3, re:"AWWA M14 / EPA CCC Manual: backflow occurs by exactly two mechanisms, backsiphonage (reduced supply pressure) and backpressure (elevated downstream pressure)."},
  {id:29, block:1, sec:"Backsiphonage vs Backpressure", q:"An elevated rooftop tank that is hard-piped into the potable supply can create:", opts:["Backpressure from the static head of the elevated water","Backsiphonage only","An air gap","A reduced-pressure zone"], correct:0, re:"AWWA M14 / EPA CCC Manual: the static head of an elevated tank or column of water can exceed supply pressure and push water back, a backpressure condition."},
  {id:30, block:1, sec:"Backsiphonage vs Backpressure", q:"Which statement is true about backsiphonage?", opts:["It requires a pump on the customer side","It is driven by a drop in supply-side pressure","It cannot occur during a main break","It only affects hot-water lines"], correct:1, re:"EPA CCC Manual: backsiphonage is driven entirely by a reduction in supply-side pressure (a partial vacuum), not by any downstream pumping."},
  {id:31, block:1, sec:"Backsiphonage vs Backpressure", q:"A backflow preventer selected to stop backpressure must be able to:", opts:["Rely on gravity alone","Work only when there is a vacuum","Hold back flow even when downstream pressure exceeds supply pressure","Be installed without any check valves"], correct:2, re:"AWWA M14: backpressure-rated assemblies (such as RP and double-check assemblies) must seal against higher downstream pressure, unlike vacuum breakers rated for backsiphonage only."},
  {id:32, block:1, sec:"Backsiphonage vs Backpressure", q:"Why is identifying the type of backflow important when selecting protection?", opts:["It changes the meter size","It has no effect on device choice","It determines the water bill","Some devices stop only backsiphonage, while others also handle backpressure"], correct:3, re:"AWWA M14 / USC FCCCHR: device selection depends on the backflow mode; for example, atmospheric vacuum breakers protect against backsiphonage only, not backpressure."},
  {id:33, block:1, sec:"Backsiphonage vs Backpressure", q:"Sub-atmospheric pressure in a water line means the pressure is:", opts:["Below atmospheric pressure (a partial vacuum)","Above the supply main pressure","Exactly at atmospheric pressure","The same as downstream pressure"], correct:0, re:"EPA CCC Manual: sub-atmospheric (negative) pressure is below atmospheric, creating the partial vacuum responsible for backsiphonage."},
  {id:34, block:1, sec:"Backsiphonage vs Backpressure", q:"A booster pump that raises a customer's pressure above the city main can create:", opts:["Backsiphonage","Backpressure backflow if the supply check fails or is absent","An air gap","Lower hazard conditions"], correct:1, re:"AWWA M14 / EPA CCC Manual: a customer booster pump can push pressure above the main and cause backpressure backflow unless an adequate preventer is in place."},
  {id:35, block:1, sec:"Degree of Hazard", q:"In cross-connection terminology, the 'degree of hazard' refers to:", opts:["How far the assembly is from the meter","The pipe diameter","Whether the substance is a pollutant (non-health) or a contaminant (health) hazard","The water pressure in psi"], correct:2, re:"USC FCCCHR / AWWA M14: degree of hazard classifies a cross-connection by the substance involved, either a pollutant (non-health hazard) or a contaminant (health hazard)."},
  {id:36, block:1, sec:"Degree of Hazard", q:"A 'contaminant' in cross-connection control is a substance that:", opts:["Only affects taste, odor, or color","Is harmless in any amount","Always lowers water pressure","Could create a health hazard, causing illness or death if it enters the water"], correct:3, re:"USC FCCCHR / EPA CCC Manual: a contaminant is a health hazard; if it enters the potable supply it could cause illness or death (for example sewage or pesticides)."},
  {id:37, block:1, sec:"Degree of Hazard", q:"A 'pollutant' in cross-connection control is a substance that:", opts:["Would impair water quality or be objectionable but is not a health hazard","Always causes disease","Is the same as a contaminant","Cannot affect the water at all"], correct:0, re:"USC FCCCHR / AWWA M14: a pollutant is a non-health (low) hazard that degrades quality or is aesthetically objectionable but does not endanger health."},
  {id:38, block:1, sec:"Degree of Hazard", q:"Which is considered a HIGH (health) hazard cross-connection?", opts:["A food-grade carbonated-beverage line","A connection to a sewage or wastewater source","A cold-water line to a drinking fountain","A clean rooftop rain collector for irrigation only"], correct:1, re:"USC FCCCHR / EPA CCC Manual: a connection to sewage or wastewater is a severe health hazard because pathogens could enter the potable supply."},
  {id:39, block:1, sec:"Degree of Hazard", q:"A non-health (pollutant) hazard would typically be protected by an air gap, a reduced-pressure assembly, OR:", opts:["No protection at all","A simple shutoff valve","A double check valve assembly","A pressure gauge"], correct:2, re:"USC FCCCHR / AWWA M14: low (non-health) hazards may be protected by an air gap, RP, or double check valve assembly; high hazards require an air gap or RP."},
  {id:40, block:1, sec:"Degree of Hazard", q:"A HIGH (health) hazard cross-connection must be protected by at least:", opts:["A hose-bibb vacuum breaker only","A check valve only","A double check valve assembly only","An air gap or a reduced-pressure principle assembly"], correct:3, re:"USC FCCCHR / CA Title 17: health-hazard cross-connections require the highest protection, an air gap or a reduced-pressure principle (RP) assembly."},
  {id:41, block:1, sec:"Degree of Hazard", q:"Who typically determines the degree of hazard at a customer's premises?", opts:["The water supplier or its cross-connection control program, through survey","The customer alone","The plumber who installed the fixtures","The fire department"], correct:0, re:"CA Title 17 / SWRCB CCC Policy Handbook: the water supplier evaluates the degree of hazard through surveys and assigns the required level of protection."},
  {id:42, block:1, sec:"Degree of Hazard", q:"Which substance class is generally treated as a contaminant (health hazard)?", opts:["Aesthetic discoloration from harmless minerals","Sewage, chemicals, or pesticides","Air bubbles in the line","Slightly warm water"], correct:1, re:"USC FCCCHR / EPA CCC Manual: sewage, toxic chemicals, and pesticides are contaminants because they pose a direct health hazard if backflowed."},
  {id:43, block:1, sec:"Degree of Hazard", q:"The selection of a backflow preventer should be 'commensurate with the degree of hazard,' which means:", opts:["Use the cheapest device available","Always use the smallest device","Match the protection level to how dangerous the substance is","Protection level does not depend on hazard"], correct:2, re:"CA Title 17 / AWWA M14: the type of protection must be commensurate with the degree of hazard, so higher hazards demand higher-rated assemblies."},
  {id:44, block:1, sec:"Degree of Hazard", q:"A connection that would only cause an objectionable taste or odor, with no health risk, is classified as a:", opts:["Health hazard","Sewage hazard","Lethal hazard","Non-health (pollutant) hazard"], correct:3, re:"USC FCCCHR: a substance affecting only taste, odor, or appearance without endangering health is a non-health (pollutant) hazard."},
  {id:45, block:1, sec:"Degree of Hazard", q:"Why must a health-hazard connection never be protected by a device rated only for pollutants?", opts:["A lower-rated device may not reliably stop a dangerous contaminant","It would cost too little","Pollutant devices are illegal everywhere","There is no difference in protection"], correct:0, re:"USC FCCCHR / AWWA M14: under-protecting a health hazard risks allowing a dangerous contaminant into the potable supply, so the assembly must match the hazard."},
  {id:46, block:1, sec:"Degree of Hazard", q:"Which of these is most likely a LOW (non-health) hazard?", opts:["A medical aspirator","A connection to a lawn-sprinkler system without chemical injection","A connection to a chemical plating tank","A mortuary table"], correct:1, re:"EPA CCC Manual: a basic lawn-sprinkler system without added chemicals is generally a low hazard, while medical, plating, and mortuary connections are high hazards."},
  {id:47, block:1, sec:"Degree of Hazard", q:"When the hazard at a site is uncertain or could change, the program generally:", opts:["Ignores the connection","Removes all protection","Treats it as the higher hazard to be safe","Lowers the protection level"], correct:2, re:"AWWA M14 / SWRCB CCC Policy Handbook: where the hazard is unknown or variable, the conservative approach is to assume the higher hazard and protect accordingly."},
  {id:48, block:1, sec:"Degree of Hazard", q:"A chemical-injection system (such as a fertilizer injector on irrigation) raises the hazard because it:", opts:["Reduces pressure in the line","Makes the water potable","Adds an air gap automatically","Introduces toxic chemicals that could backflow into the potable supply"], correct:3, re:"EPA CCC Manual / USC FCCCHR: adding chemical injection turns an otherwise low-hazard irrigation system into a health hazard, requiring an RP or air gap."},
  {id:49, block:1, sec:"Degree of Hazard", q:"The terms 'health hazard' and 'non-health hazard' correspond respectively to:", opts:["Contaminant and pollutant","Pollutant and contaminant","Direct and indirect","Backpressure and backsiphonage"], correct:0, re:"USC FCCCHR / AWWA M14: a health hazard is a contaminant; a non-health hazard is a pollutant."},
  {id:50, block:1, sec:"Degree of Hazard", q:"Assigning the degree of hazard is important because it:", opts:["Sets the customer's water rate","Determines the type and minimum rating of backflow protection required","Determines the meter color","Has no practical effect"], correct:1, re:"CA Title 17 / AWWA M14: the degree of hazard directly drives which backflow-prevention method is acceptable for the connection."},
  {id:51, block:1, sec:"Air Gap & Basic Separation", q:"An air gap is:", opts:["A mechanical check valve","A pressure-relief port","A physical, vertical separation between a water outlet and the flood-level rim of a receiving vessel","A type of hose connection"], correct:2, re:"AWWA M14 / EPA CCC Manual: an air gap is the unobstructed vertical physical separation between the lowest point of a water outlet and the flood-level rim of the receptacle below it."},
  {id:52, block:1, sec:"Air Gap & Basic Separation", q:"The minimum air gap is generally:", opts:["Equal to the outlet diameter","At least four times the pipe diameter, minimum 3 inches","Exactly 1/2 inch in all cases","At least twice the diameter of the effective opening, but never less than 1 inch"], correct:3, re:"AWWA M14 / Uniform Plumbing Code / CA HSC: the minimum air gap is twice the effective opening diameter and in no case less than 1 inch (the '2D, never less than 1 inch' rule)."},
  {id:53, block:1, sec:"Air Gap & Basic Separation", q:"An air gap protects against:", opts:["Both backsiphonage and backpressure","Backpressure only","Backsiphonage only","Neither type of backflow"], correct:0, re:"AWWA M14 / EPA CCC Manual: a properly sized air gap is the most reliable method and protects against both backsiphonage and backpressure because there is no physical pipe path."},
  {id:54, block:1, sec:"Air Gap & Basic Separation", q:"The air gap is generally regarded as:", opts:["The least effective backflow protection","The maximum (most reliable) protection against backflow","Equal to a hose-bibb vacuum breaker","Useful only for low pressure"], correct:1, re:"AWWA M14 / USC FCCCHR: when correctly installed and maintained, the air gap provides the highest degree of protection of any method."},
  {id:55, block:1, sec:"Air Gap & Basic Separation", q:"An air gap is measured from the:", opts:["Top of the faucet handle to the floor","Center of the pipe to the wall","Lowest point of the water outlet down to the flood-level rim of the fixture","Outlet to the bottom of the basin"], correct:2, re:"AWWA M14 / UPC: the air gap is the vertical distance from the lowest opening of the supply outlet to the flood-level rim of the receiving vessel."},
  {id:56, block:1, sec:"Air Gap & Basic Separation", q:"A key limitation of the air gap as backflow protection is that it:", opts:["Cannot stop backpressure","Only works above 80 psi","Requires annual electrical testing","Can be easily defeated by adding a hose or extension to the outlet"], correct:3, re:"EPA CCC Manual: although highly effective, an air gap is easily bypassed (for example by attaching a hose), so it must be maintained and not modified."},
  {id:57, block:1, sec:"Air Gap & Basic Separation", q:"If a water outlet is submerged below the flood-level rim, the air gap is:", opts:["Eliminated, creating a cross-connection","Increased","Doubled","Unaffected"], correct:0, re:"AWWA M14 / EPA CCC Manual: once the outlet is at or below the flood rim it is a submerged inlet; the air gap no longer exists and a cross-connection is formed."},
  {id:58, block:1, sec:"Air Gap & Basic Separation", q:"For a 1-inch effective opening, the minimum air gap would be:", opts:["1/2 inch","2 inches","1 inch","4 inches"], correct:1, re:"AWWA M14 / UPC: twice the 1-inch effective opening equals 2 inches, which also satisfies the 1-inch minimum, so the required gap is 2 inches."},
  {id:59, block:1, sec:"Air Gap & Basic Separation", q:"For a very small outlet (for example 1/4 inch), the minimum air gap is:", opts:["1/2 inch (twice the opening)","1/4 inch","1 inch, because the gap is never less than 1 inch","Zero"], correct:2, re:"AWWA M14 / UPC: twice 1/4 inch is only 1/2 inch, but the rule sets an absolute minimum of 1 inch, so 1 inch governs."},
  {id:60, block:1, sec:"Air Gap & Basic Separation", q:"A nearby wall close to the outlet affects the air gap requirement by:", opts:["Reducing the required gap","Eliminating the need for a gap","Having no effect","Increasing the required gap because the wall can disrupt the air separation"], correct:3, re:"UPC / plumbing code: a near wall can interfere with the free air path, so codes require a larger air gap (for example 3x the diameter) when the outlet is close to a wall."},
  {id:61, block:1, sec:"Air Gap & Basic Separation", q:"Which best describes why an air gap cannot be overcome by pressure?", opts:["There is no physical pipe connecting the two sides, so no pressure path exists","It uses a spring-loaded check","It is electrically powered","It relies on a relief valve"], correct:0, re:"AWWA M14 / EPA CCC Manual: because the air gap is an open break to atmosphere with no piping across it, neither backpressure nor backsiphonage can carry water across it."},
  {id:62, block:1, sec:"Air Gap & Basic Separation", q:"An air gap is most appropriate where:", opts:["Continuous pressurized flow downstream of the gap is required","An open discharge into a tank or receptor is acceptable","A flame is present","Only backpressure exists"], correct:1, re:"AWWA M14: an air gap suits open discharges (tank fills, drains, receptors) where downstream pressure is not needed, since the gap breaks the line to atmosphere."},
  {id:63, block:1, sec:"Air Gap & Basic Separation", q:"The flood-level rim referenced in air-gap measurement is:", opts:["The bottom of the basin","The faucet outlet","The top edge over which water would overflow the vessel","The drain opening"], correct:2, re:"AWWA M14 / UPC: the flood-level rim is the top edge of a fixture or vessel from which water would overflow, and it is the reference point for the air gap."},
  {id:64, block:1, sec:"Air Gap & Basic Separation", q:"Compared with a mechanical backflow assembly, an air gap:", opts:["Has internal parts that can wear out","Requires electricity","Must be tested with gauges annually","Has no moving parts to wear or fail"], correct:3, re:"USC FCCCHR / AWWA M14: an air gap is non-mechanical with no moving parts, so it cannot wear out, though it can be defeated if physically altered."},
  {id:65, block:1, sec:"Air Gap & Basic Separation", q:"An acceptable air gap on a mop-sink supply means the spout:", opts:["Terminates at least the required distance above the flood-level rim","Discharges below the rim","Is connected to a hose touching the floor","Is submerged when the sink fills"], correct:0, re:"AWWA M14 / EPA CCC Manual: the spout must end at least the required air-gap distance above the flood rim so it can never be submerged."},
  {id:66, block:1, sec:"Air Gap & Basic Separation", q:"Why is the air gap considered the basic form of backflow separation?", opts:["It is the newest technology","It is the simplest and most positive separation between potable and non-potable water","It needs the most maintenance","It only works on hot water"], correct:1, re:"EPA CCC Manual / AWWA M14: the air gap is the original and most positive separation method, the benchmark against which mechanical assemblies are compared."},
  {id:67, block:1, sec:"Air Gap & Basic Separation", q:"If a piece of equipment requires pressurized water and an open air gap cannot be used, the alternative is to:", opts:["Leave the connection unprotected","Reduce the water pressure to zero","Install an appropriate mechanical backflow-prevention assembly","Submerge the outlet"], correct:2, re:"AWWA M14 / USC FCCCHR: where a pressurized, closed connection is needed, an approved mechanical assembly (such as an RP or double check) replaces the air gap."},
  {id:68, block:1, sec:"Containment vs Isolation", q:"In cross-connection control, 'containment' (premises isolation) means installing protection:", opts:["At every fixture inside the building","Only at the water heater","Only on the hot-water line","At or near the service connection to protect the public water main"], correct:3, re:"EPA CCC Manual / CA SWRCB CCC Policy Handbook: containment (premises isolation) places a backflow preventer at the service connection to protect the public main from the entire premises."},
  {id:69, block:1, sec:"Containment vs Isolation", q:"'Isolation' (fixture protection) in cross-connection control means protecting:", opts:["Each individual cross-connection or fixture within the premises","The whole site at the meter only","Only the city main","The fire hydrant"], correct:0, re:"EPA CCC Manual: isolation (internal/fixture protection) addresses each cross-connection at its point of use within the building's plumbing."},
  {id:70, block:1, sec:"Containment vs Isolation", q:"A containment assembly is typically located:", opts:["At the farthest fixture from the meter","Just downstream of the water meter or service entrance","Inside the water heater","On the building roof"], correct:1, re:"CA SWRCB CCC Policy Handbook / EPA CCC Manual: the containment (premises isolation) assembly sits immediately downstream of the meter or at the service entrance."},
  {id:71, block:1, sec:"Containment vs Isolation", q:"The main purpose of containment is to protect:", opts:["The building's occupants","The customer's appliances","The public water distribution system from the customer's premises","The sewer system"], correct:2, re:"EPA CCC Manual: containment protects the public water system; it does not by itself protect people inside the building from internal cross-connections."},
  {id:72, block:1, sec:"Containment vs Isolation", q:"The main purpose of isolation (internal protection) is to protect:", opts:["Only the public main","The street pavement","The water meter","People and water quality within the building at each cross-connection"], correct:3, re:"EPA CCC Manual: isolation protects the occupants and the in-building water quality by addressing each individual cross-connection at its source."},
  {id:73, block:1, sec:"Containment vs Isolation", q:"A complete cross-connection control approach often uses:", opts:["Both containment at the service and isolation at internal hazards","Isolation only","Containment only","Neither, relying on water treatment"], correct:0, re:"EPA CCC Manual / AWWA M14: best practice combines containment (premises isolation) at the service with isolation of internal hazards for layered protection."},
  {id:74, block:1, sec:"Containment vs Isolation", q:"Why does containment alone not protect building occupants?", opts:["Because it stops only hot water","Because an internal cross-connection can still contaminate water inside the building, downstream of the containment device","Because it has no check valves","Because it raises pressure"], correct:1, re:"EPA CCC Manual: a containment device at the meter does not stop contamination that occurs from cross-connections inside the building, downstream of it."},
  {id:75, block:1, sec:"Containment vs Isolation", q:"Water suppliers most commonly require which approach as a minimum to protect the public main?", opts:["Isolation of every fixture by the utility","No protection","Containment (premises isolation) at the service connection","Treatment at the customer's tap"], correct:2, re:"CA Title 17 / SWRCB CCC Policy Handbook: utilities generally require containment at the service connection as their primary means to protect the public distribution system."},
  {id:76, block:1, sec:"Containment vs Isolation", q:"Premises isolation is another name for:", opts:["Fixture-level protection","Sewer isolation","An air gap at every sink","Containment at the service connection"], correct:3, re:"CA SWRCB CCC Policy Handbook: 'premises isolation' and 'containment' both refer to protecting the public system with an assembly at the service connection."},
  {id:77, block:1, sec:"Containment vs Isolation", q:"Internal (point-of-use) protection of a single laboratory faucet is an example of:", opts:["Isolation","Containment","Premises isolation","Service protection"], correct:0, re:"EPA CCC Manual: protecting one specific fixture, such as a lab faucet, at its point of use is isolation (fixture protection), not whole-premises containment."},
  {id:78, block:1, sec:"Containment vs Isolation", q:"For a high-hazard facility, the water supplier typically requires containment AND:", opts:["Removal of the meter","Internal isolation of the specific hazards by the owner","Lower water pressure","No further action"], correct:1, re:"AWWA M14 / SWRCB CCC Policy Handbook: high-hazard sites usually need containment at the service plus owner-provided isolation of the internal hazards."},
  {id:79, block:1, sec:"Containment vs Isolation", q:"Which statement correctly contrasts containment and isolation?", opts:["Isolation is installed at the meter only","They are identical","Containment protects the public main; isolation protects each internal cross-connection","Containment protects only fixtures"], correct:2, re:"EPA CCC Manual / AWWA M14: containment is service-level protection of the public system, while isolation is point-of-use protection of each internal cross-connection."},
  {id:80, block:1, sec:"Containment vs Isolation", q:"A backflow assembly installed immediately after the meter on an entire apartment building is performing:", opts:["Isolation","Thermal expansion control","Air-gap separation","Containment (premises isolation)"], correct:3, re:"CA SWRCB CCC Policy Handbook: an assembly serving the whole building at the meter is containment (premises isolation) for the public system."},
  {id:81, block:1, sec:"Containment vs Isolation", q:"From the water purveyor's standpoint, containment is valuable because it:", opts:["Provides a single, testable barrier protecting the public system from the whole premises","Eliminates the need for any internal plumbing review","Lowers the customer's water bill","Removes all internal hazards"], correct:0, re:"EPA CCC Manual / AWWA M14: containment gives the purveyor one defined, testable assembly to protect the public main from everything beyond the service."},
  {id:82, block:1, sec:"Containment vs Isolation", q:"Isolation protection is generally the responsibility of:", opts:["The water supplier only","The property owner / customer for hazards within their plumbing","The fire department","The state only"], correct:1, re:"CA Title 17 / EPA CCC Manual: internal (isolation) protection of in-building cross-connections is the customer/owner's responsibility, often enforced via plumbing code."},
  {id:83, block:1, sec:"Containment vs Isolation", q:"Which scenario shows a need for BOTH containment and isolation?", opts:["A single-family home with only a kitchen faucet","An empty lot","A hospital with many internal high-hazard connections served from one main","A drinking fountain in a park"], correct:2, re:"AWWA M14 / EPA CCC Manual: facilities with multiple internal high hazards (such as hospitals) need containment at the service plus isolation of each internal hazard."},
  {id:84, block:1, sec:"Terminology & Responsibilities", q:"The 'service connection' in cross-connection control is:", opts:["The hose bibb at the back of a house","The sewer cleanout","The water heater inlet","The point where the public water system connects to the customer's piping"], correct:3, re:"AWWA M14 / CA Title 17: the service connection is the point of delivery where the public water system meets the customer's plumbing, often at or just past the meter."},
  {id:85, block:1, sec:"Terminology & Responsibilities", q:"A 'water purveyor' (water supplier) is:", opts:["The agency or utility that owns and operates the public water system","The plumber who installs fixtures","The backflow tester","The state legislature"], correct:0, re:"AWWA M14 / CA Title 17: the water purveyor or supplier is the entity that owns and operates the public water system delivering potable water to customers."},
  {id:86, block:1, sec:"Terminology & Responsibilities", q:"Under California Title 17, who is generally responsible for protecting the public water system at the service connection?", opts:["The customer's insurance company","The water supplier (purveyor)","The fire department","The county assessor"], correct:1, re:"CA Title 17 (CCR sections 7583-7605): the water supplier is charged with protecting the public water system at each service connection through a cross-connection control program."},
  {id:87, block:1, sec:"Terminology & Responsibilities", q:"Who typically pays for and installs a required backflow-prevention assembly at a service connection?", opts:["Always the manufacturer","The state water board","The water user (customer), at their expense","The neighboring property"], correct:2, re:"CA Title 17: a required backflow assembly is installed by and at the expense of the water user at each connection where the supplier requires it."},
  {id:88, block:1, sec:"Terminology & Responsibilities", q:"How often must backflow-prevention assemblies generally be tested under California requirements?", opts:["Once every five years","Never after installation","Only when they fail","At least annually, and after installation, relocation, or repair"], correct:3, re:"CA Title 17 / SWRCB CCC Policy Handbook: backflow assemblies must be tested at least once a year and upon installation, relocation, or repair."},
  {id:89, block:1, sec:"Terminology & Responsibilities", q:"A backflow-prevention ASSEMBLY differs from a backflow-prevention DEVICE mainly because an assembly:", opts:["Includes shutoff valves and test cocks so it can be field-tested","Has no internal parts","Cannot be tested","Is always non-mechanical"], correct:0, re:"AWWA M14 / USC FCCCHR: a testable 'assembly' includes resilient-seated shutoff valves and test cocks, allowing in-line field testing, unlike a non-testable 'device.'"},
  {id:90, block:1, sec:"Terminology & Responsibilities", q:"A certified backflow assembly tester's primary role is to:", opts:["Design the water main","Test, and report on, backflow assemblies to verify they function correctly","Set the customer's water rates","Read the electric meter"], correct:1, re:"AWWA M14 / CA Title 17: the certified tester performs the required periodic tests and documents whether each assembly is operating properly."},
  {id:91, block:1, sec:"Terminology & Responsibilities", q:"The overall goal of a cross-connection control program is to:", opts:["Increase water sales","Lower the building's heating bill","Protect the public potable water supply from contamination by backflow","Speed up water flow"], correct:2, re:"EPA CCC Manual / CA SWRCB CCC Policy Handbook: a cross-connection control program exists to safeguard the public potable supply against backflow contamination."},
  {id:92, block:1, sec:"Terminology & Responsibilities", q:"'Approved' backflow assemblies in California are generally those:", opts:["Chosen at random by the installer","Only homemade units","Any device sold at a hardware store","Tested and listed by a recognized authority such as USC FCCCHR"], correct:3, re:"CA Title 17 / USC FCCCHR: California recognizes assemblies that have passed laboratory and field evaluation, such as those on the USC FCCCHR approved list."},
  {id:93, block:1, sec:"Terminology & Responsibilities", q:"An unprotected cross-connection with the public water supply is:", opts:["Prohibited under cross-connection control regulations","Permitted if the customer agrees","Required by code","Only an issue for industrial sites"], correct:0, re:"CA Title 17: unprotected cross-connections with the public water supply are prohibited; required protection must be in place and maintained."},
  {id:94, block:1, sec:"Terminology & Responsibilities", q:"A cross-connection control 'survey' or inspection is used to:", opts:["Measure the water bill","Identify cross-connections and assess the degree of hazard at a premises","Test the soil","Read the gas meter"], correct:1, re:"EPA CCC Manual / CA Title 17: the supplier conducts surveys to locate cross-connections and evaluate the degree of hazard so proper protection can be required."},
  {id:95, block:1, sec:"Terminology & Responsibilities", q:"Records of backflow assembly tests are important because they:", opts:["Set the water pressure","Replace the need for any device","Document that each assembly was tested and found operable, as required by regulation","Determine pipe color"], correct:2, re:"CA Title 17 / AWWA M14: test records demonstrate regulatory compliance and confirm each assembly was tested and functioning, and are reported to the supplier."},
  {id:96, block:1, sec:"Terminology & Responsibilities", q:"The 'point of delivery' generally marks:", opts:["The sewer outfall","The water treatment plant","The fire hydrant","The boundary where the supplier's responsibility ends and the customer's begins"], correct:3, re:"AWWA M14: the point of delivery (service connection) is the dividing line between the supplier's and the customer's water systems and responsibilities."},
  {id:97, block:1, sec:"Terminology & Responsibilities", q:"Why must a tester be certified before testing assemblies in California?", opts:["To ensure tests are performed correctly so public-health protection is reliably verified","For tax purposes","To set water rates","It is not actually required"], correct:0, re:"CA Title 17 / AWWA M14: only certified testers may test assemblies, ensuring competent, consistent verification that the public-health barrier works."},
  {id:98, block:1, sec:"Terminology & Responsibilities", q:"If a backflow assembly fails its test, the proper response is to:", opts:["Ignore it until next year","Repair or replace it promptly and retest to restore protection","Remove all protection","Increase the water pressure"], correct:1, re:"AWWA M14 / CA Title 17: a failed assembly must be repaired or replaced and retested without delay because the cross-connection is unprotected until it passes."},
  {id:99, block:1, sec:"Terminology & Responsibilities", q:"The customer's main responsibility in cross-connection control is to:", opts:["Operate the public water main","Set the supplier's policies","Install, maintain, and have tested the required backflow protection on their premises","Certify other testers"], correct:2, re:"CA Title 17: the water user is responsible for installing, maintaining, and arranging required testing of backflow protection on their side of the service connection."},
  {id:100, block:1, sec:"Terminology & Responsibilities", q:"Which agency adopted California's statewide Cross-Connection Control Policy Handbook governing backflow protection?", opts:["The U.S. Department of Energy","The local fire marshal","The Federal Communications Commission","The State Water Resources Control Board (SWRCB)"], correct:3, re:"CA SWRCB: the State Water Resources Control Board adopted the Cross-Connection Control Policy Handbook (effective July 1, 2024) governing cross-connection control statewide."},
  {id:101, block:2, sec:"Reduced Pressure (RP/RPDA)", q:"What two primary internal valve components make up the core of a reduced pressure principle (RP) assembly?", opts:["Two independently acting check valves with a differential relief valve between them","A single check valve and an atmospheric air inlet","One check valve and two relief valves in series","A float-operated air inlet and a single check valve"], correct:0, re:"An RP consists of two independently acting, spring-loaded check valves with a hydraulically operating, mechanically independent differential-pressure relief valve located between them. Source: AWWA M14; USC FCCCHR 10th ed."},
  {id:102, block:2, sec:"Reduced Pressure (RP/RPDA)", q:"Against which backflow condition(s) is an RP assembly effective?", opts:["Backsiphonage only","Backpressure only","Both backpressure and backsiphonage","Neither, it only reduces pressure"], correct:2, re:"An RP is effective against both backpressure backflow and backsiphonage. Source: AWWA M14; USC FCCCHR 10th ed."},
  {id:103, block:2, sec:"Reduced Pressure (RP/RPDA)", q:"What level of hazard may an RP assembly be used to protect against?", opts:["Non-health hazards only","Aesthetic (color/odor) hazards only","Backsiphonage hazards only","Health hazards (and non-health hazards)"], correct:3, re:"An RP may be used to isolate health (high) hazards as well as non-health hazards, making it the highest-level testable assembly. Source: AWWA M14; CA Title 17 §7603."},
  {id:104, block:2, sec:"Reduced Pressure (RP/RPDA)", q:"Where is the differential-pressure relief valve located in an RP assembly?", opts:["Between the two check valves (in the reduced-pressure zone)","Upstream of both check valves","Downstream of the second check valve","Inside the second check valve housing"], correct:0, re:"The relief valve sits in the zone between the two check valves and below the first check valve, sensing the differential across the first check. Source: AWWA M14; CA Title 17 §7603(c)."},
  {id:105, block:2, sec:"Reduced Pressure (RP/RPDA)", q:"During normal operation, the pressure in the zone between the two checks of an RP must be at least how much lower than the supply (inlet) pressure?", opts:["2 psi lower","10 psi lower","Equal to supply pressure","0.5 psi lower"], correct:0, re:"The zone of reduced pressure must remain at least 2 psi below the supply-side pressure during normal operation. Source: AWWA M14; USC FCCCHR 10th ed."},
  {id:106, block:2, sec:"Reduced Pressure (RP/RPDA)", q:"How many test cocks are provided on a standard RP assembly?", opts:["Two","Three","Four","One"], correct:2, re:"A standard RP has four properly located, resilient-seated test cocks for field testing the checks and relief valve. Source: AWWA M14; USC FCCCHR 10th ed."},
  {id:107, block:2, sec:"Reduced Pressure (RP/RPDA)", q:"How many resilient-seated shutoff valves are part of a complete RP assembly?", opts:["One","Four","Two (inlet and outlet)","None"], correct:2, re:"A complete RP includes two tightly closing resilient-seated shutoff valves, one at the inlet and one at the outlet. Source: AWWA M14; USC FCCCHR 10th ed."},
  {id:108, block:2, sec:"Reduced Pressure (RP/RPDA)", q:"When does the relief valve of an RP open and discharge water to atmosphere?", opts:["Only during normal forward flow","Continuously whenever the assembly is pressurized","When the differential across the first check drops to about 2 psi or the first check leaks","Only when both shutoff valves are closed"], correct:2, re:"The relief valve opens to dump the zone to atmosphere when the differential across the first check falls toward ~2 psi (e.g., first check fouling or a backflow event), maintaining the reduced-pressure zone. Source: AWWA M14."},
  {id:109, block:2, sec:"Reduced Pressure (RP/RPDA)", q:"How must the relief valve discharge of an RP be terminated?", opts:["Directly connected to a sanitary sewer","Capped to prevent any spillage","Through an air gap to an approved drain or grade","Routed back into the assembly inlet"], correct:2, re:"The relief discharge must terminate through an air gap over an approved receptor or to grade; a direct (submerged) sewer connection is prohibited. Source: AWWA M14; CA Title 17."},
  {id:110, block:2, sec:"Reduced Pressure (RP/RPDA)", q:"Why should an RP assembly never be installed in a pit or below-grade vault subject to flooding?", opts:["The relief valve discharge could be submerged, defeating the air gap and creating a cross-connection","The test cocks would freeze faster underground","Check valve springs corrode only below grade","Pits increase the supply pressure too much"], correct:0, re:"If a flooded pit submerges the relief port, the air gap is lost and contaminated water can be drawn back in; RP assemblies must not be located where flooding can submerge the relief valve. Source: AWWA M14."},
  {id:111, block:2, sec:"Reduced Pressure (RP/RPDA)", q:"The lowest part of the RP relief valve discharge port is typically required to be at least how far above the floor/grade or flood level?", opts:["12 inches","1 inch","6 inches","36 inches"], correct:0, re:"The relief discharge port is generally required to be a minimum of 12 inches above the ground, top of enclosure opening, or maximum flood level, whichever is highest. Source: AWWA M14 installation guidance."},
  {id:112, block:2, sec:"Reduced Pressure (RP/RPDA)", q:"What does the acronym 'RP' stand for in backflow assembly terminology?", opts:["Relief Preventer","Reverse Pressure assembly","Reduced Pressure principle backflow prevention assembly","Regulated Pipe assembly"], correct:2, re:"RP stands for Reduced Pressure principle backflow prevention assembly (also written RPZ or RPBA). Source: AWWA M14; USC FCCCHR 10th ed."},
  {id:113, block:2, sec:"Reduced Pressure (RP/RPDA)", q:"An RPDA (reduced pressure detector assembly) is primarily used on what type of service?", opts:["Residential drinking fountains","Hose bibbs","Fire-protection (fire sprinkler) lines where leak/theft detection is required","Atmospheric irrigation outlets"], correct:2, re:"An RPDA is an RP-based assembly with a metered bypass used on fire lines to detect low flows from leaks or unauthorized water use. Source: AWWA M14."},
  {id:114, block:2, sec:"Reduced Pressure (RP/RPDA)", q:"The metered bypass line of an RPDA contains which of the following?", opts:["A second relief valve only","An atmospheric vacuum breaker","A small RP (or check) assembly with a low-flow detector meter","A pressure-reducing valve only"], correct:2, re:"The RPDA bypass routes low flows through a parallel small RP assembly fitted with a detector (registration) meter to capture leaks or unauthorized use. Source: AWWA M14."},
  {id:115, block:2, sec:"Reduced Pressure (RP/RPDA)", q:"Compared with a double check assembly, the RP provides what?", opts:["Less protection","The same protection","A higher (greater) level of protection","No backflow protection at all"], correct:2, re:"The RP provides a higher level of protection than a DC because its relief valve actively dumps the zone if a check fails; it is rated for health hazards, while a DC is not. Source: AWWA M14; CA Title 17 hazard ranking."},
  {id:116, block:2, sec:"Reduced Pressure (RP/RPDA)", q:"Which statement about RP relief valve discharge during a fouled first check is correct?", opts:["Visible water discharge from the relief port can indicate a fouled or leaking first check valve","The relief port should never discharge under any condition","Discharge means the second check has failed only","Discharge proves the assembly is installed backward"], correct:0, re:"Intermittent or continuous relief discharge commonly signals a fouled/leaking first check (or fluctuating supply pressure); the relief valve is doing its protective job by dumping the zone. Source: AWWA M14; manufacturer service literature."},
  {id:117, block:2, sec:"Reduced Pressure (RP/RPDA)", q:"In an RP, the relief valve operation is described as which of the following?", opts:["Electrically actuated","Manually opened by the tester only","Hydraulically operated and mechanically independent of the checks","Driven by a float in the air inlet"], correct:2, re:"The RP relief valve is a hydraulically operating, mechanically independent differential-pressure relief valve referenced to supply pressure. Source: AWWA M14; CA Title 17 §7603(c)."},
  {id:118, block:2, sec:"Double Check (DC/DCDA)", q:"A double check valve assembly (DC) consists of which arrangement?", opts:["One check valve and a relief valve","An air inlet and a single check valve","Two independently acting check valves in series","A relief valve between two air inlets"], correct:2, re:"A DC is two single, independently acting check valves arranged in series, with shutoff valves at each end and test cocks. Source: AWWA M14; USC FCCCHR 10th ed."},
  {id:119, block:2, sec:"Double Check (DC/DCDA)", q:"For what hazard level is a double check valve assembly approved?", opts:["Health (high) hazards","Sewage connections","Non-health (low) hazards only","Chemical injection systems"], correct:2, re:"A DC is used to isolate non-health hazards (pollutants) only; it is not approved for health hazards. Source: AWWA M14; CA Title 17 §7603."},
  {id:120, block:2, sec:"Double Check (DC/DCDA)", q:"Against which backflow conditions is a DC effective?", opts:["Backsiphonage only","Backpressure only","Both backpressure and backsiphonage","Neither condition"], correct:2, re:"A DC is effective against both backpressure and backsiphonage (for non-health hazards). Source: AWWA M14; USC FCCCHR 10th ed."},
  {id:121, block:2, sec:"Double Check (DC/DCDA)", q:"How many test cocks does a standard DC assembly have?", opts:["One","Two","Four","Six"], correct:2, re:"A DC has four properly located test cocks used to measure the differential across each check. Source: AWWA M14; ASSE 1015."},
  {id:122, block:2, sec:"Double Check (DC/DCDA)", q:"What is the typical minimum acceptable differential each check valve of a DC must hold when tested?", opts:["1.0 psid","5.0 psid","0.1 psid","10 psid"], correct:0, re:"Each check of a DC is generally required to hold a minimum of about 1.0 psid in the direction of flow to pass. Source: AWWA M14; USC FCCCHR 10th ed."},
  {id:123, block:2, sec:"Double Check (DC/DCDA)", q:"Why are two checks used in series in a DC rather than one?", opts:["To double the flow rate","To create an air gap","To eliminate the need for shutoff valves","To provide redundancy so the second check still seals if the first leaks"], correct:3, re:"The series arrangement provides redundancy: if one check fails to seal, the other still provides protection. Source: AWWA M14."},
  {id:124, block:2, sec:"Double Check (DC/DCDA)", q:"A double check detector assembly (DCDA) is most commonly installed on what?", opts:["Drinking fountains","Boiler feed lines with chemicals","Dishwashers","Fire-protection (fire sprinkler) supply lines"], correct:3, re:"A DCDA is a DC with a metered bypass installed on non-health-hazard fire lines to detect leaks or unauthorized use. Source: AWWA M14."},
  {id:125, block:2, sec:"Double Check (DC/DCDA)", q:"The bypass on a DCDA is designed to register flows up to approximately what rate before the main checks open?", opts:["About 2 to 5 gpm (low flow)","About 50 gpm","About 500 gpm","Only flows above 100 gpm"], correct:0, re:"The bypass detector meter captures low flows (roughly up to ~2-5 gpm); larger flows open the mainline checks. Source: AWWA M14 (DCDA bypass design)."},
  {id:126, block:2, sec:"Double Check (DC/DCDA)", q:"On a DCDA, the differential pressure setting of the bypass relative to the main checks is designed so that:", opts:["Low flows are forced through the metered bypass first","All flow always bypasses the mainline checks","The mainline opens before any bypass flow","The bypass never registers flow"], correct:0, re:"The bypass is set with a slightly lower differential than the mainline checks so low flows register on the bypass meter before the main checks open. Source: AWWA M14."},
  {id:127, block:2, sec:"Double Check (DC/DCDA)", q:"A primary purpose of the detector meter on a DCDA/RPDA fire line is to:", opts:["Increase fire flow capacity","Reduce the supply pressure","Replace the need for annual testing","Reveal small leaks or unauthorized (unmetered) water use"], correct:3, re:"The detector meter alerts the utility to leaks or unauthorized diversion that could go unnoticed on an otherwise unmetered fire line. Source: AWWA M14."},
  {id:128, block:2, sec:"Double Check (DC/DCDA)", q:"How many shutoff valves are included on a complete DC assembly?", opts:["None","One","Two (inlet and outlet)","Four"], correct:2, re:"A DC includes two tightly closing resilient-seated shutoff valves for isolation during testing and maintenance. Source: AWWA M14; ASSE 1015."},
  {id:129, block:2, sec:"Double Check (DC/DCDA)", q:"Which of the following is an example of a non-health hazard that a DC would typically protect?", opts:["A medical/dental aspirator","A sewage ejector connection","A chemical feed (injection) system","A lawn-irrigation system with no chemical injection"], correct:3, re:"Plain irrigation without chemical injection is generally a non-health (pollutant) hazard suitable for DC protection; chemical injection or sewage would require an RP or air gap. Source: AWWA M14; CA Title 17 hazard evaluation."},
  {id:130, block:2, sec:"Double Check (DC/DCDA)", q:"Unlike an RP, a double check assembly does NOT include which component?", opts:["A second check valve","An inlet shutoff valve","A differential-pressure relief valve","Test cocks"], correct:2, re:"A DC has no relief valve; that is the defining difference from an RP and why a DC cannot dump the zone if a check fouls. Source: AWWA M14."},
  {id:131, block:2, sec:"Double Check (DC/DCDA)", q:"Because a DC has no relief port, it may be installed in which location where an RP cannot?", opts:["Submerged in a sewer","Directly on a sewage line","Inside a pressurized chemical tank","Below grade in a vault (where flooding of a relief port is not a concern), if otherwise permitted"], correct:3, re:"Lacking a relief discharge, a DC may be placed in a vault/below-grade setting where an RP would be prohibited due to flooding of its relief port (subject to local rules on access and drainage). Source: AWWA M14."},
  {id:132, block:2, sec:"Double Check (DC/DCDA)", q:"The check valves in a DC are described as being:", opts:["Force-loaded (spring-loaded) to the closed position","Loaded to the open position","Held closed only by gravity","Electrically held closed"], correct:0, re:"Each DC check is internally force-loaded (spring-loaded) to the closed position so it seals independently. Source: AWWA M14; ASSE 1015."},
  {id:133, block:2, sec:"Double Check (DC/DCDA)", q:"What does the acronym 'DCDA' stand for?", opts:["Double Check Drain Assembly","Differential Check Detector Array","Dual Cylinder Discharge Apparatus","Double Check Detector Assembly"], correct:3, re:"DCDA stands for Double Check Detector Assembly. Source: AWWA M14; USC FCCCHR 10th ed."},
  {id:134, block:2, sec:"Double Check (DC/DCDA)", q:"Which standard commonly applies to double check valve backflow prevention assemblies?", opts:["ASSE 1015 / AWWA C510","ASSE 1056 only","40 CFR Part 82","ASME boiler code"], correct:0, re:"DC assemblies commonly conform to ASSE 1015 and AWWA C510 (and USC FCCCHR approval). Source: AWWA M14; ASSE 1015; AWWA C510."},
  {id:135, block:2, sec:"PVB & SVB", q:"A pressure vacuum breaker (PVB) assembly contains which two operating elements?", opts:["Two check valves and a relief valve","A relief valve and an air gap","Two air inlets in series","A single spring-loaded check valve and a force-loaded air inlet valve"], correct:3, re:"A PVB has one independently operating, spring-loaded (force-loaded closed) check valve and an air inlet valve downstream that is force-loaded to the open position. Source: AWWA M14; ASSE 1020."},
  {id:136, block:2, sec:"PVB & SVB", q:"Against which backflow condition is a PVB approved?", opts:["Backpressure only","Neither","Both backpressure and backsiphonage","Backsiphonage only"], correct:3, re:"A PVB protects against backsiphonage only; it must not be used where backpressure can occur. Source: AWWA M14; CA Title 17 §7603."},
  {id:137, block:2, sec:"PVB & SVB", q:"A PVB must be installed at least how far above the highest downstream piping/outlet?", opts:["6 inches","24 inches","1 inch","12 inches"], correct:3, re:"A PVB must be installed at least 12 inches above all downstream piping and the highest outlet (or flood-level rim). Source: CA Title 17 §7603(b); AWWA M14; UPC/IPC."},
  {id:138, block:2, sec:"PVB & SVB", q:"How many test cocks does a standard PVB assembly have?", opts:["One","None","Four","Two"], correct:3, re:"A PVB has two test cocks (one upstream and one downstream of the check), plus its inlet/outlet shutoffs. Source: AWWA M14; ASSE 1020."},
  {id:139, block:2, sec:"PVB & SVB", q:"A key advantage of a PVB over an atmospheric vacuum breaker (AVB) is that the PVB:", opts:["May be subjected to continuous water pressure","Provides backpressure protection","Needs no shutoff valves","Requires no testing"], correct:0, re:"Because its check is spring-loaded and it has test cocks/shutoffs, a PVB may be kept under continuous pressure, unlike an AVB. Source: AWWA M14; ASSE 1020."},
  {id:140, block:2, sec:"PVB & SVB", q:"In a PVB, the air inlet valve is loaded to which position?", opts:["Closed (force-loaded closed)","Locked shut during service","Floating, with no spring","Open (force-loaded open)"], correct:3, re:"The PVB air inlet is force-loaded to the OPEN position so it opens to admit air and break a vacuum when supply pressure drops. Source: AWWA M14; ASSE 1020."},
  {id:141, block:2, sec:"PVB & SVB", q:"In a PVB, the single check valve is loaded to which position?", opts:["Open","Reverse","Neutral/balanced","Closed (force-loaded closed)"], correct:3, re:"The PVB check valve is force-loaded to the closed position to seal against backsiphonage. Source: AWWA M14; ASSE 1020."},
  {id:142, block:2, sec:"PVB & SVB", q:"The main functional difference of a spill-resistant vacuum breaker (SVB) compared to a PVB is that the SVB:", opts:["Provides backpressure protection","Has four test cocks","Requires no elevation above downstream piping","Is designed to minimize/contain spillage when the air inlet opens"], correct:3, re:"An SVB uses a sealed/diaphragm air-inlet design to minimize water spillage on activation, making it better suited for indoor locations. Source: ASSE 1056; AWWA M14."},
  {id:143, block:2, sec:"PVB & SVB", q:"How many test cocks does a typical SVB have, distinguishing it physically from a PVB?", opts:["One (plus a vent/bleed valve)","Two","Four","Three"], correct:0, re:"An SVB typically has a single test cock plus a vent (bleed) valve, whereas a PVB has two test cocks. Source: ASSE 1056."},
  {id:144, block:2, sec:"PVB & SVB", q:"Like the PVB, the SVB is approved against which backflow condition?", opts:["Backpressure only","Thermal expansion only","Both conditions","Backsiphonage only"], correct:3, re:"The SVB, like the PVB, protects against backsiphonage only and must not be used where backpressure exists. Source: ASSE 1056; AWWA M14."},
  {id:145, block:2, sec:"PVB & SVB", q:"An SVB, like a PVB, must be installed at least how far above the highest downstream outlet?", opts:["12 inches","6 inches","1 inch","No minimum"], correct:0, re:"An SVB must be installed at least 12 inches above all downstream piping/outlets, the same minimum as a PVB. Source: ASSE 1056; AWWA M14; CA Title 17."},
  {id:146, block:2, sec:"PVB & SVB", q:"A common, appropriate application for a PVB is:", opts:["A boiler with chemical treatment under backpressure","A carbonated-beverage (carbonator) line","A sewage lift station","A lawn-irrigation system with no chemical injection and no backpressure"], correct:3, re:"PVBs are widely used on irrigation systems where only backsiphonage can occur; chemical injection (health hazard) or backpressure situations require an RP. Source: AWWA M14; CA Title 17."},
  {id:147, block:2, sec:"PVB & SVB", q:"Why must a PVB/SVB be installed in the vertical (upright) orientation?", opts:["So the test cocks face the technician","To allow horizontal flow only","To increase downstream pressure","So the air inlet and check operate correctly by gravity/spring action"], correct:3, re:"PVB/SVB assemblies are designed to function upright (vertical) so the float/poppet air inlet and check seat properly; other orientations void the listing. Source: ASSE 1020/1056 installation requirements."},
  {id:148, block:2, sec:"PVB & SVB", q:"What is the standard physically describing performance for spill-resistant vacuum breaker assemblies?", opts:["ASSE 1056","ASSE 1015","ASSE 1013","AWWA C511"], correct:0, re:"ASSE 1056 covers performance requirements for spill-resistant vacuum breaker assemblies. Source: ASSE 1056."},
  {id:149, block:2, sec:"PVB & SVB", q:"What is the standard commonly describing performance for pressure vacuum breaker assemblies?", opts:["ASSE 1020","ASSE 1056","ASSE 1015","ASSE 1011"], correct:0, re:"ASSE 1020 covers performance requirements for pressure vacuum breaker assemblies. Source: ASSE 1020."},
  {id:150, block:2, sec:"PVB & SVB", q:"When supply pressure drops below atmospheric in a PVB, the air inlet:", opts:["Stays closed and holds vacuum","Increases the downstream pressure","Discharges water to the sewer","Opens to admit air, breaking the siphon"], correct:3, re:"On loss of pressure the force-loaded air inlet opens to admit air, breaking the vacuum and preventing backsiphonage past the closed check. Source: AWWA M14; ASSE 1020."},
  {id:151, block:2, sec:"PVB & SVB", q:"The spill-resistant feature of an SVB makes it preferred over a PVB in which situation?", opts:["Outdoor irrigation in a freezing climate","Backpressure applications","Sewage applications","Indoor installations where atmospheric spillage cannot be tolerated"], correct:3, re:"Because it contains spillage, the SVB is preferred for indoor locations where a PVB's open vent discharge would be unacceptable. Source: ASSE 1056; AWWA M14."},
  {id:152, block:2, sec:"AVB & Other Devices", q:"An atmospheric vacuum breaker (AVB) is approved to protect against which condition only?", opts:["Backpressure","Thermal expansion","Both conditions","Backsiphonage"], correct:3, re:"An AVB protects against backsiphonage only and never against backpressure. Source: AWWA M14; CA Title 17 §7603."},
  {id:153, block:2, sec:"AVB & Other Devices", q:"A critical installation rule for an AVB is that there must be:", opts:["A pump downstream","Continuous backpressure","Four test cocks","No shutoff valve or control valve downstream of the AVB"], correct:3, re:"No shutoff or control valve may be located downstream of an AVB, because that would keep it under continuous pressure and could jam the air inlet. Source: AWWA M14; CA Title 17 §7603."},
  {id:154, block:2, sec:"AVB & Other Devices", q:"An AVB must be installed at least how far above the highest downstream outlet or flood-level rim?", opts:["6 inches","12 inches","1 inch","18 inches"], correct:0, re:"An AVB must be installed at least 6 inches above all downstream piping and the highest outlet/flood-level rim. Source: CA Title 17 §7603; AWWA M14; UPC/IPC."},
  {id:155, block:2, sec:"AVB & Other Devices", q:"An AVB may NOT be subjected to continuous pressure for more than how long in any 24-hour period?", opts:["12 hours","24 hours","1 hour","No limit"], correct:0, re:"An AVB may be under pressure no more than 12 hours out of any 24-hour period; longer can cause the air-inlet disc to stick. Source: CA Title 17 §7603; AWWA M14."},
  {id:156, block:2, sec:"AVB & Other Devices", q:"How many test cocks does a standard atmospheric vacuum breaker (AVB) have?", opts:["Four","Two","None (it is a non-testable device)","One"], correct:2, re:"An AVB has no test cocks or shutoffs as part of the device; it cannot be field-tested like an assembly and is considered a device, not a testable assembly. Source: AWWA M14; USC FCCCHR."},
  {id:157, block:2, sec:"AVB & Other Devices", q:"The internal moving part of an AVB is best described as:", opts:["A spring-loaded check and relief valve","A diaphragm relief valve","Two checks in series","A float/poppet (air-inlet disc) that seals the air port under flow and drops to admit air on loss of pressure"], correct:3, re:"An AVB uses a floating disc/poppet that is held up to seal the atmospheric port during flow and drops to open the port (admitting air) when pressure is lost. Source: AWWA M14; ASME A112.1.3."},
  {id:158, block:2, sec:"AVB & Other Devices", q:"Why must an AVB never have downstream backpressure applied?", opts:["It would over-pressurize the supply main","Backpressure improves its performance","It would open the relief valve","It has no check valve to resist backpressure and would allow backflow"], correct:3, re:"An AVB relies only on its air inlet for backsiphonage; it has no loaded check capable of holding backpressure, so backpressure would push contaminated water past it. Source: AWWA M14."},
  {id:159, block:2, sec:"AVB & Other Devices", q:"A hose connection (hose bibb) vacuum breaker is generally classified as which type of device?", opts:["A reduced pressure assembly","A pressure vacuum breaker assembly","A double check assembly","An atmospheric-type vacuum breaker (backsiphonage only)"], correct:3, re:"A hose bibb vacuum breaker (HBVB/HCVB) is an atmospheric-type vacuum breaker protecting against backsiphonage and should not be left under continuous pressure. Source: AWWA M14; ASSE 1011."},
  {id:160, block:2, sec:"AVB & Other Devices", q:"An air gap is defined by what minimum vertical separation relative to the effective opening?", opts:["Two times the effective opening diameter, and never less than 1 inch","One-half the pipe diameter","Equal to the pipe diameter, no minimum","Ten times the pipe diameter"], correct:0, re:"An approved air gap is at least two times the effective opening diameter and in no case less than 1 inch. Source: CA Title 17 §7602; AWWA M14; USC FCCCHR."},
  {id:161, block:2, sec:"AVB & Other Devices", q:"Among approved methods, which provides the highest level of backflow protection?", opts:["Atmospheric vacuum breaker","Double check assembly","Air gap separation","Pressure vacuum breaker"], correct:2, re:"An air gap (a physical separation) provides the highest level of protection because no mechanical part can fail. Source: AWWA M14; CA Title 17 ranking."},
  {id:162, block:2, sec:"AVB & Other Devices", q:"An AVB is an acceptable choice only when which conditions are met?", opts:["No backpressure and no continuous pressure (and no downstream shutoff)","Backpressure is present","It is installed below the outlets","A pump is located downstream"], correct:0, re:"An AVB applies only where there is no backpressure, no continuous pressure beyond 12 hr, and no downstream valve. Source: AWWA M14; CA Title 17."},
  {id:163, block:2, sec:"AVB & Other Devices", q:"Which device protects against backsiphonage only and CANNOT be field-tested with gauges like an assembly?", opts:["RP","DC","AVB","PVB"], correct:2, re:"The AVB is a non-testable device (no test cocks/shutoffs); RP, DC, and PVB are testable assemblies. Source: AWWA M14; USC FCCCHR."},
  {id:164, block:2, sec:"AVB & Other Devices", q:"Compared with an AVB, a PVB adds which capability while still being backsiphonage-only?", opts:["Backpressure protection","Continuous-pressure operation and field testability (test cocks/shutoffs)","An internal relief valve","An air gap"], correct:1, re:"A PVB keeps the air inlet spring-loaded and adds test cocks/shutoffs, allowing continuous-pressure operation and field testing the AVB cannot provide. Source: AWWA M14; ASSE 1020."},
  {id:165, block:2, sec:"AVB & Other Devices", q:"Why is an air gap immune to the failure modes of mechanical assemblies?", opts:["It contains stronger springs","It is a physical (non-mechanical) separation that cannot foul or wear","It is pressurized at all times","It uses two relief valves"], correct:1, re:"An air gap has no moving parts to foul, stick, or wear, so it cannot fail like a check or relief valve can. Source: AWWA M14; USC FCCCHR."},
  {id:166, block:2, sec:"AVB & Other Devices", q:"A laboratory faucet with a serrated (hose-thread) outlet in a building uses what point-of-use device class to guard against backsiphonage?", opts:["Reduced pressure assembly only","Vacuum breaker (atmospheric-type/hose connection vacuum breaker)","Double check detector assembly","Air inlet relief valve"], correct:1, re:"Hose-threaded laboratory/utility outlets are commonly protected by hose-connection (atmospheric-type) vacuum breakers against backsiphonage. Source: AWWA M14; ASSE 1011."},
  {id:167, block:2, sec:"AVB & Other Devices", q:"If continuous pressure or backpressure is possible at a non-health-hazard outlet that otherwise might use an AVB, the proper upgrade is to a:", opts:["Hose bibb cap","PVB/DC (or RP for a health hazard) capable of the service condition","Larger AVB","Second AVB in series"], correct:1, re:"Because an AVB cannot take continuous pressure or backpressure, the service is upgraded to a PVB (backsiphonage, continuous pressure) or DC/RP as the hazard and conditions dictate. Source: AWWA M14; CA Title 17."},
  {id:168, block:2, sec:"Internal Components", q:"What is the purpose of the test cocks on a backflow assembly?", opts:["To drain the building","To provide gauge connection points for field testing the checks/relief valve","To relieve thermal expansion","To admit air during backsiphonage"], correct:1, re:"Test cocks are small valves that let a certified tester connect a differential gauge to measure check tightness and relief-valve opening. Source: AWWA M14; USC FCCCHR."},
  {id:169, block:2, sec:"Internal Components", q:"In a backflow assembly, the resilient-seated shutoff valves are used primarily to:", opts:["Reduce supply pressure permanently","Isolate the assembly for testing and maintenance","Admit air to the system","Replace the relief valve"], correct:1, re:"The inlet and outlet shutoff valves isolate the assembly so it can be tested or serviced. Source: AWWA M14; ASSE standards."},
  {id:170, block:2, sec:"Internal Components", q:"The relief valve is a defining internal component of which assembly?", opts:["Double check (DC)","Pressure vacuum breaker (PVB)","Reduced pressure principle (RP)","Atmospheric vacuum breaker (AVB)"], correct:2, re:"Only the RP contains a differential-pressure relief valve; DC, PVB, and AVB do not. Source: AWWA M14."},
  {id:171, block:2, sec:"Internal Components", q:"The air inlet valve is a defining internal component of which device/assembly?", opts:["Reduced pressure assembly","Pressure/atmospheric vacuum breakers (PVB/AVB/SVB)","Double check assembly","RP detector assembly"], correct:1, re:"The air inlet (vent) valve is the characteristic component of vacuum breakers (PVB/SVB/AVB), used to break a siphon; DC/RP have no air inlet. Source: AWWA M14."},
  {id:172, block:2, sec:"Internal Components", q:"Check valves used in RP and DC assemblies are characterized as:", opts:["Independently acting and force-loaded (spring-loaded) closed","Loaded open by springs","Gravity-only flap checks","Manually operated"], correct:0, re:"Both RP and DC use independently acting, internally force-loaded (spring-loaded) check valves that seal against reverse flow. Source: AWWA M14; ASSE 1013/1015."},
  {id:173, block:2, sec:"Internal Components", q:"A 'resilient seat' on a check or shutoff valve refers to:", opts:["A metal-to-metal seat","An elastomeric (rubber-type) sealing surface for a tight, drop-tight seal","A ceramic disc with no gasket","A threaded brass plug"], correct:1, re:"Resilient (elastomeric) seats give the drop-tight seal required for backflow assemblies and their shutoffs. Source: AWWA M14; AWWA C510/C511."},
  {id:174, block:2, sec:"Internal Components", q:"On a four-test-cock assembly, test cock No. 1 is generally located:", opts:["Downstream of the second check","On the relief valve only","Upstream of the inlet shutoff/first check (supply side)","On the air inlet"], correct:2, re:"By convention, test cock No. 1 is on the supply side (upstream of the first check), with subsequent cocks numbered through the zone and downstream. Source: AWWA M14 test procedures."},
  {id:175, block:2, sec:"Internal Components", q:"On an RP, the test cock located in the zone between the two checks lets the tester measure:", opts:["Downstream system demand","The reduced-pressure zone pressure and relief-valve opening point","Air inlet float position","Supply main flow rate"], correct:1, re:"The zone test cock reads the reduced-pressure-zone pressure and is used to determine the relief valve opening differential. Source: AWWA M14 RP test procedure."},
  {id:176, block:2, sec:"Internal Components", q:"In a PVB, which component is force-loaded toward OPEN, the opposite loading of the check valve?", opts:["The inlet shutoff","The air inlet valve","The downstream test cock","The bonnet bolt"], correct:1, re:"The PVB air inlet is force-loaded open (the check is force-loaded closed), so it pops open to admit air on pressure loss. Source: AWWA M14; ASSE 1020."},
  {id:177, block:2, sec:"Internal Components", q:"What component would you find on an SVB that is NOT found on a standard PVB?", opts:["A diaphragm-sealed (spill-resistant) air inlet with a vent/bleed valve","A second relief valve","Two extra check valves","A float-operated air gap"], correct:0, re:"The SVB adds a diaphragm-sealed air inlet and a vent (bleed) valve to contain spillage, and uses a single test cock. Source: ASSE 1056."},
  {id:178, block:2, sec:"Internal Components", q:"The number of independently acting check valves in an RP and in a DC is:", opts:["One in each","Two in each","Three in the RP, two in the DC","Two in the RP, one in the DC"], correct:1, re:"Both the RP and the DC contain two independently acting check valves; the RP additionally has a relief valve between them. Source: AWWA M14."},
  {id:179, block:2, sec:"Internal Components", q:"What is the primary function of the check valve(s) in any of these assemblies?", opts:["To admit air to the line","To permit flow in one direction and seal against reverse flow","To reduce the line pressure to zero","To meter low flows"], correct:1, re:"Check valves allow forward flow and close to prevent reverse (back) flow, the basic barrier in DC, RP, and vacuum breakers. Source: AWWA M14."},
  {id:180, block:2, sec:"Internal Components", q:"On an RP, the relief valve senses pressure differential referenced to which point?", opts:["The downstream outlet","The supply (inlet) pressure versus the zone pressure","Atmospheric pressure only","The air inlet"], correct:1, re:"The relief valve compares supply (inlet) pressure to the reduced-pressure-zone pressure and opens when that differential drops toward ~2 psi. Source: AWWA M14."},
  {id:181, block:2, sec:"Internal Components", q:"A bleed/vent valve on an SVB is used during testing to:", opts:["Pressurize the downstream piping","Vent the bonnet/air-inlet chamber so the air inlet opening can be checked","Increase the spring load","Drain the entire building"], correct:1, re:"The SVB vent (bleed) valve releases pressure in the air-inlet chamber so the tester can verify the air inlet opens at the correct point. Source: ASSE 1056 test procedure."},
  {id:182, block:2, sec:"Internal Components", q:"Why are the two check valves in an RP/DC required to operate INDEPENDENTLY?", opts:["So both must be opened by the tester at once","So the failure or fouling of one check does not prevent the other from sealing","To share a single spring","To eliminate test cocks"], correct:1, re:"Independent operation means each check seals on its own, preserving redundancy if the other fouls or fails. Source: AWWA M14; ASSE 1013/1015."},
  {id:183, block:2, sec:"Internal Components", q:"Which internal component allows an RP to actively expel water from the central zone to atmosphere when protection is threatened?", opts:["The downstream check","The inlet shutoff valve","The differential-pressure relief valve","A test cock"], correct:2, re:"The differential-pressure relief valve discharges the zone to atmosphere through an air gap when the differential falls, which is unique to the RP. Source: AWWA M14."},
  {id:184, block:2, sec:"Selection, Application & Installation", q:"A restaurant carbonator (CO2 beverage system) connected to the potable supply requires which protection?", opts:["A double check assembly","A reduced pressure principle (RP) assembly","A pressure vacuum breaker","An atmospheric vacuum breaker"], correct:1, re:"A carbonator presents a health hazard (CO2 reacting with copper plus backpressure) and requires an RP assembly. Source: AWWA M14; CA Title 17 hazard tables."},
  {id:185, block:2, sec:"Selection, Application & Installation", q:"An irrigation system that injects fertilizer/pesticide chemicals (chemigation) requires which level of protection?", opts:["Atmospheric vacuum breaker","Pressure vacuum breaker","Double check assembly","Reduced pressure (RP) assembly or air gap"], correct:3, re:"Chemical injection makes the system a health hazard, requiring an RP assembly (or air gap); a DC/PVB/AVB is not sufficient. Source: AWWA M14; CA Title 17."},
  {id:186, block:2, sec:"Selection, Application & Installation", q:"When selecting an assembly, which two factors most directly drive the choice?", opts:["Pipe color and brand","The degree of hazard (health vs non-health) and the backflow type (backpressure vs backsiphonage only)","Installer preference and price only","Time of year and weather"], correct:1, re:"Selection is governed by the hazard level (health/non-health) and whether backpressure can occur (versus backsiphonage only). Source: AWWA M14; CA Title 17."},
  {id:187, block:2, sec:"Selection, Application & Installation", q:"For a non-health-hazard service where backpressure CAN occur, which assembly is appropriate?", opts:["Atmospheric vacuum breaker","Pressure vacuum breaker","Double check assembly","Hose bibb vacuum breaker"], correct:2, re:"A DC handles non-health hazards under both backpressure and backsiphonage; PVB/AVB cannot take backpressure. Source: AWWA M14; CA Title 17."},
  {id:188, block:2, sec:"Selection, Application & Installation", q:"A PVB or AVB must NOT be selected when which condition is present?", opts:["Backsiphonage only","Backpressure (downstream pump, elevation, or thermal expansion)","An open atmospheric outlet","A single irrigation zone"], correct:1, re:"Vacuum breakers (PVB/AVB) protect against backsiphonage only and must never be used where backpressure exists. Source: AWWA M14; CA Title 17."},
  {id:189, block:2, sec:"Selection, Application & Installation", q:"An RP assembly should be installed in which orientation/location for proper relief-valve function (unless listed otherwise)?", opts:["Submerged in a sump","Horizontally above grade with the relief port clear and a proper air gap to drainage","Inverted below the outlets","Inside a sealed, water-filled vault"], correct:1, re:"An RP is typically installed horizontally above grade with the relief discharge clear of submersion and draining through an air gap; it must not be installed where flooding can submerge the relief port. Source: AWWA M14."},
  {id:190, block:2, sec:"Selection, Application & Installation", q:"Adequate clearance around an installed assembly is required primarily to:", opts:["Improve appearance","Allow access for testing, repair, and relief/air-inlet discharge","Increase water pressure","Reduce the number of test cocks"], correct:1, re:"Clearances (e.g., around and below the assembly) are required so a tester can reach test cocks and shutoffs and so relief/air-inlet discharge is unobstructed. Source: AWWA M14 installation guidance."},
  {id:191, block:2, sec:"Selection, Application & Installation", q:"A premises with an auxiliary (private well) water source cross-connected to the public supply generally requires which protection at the service?", opts:["Atmospheric vacuum breaker","Double check assembly","Reduced pressure (RP) assembly or air gap","No protection"], correct:2, re:"An unapproved auxiliary supply is treated as a health hazard, requiring an RP assembly or air gap at the service connection. Source: AWWA M14; CA Title 17."},
  {id:192, block:2, sec:"Selection, Application & Installation", q:"A medical/dental office (aspirators, sterilizers) connected to potable water typically requires:", opts:["A reduced pressure (RP) assembly","A double check assembly","An atmospheric vacuum breaker","A hose bibb vacuum breaker"], correct:0, re:"Medical/dental facilities are health hazards (contaminant backflow risk) and require RP protection. Source: AWWA M14; CA Title 17 hazard tables."},
  {id:193, block:2, sec:"Selection, Application & Installation", q:"For a PVB to function, the relationship between the assembly and the system it serves must be:", opts:["The PVB at least 12 in above the highest downstream outlet","The PVB below the lowest outlet","The PVB at the same level as the outlets","The PVB submerged for cooling"], correct:0, re:"The PVB air inlet must sit at least 12 inches above the highest downstream outlet so it cannot be back-flooded and can break the siphon. Source: AWWA M14; CA Title 17 §7603(b)."},
  {id:194, block:2, sec:"Selection, Application & Installation", q:"Why must an RP never be installed in a location subject to flooding even though it gives the highest assembly protection?", opts:["Its relief discharge air gap can be submerged, creating a cross-connection","It would lose all backpressure rating","Flooding raises the supply pressure","The test cocks become decorative"], correct:0, re:"Submerging the relief discharge defeats the air gap and can siphon contaminated floodwater back into the potable line; RP relief ports must remain above flood level. Source: AWWA M14."},
  {id:195, block:2, sec:"Selection, Application & Installation", q:"A fire-sprinkler line using non-potable additives (antifreeze/foam) is a health hazard and requires which assembly?", opts:["Double check detector assembly (DCDA)","Reduced pressure detector assembly (RPDA)","Atmospheric vacuum breaker","Pressure vacuum breaker"], correct:1, re:"When a fire line contains chemical additives it becomes a health hazard requiring RP-level protection, i.e., an RPDA (RP with detector). A plain DCDA is only for non-health-hazard fire lines. Source: AWWA M14; CA Title 17."},
  {id:196, block:2, sec:"Selection, Application & Installation", q:"A standard (non-additive) fire-sprinkler line that is a non-health hazard but requires leak/usage detection typically uses:", opts:["A reduced pressure detector assembly","A double check detector assembly (DCDA)","An atmospheric vacuum breaker","A hose bibb vacuum breaker"], correct:1, re:"A non-health-hazard fire line needing detection uses a DCDA; an RPDA is reserved for health-hazard fire systems. Source: AWWA M14."},
  {id:197, block:2, sec:"Selection, Application & Installation", q:"When backpressure is possible at a HEALTH-hazard connection, the correct selection is:", opts:["Pressure vacuum breaker","Atmospheric vacuum breaker","Reduced pressure (RP) assembly or air gap","Double check assembly"], correct:2, re:"Health hazard plus backpressure requires the highest mechanical assembly (RP) or an air gap; PVB/AVB cannot take backpressure and a DC is not rated for health hazards. Source: AWWA M14; CA Title 17."},
  {id:198, block:2, sec:"Selection, Application & Installation", q:"Which installation practice is correct for a PVB serving lawn irrigation?", opts:["Install it in a buried box below the sprinkler heads","Install it upright at least 12 in above the highest head, accessible for testing","Lay it on its side at grade","Connect its bonnet vent to the sewer"], correct:1, re:"A PVB must be upright, at least 12 inches above the highest downstream outlet, and accessible for annual testing. Source: AWWA M14; ASSE 1020; CA Title 17 §7603(b)."},
  {id:199, block:2, sec:"Selection, Application & Installation", q:"The general ranking of protection from highest to lowest among approved methods is:", opts:["AVB > PVB > DC > RP > Air gap","Air gap > RP > PVB > DC > AVB","DC > RP > Air gap > PVB > AVB","PVB > AVB > RP > DC > Air gap"], correct:1, re:"Listed in decreasing protection: air gap, then RP, then PVB, then DC, then AVB. Source: CA Title 17; AWWA M14 hazard ranking."},
  {id:200, block:2, sec:"Selection, Application & Installation", q:"Before an assembly is selected, the most fundamental step required by cross-connection control programs is to:", opts:["Order the largest assembly available","Evaluate the degree of hazard and the type of backflow possible at the connection","Choose the cheapest device","Install the device, then test the hazard"], correct:1, re:"Proper protection follows a hazard evaluation: determine the health/non-health hazard and whether backpressure or only backsiphonage can occur, then select the matching assembly. Source: AWWA M14; CA Title 17 §7583 et seq."},
  {id:201, block:3, sec:"Differential Gauge Setup", q:"What does the test instrument used for field testing backflow assemblies actually measure?", opts:["The difference in pressure between two points, in pounds per square inch differential (psid)","The flow rate of water through the assembly in gallons per minute","The absolute static line pressure on the supply main","The water temperature at the relief valve discharge"], correct:0, re:"A backflow tester uses a differential pressure gauge that reads the pressure difference between its high and low sides in psid. Source: AWWA Manual M14; USC FCCCHR Field Test Procedures, 10th ed."},
  {id:202, block:3, sec:"Differential Gauge Setup", q:"A standard backflow differential pressure gauge is calibrated over what reading range?", opts:["0 to 150 psid","0 to 15 psid","0 to 5 psid","0 to 60 psid"], correct:1, re:"Field test gauges typically read 0-15 psid (0-100 kPa), which covers the small differentials seen across checks and relief valves. Source: Mid-West Instrument 845-5 gauge spec; AWWA M14."},
  {id:203, block:3, sec:"Differential Gauge Setup", q:"On a 3-valve differential gauge test kit, what are the three needle valves commonly called?", opts:["Inlet, outlet, and drain valves","Red, green, and blue valves","High control, low control, and bypass (vent) valves","Primary, secondary, and tertiary valves"], correct:2, re:"A 3-valve kit has a high-side control, a low-side control, and a bypass/vent (bleed) valve. Source: USC FCCCHR Field Test Procedures; AWWA M14 differential-gauge test kit description."},
  {id:204, block:3, sec:"Differential Gauge Setup", q:"Compared with a 3-valve kit, what extra valves does a 5-valve differential gauge test kit add?", opts:["A pressure-reducing valve and a relief valve","A second pressure gauge and a flow meter","Two extra hose connections only, with no added valves","Two additional bleed valves (a high bleed and a low bleed)"], correct:3, re:"A 5-valve kit adds dedicated high-side and low-side bleed valves to the high, low, and bypass valves, simplifying air removal. Source: Mid-West 845-5 5-valve kit; AWWA M14."},
  {id:205, block:3, sec:"Differential Gauge Setup", q:"Before recording any test, why must all air be bled out of the gauge hoses and body?", opts:["Because trapped air compresses and gives a false (inaccurate) differential reading","To prevent the hoses from freezing","To lower the supply line pressure before testing","To keep the test cocks from leaking"], correct:0, re:"Trapped air is compressible and distorts the differential reading, so hoses and the gauge must be purged of air before readings are taken. Source: USC FCCCHR Field Test Procedures; AWWA M14."},
  {id:206, block:3, sec:"Differential Gauge Setup", q:"Where should the differential pressure gauge be positioned relative to the assembly during a test?", opts:["At least 3 feet above the assembly","At approximately the same elevation as the assembly","Always below the assembly on the ground","Elevation does not matter for differential readings"], correct:1, re:"The gauge and hoses should be held at the same height as the assembly so that the water column in the hoses does not add an elevation error to the differential reading. Source: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:207, block:3, sec:"Differential Gauge Setup", q:"How often must a backflow tester's differential pressure gauge be calibrated, per common regulatory requirements?", opts:["Once every five years","Only when it is first purchased","At least annually","Once every month"], correct:2, re:"Most jurisdictions require the differential test gauge to be calibrated at least once a year, and the calibration date is recorded on the test report. Source: AWWA M14; state cross-connection program rules (e.g., NY DOH, Denver Water test report)."},
  {id:208, block:3, sec:"Differential Gauge Setup", q:"What is the purpose of the bleed (vent) valve on a differential gauge test kit?", opts:["To increase the supply pressure to the assembly","To shut off the customer's water supply","To measure the flow through check valve No. 1","To allow trapped air and water to escape so the hoses can be purged"], correct:3, re:"The bleed/vent valve lets air and water escape from the kit and hoses so the lines can be filled and air-free before a reading. Source: USC FCCCHR Field Test Procedures; AWWA M14."},
  {id:209, block:3, sec:"Differential Gauge Setup", q:"On a typical color-coded test kit, the HIGH side hose and the LOW side hose are usually which colors?", opts:["High = red, Low = green (or blue)","High = green, Low = red","High = yellow, Low = black","Both hoses are white"], correct:0, re:"Test kits commonly color the high-side hose red and the low-side hose green (or blue) so the tester connects each to the correct test cock. Source: AWWA M14; PNW-AWWA test procedure illustrations."},
  {id:210, block:3, sec:"Differential Gauge Setup", q:"Many test kits include 90-micron filter screens at the hose fittings. What is their main purpose?", opts:["To reduce the water pressure entering the gauge","To keep scale, sand, and debris from plugging the gauge passages","To warm the water before it reaches the gauge","To add chlorine to the test water"], correct:1, re:"Inline filter screens keep sand, scale and grit from entering and fouling the small internal passages of the differential gauge. Source: Mid-West Instrument test-kit literature; AWWA M14."},
  {id:211, block:3, sec:"Differential Gauge Setup", q:"What should a tester do to the test cocks before connecting the gauge hoses?", opts:["Leave them capped and connect over the caps","Paint them to mark which is which","Open each one briefly to flush out debris, then connect the hoses","Remove them entirely from the assembly"], correct:2, re:"Each test cock is opened briefly to flush dirt and debris out of the port before the hose is attached, protecting the gauge. Source: USC FCCCHR Field Test Procedures; AWWA M14."},
  {id:212, block:3, sec:"Differential Gauge Setup", q:"The stated accuracy of a typical backflow differential gauge is closest to which value?", opts:["Plus or minus 0.001 psid","Plus or minus 2 psid","Plus or minus 5 psid","Plus or minus 0.2 psid"], correct:3, re:"A typical field gauge is accurate to about plus or minus 0.2 psid on the descending reading. Source: Mid-West Instrument 845-5 specification; AWWA M14."},
  {id:213, block:3, sec:"Differential Gauge Setup", q:"When a test kit is connected with the high and low hoses on the same closed check, what reading should a properly bled, accurate gauge show?", opts:["Approximately zero psid (no differential) until pressures differ","The full line pressure","About 15 psid","A negative reading equal to atmospheric pressure"], correct:0, re:"With both sides sensing the same pressure and no differential applied, a properly bled gauge reads near zero; a non-zero static reading signals trapped air or a gauge problem. Source: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:214, block:3, sec:"Differential Gauge Setup", q:"What is the function of the 'bypass' (vent) valve when establishing flow conditions across a gauge during setup?", opts:["It permanently isolates the low side from the high side","It connects high and low sides so water can move through and purge the kit","It vents the supply main to atmosphere","It calibrates the needle to zero automatically"], correct:1, re:"Opening the bypass connects the high and low chambers so water flows through the kit, letting trapped air be carried out during purging. Source: USC FCCCHR Field Test Procedures; AWWA M14."},
  {id:215, block:3, sec:"Differential Gauge Setup", q:"Why is the high-side control valve typically left open for the duration of an RP or DC differential test once the kit is set up?", opts:["To prevent the relief valve from ever opening","To slowly drain the customer's water heater","To keep supply pressure continuously sensed on the high side of the gauge","Because closing it would damage the gauge"], correct:2, re:"Keeping the high-side valve open maintains the upstream/supply reference pressure on the gauge high side throughout the test. Source: USC FCCCHR / PNW-AWWA RP and DC procedures."},
  {id:216, block:3, sec:"Differential Gauge Setup", q:"A 5-valve test kit is described by manufacturers as capable of testing which assemblies?", opts:["Only reduced pressure principle (RP) assemblies","Only fire-line detector assemblies","Only pressure vacuum breakers","RP, double check (DC), and pressure vacuum breaker (PVB) assemblies"], correct:3, re:"A 5-valve kit can perform field tests on RP, DC and PVB assemblies and is rated for ASSE, AWWA, CSA and USC procedures. Source: Mid-West 845-5 kit literature; AWWA M14."},
  {id:217, block:3, sec:"Differential Gauge Setup", q:"Before beginning the test, the differential gauge should be checked to confirm it reads what with no pressure applied?", opts:["Zero (the needle rests on the zero mark)","Exactly 15 psid","Half scale","The local barometric pressure"], correct:0, re:"With no differential applied the needle should rest on zero; an off-zero needle indicates the gauge needs attention before it is trusted for a test. Source: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:218, block:3, sec:"Testing RP Assemblies", q:"To PASS, the relief valve of a reduced pressure principle (RP) assembly must begin to open (relieve) at a differential pressure of at least how much?", opts:["1.0 psid","2.0 psid","5.0 psid","0.5 psid"], correct:1, re:"The RP relief valve must open at a minimum differential of 2.0 psid to pass the field test. Source: AWWA Manual M14; USC FCCCHR Field Test Procedures, 10th ed."},
  {id:219, block:3, sec:"Testing RP Assemblies", q:"For an RP assembly to pass, check valve No. 1 must hold a differential pressure of at least how much in the direction of flow?", opts:["1.0 psid","2.0 psid","5.0 psid","10.0 psid"], correct:2, re:"Check valve No. 1 of an RP must hold at least 5.0 psid in the direction of flow to pass. Source: AWWA M14; USC FCCCHR Field Test Procedures, 10th ed."},
  {id:220, block:3, sec:"Testing RP Assemblies", q:"In addition to its minimum value, what relationship must the No. 1 check valve differential have to the relief valve opening point on an RP?", opts:["It must be equal to the relief valve opening point","It has no required relationship to the relief valve","It must be lower than the relief valve opening point","It must be at least 3 psid higher than the relief valve opening point"], correct:3, re:"The first check must hold a differential at least 3.0 psid greater than the relief valve opening point (a 'buffer'), so the relief valve opens before the first check leaks. Source: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:221, block:3, sec:"Testing RP Assemblies", q:"How many test cocks does a typical RP assembly have?", opts:["Four","Two","One","Six"], correct:0, re:"An RP assembly has four test cocks (No. 1 upstream of check No. 1, No. 2 and No. 3 in the reduced-pressure zone region, No. 4 downstream of check No. 2). Source: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:222, block:3, sec:"Testing RP Assemblies", q:"In the USC 10th edition RP procedure, which component is tested FIRST?", opts:["Check valve No. 2","The relief valve opening point","Check valve No. 1","The downstream shutoff valve"], correct:1, re:"The USC 10th edition tests the relief valve opening point first, which also confirms the assembly is in a static condition before the checks are tested. Source: USC FCCCHR Field Test Procedures, 10th ed."},
  {id:223, block:3, sec:"Testing RP Assemblies", q:"What does the relief valve of an RP assembly do when the differential between the supply and the zone drops to its opening point?", opts:["It closes more tightly to hold pressure","It increases the supply pressure","It opens and discharges water from the zone to atmosphere","It locks the check valves open"], correct:2, re:"When the zone differential falls to about 2 psid, the relief valve opens and dumps the reduced-pressure zone to atmosphere, preventing backflow. Source: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:224, block:3, sec:"Testing RP Assemblies", q:"During an RP test, what is the No. 4 test cock primarily used for?", opts:["Adjusting the relief valve spring","Draining the customer's irrigation system","Mounting the differential gauge body","Sensing pressure downstream of the No. 2 check valve"], correct:3, re:"Test cock No. 4 is located downstream of the second check and is used to sense downstream pressure when testing check No. 2. Source: AWWA M14; PNW-AWWA RP test procedure."},
  {id:225, block:3, sec:"Testing RP Assemblies", q:"When testing the relief valve opening point, the reading is recorded at what moment?", opts:["When the relief valve first begins to discharge (water first drips/flows from the relief port)","After the relief valve has been discharging for five minutes","When the gauge needle reaches 15 psid","When the downstream shutoff is fully opened"], correct:0, re:"The differential is read at the instant the relief valve first opens and water begins to discharge from the relief port. Source: USC FCCCHR Field Test Procedures; AWWA M14."},
  {id:226, block:3, sec:"Testing RP Assemblies", q:"Which shutoff valve must be closed to isolate an RP assembly for testing the checks (so a static differential can be established)?", opts:["The No. 1 (upstream) shutoff valve","The No. 2 (downstream) shutoff valve","Both shutoff valves at once","Neither shutoff valve is closed"], correct:1, re:"The downstream (No. 2) shutoff is closed to isolate the assembly from downstream demand so a stable static differential can be read across the checks. Source: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:227, block:3, sec:"Testing RP Assemblies", q:"If an RP's relief valve continuously discharges water during normal service, what does that typically indicate?", opts:["The assembly is functioning perfectly","The supply pressure is too high to test","A fouled No. 1 check or a relief-valve/zone problem causing the zone differential to fall","The downstream shutoff is open"], correct:2, re:"Continuous relief discharge usually means the zone differential has dropped (often a fouled first check or a leaking relief seat), and the cause must be diagnosed and repaired. Source: USC FCCCHR Field Test Procedures; AWWA M14 troubleshooting."},
  {id:228, block:3, sec:"Testing RP Assemblies", q:"For the relief valve opening test on an RP using the gauge, which test cocks are commonly used to sense the high (supply) and the zone pressures?", opts:["No test cocks are used for this step","Test cock No. 1 and test cock No. 4 only","Only test cock No. 4","Test cock No. 2 (high/supply side) and test cock No. 3 (zone side)"], correct:3, re:"The high hose senses the supply/first-check region (No. 2) and the low hose senses the zone (No. 3) so the gauge tracks the zone differential as the relief valve opens. Source: PNW-AWWA / USC RP test procedure."},
  {id:229, block:3, sec:"Testing RP Assemblies", q:"In the USC RP procedure, after the relief valve test, which check is tested before the first check?", opts:["Check valve No. 2 (with backpressure)","There is no second check to test","The relief valve is retested","The bypass check"], correct:0, re:"The USC sequence tests the relief valve, then check No. 2 under backpressure, and finishes with check No. 1 in the direction of flow. Source: USC FCCCHR Field Test Procedures, 10th ed."},
  {id:230, block:3, sec:"Testing RP Assemblies", q:"Why does the RP first check valve have to hold a HIGHER differential than the relief valve opening point?", opts:["So the gauge reads zero","So the relief valve will discharge before the first check leaks backward, keeping the zone safe","So the second check never has to close","To reduce the supply pressure"], correct:1, re:"The buffer ensures the relief valve dumps the zone before the first check can pass water backward, preserving the reduced-pressure protection. Source: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:231, block:3, sec:"Testing RP Assemblies", q:"An RP relief valve opens at exactly 2.0 psid and the No. 1 check holds 4.0 psid. Does the assembly pass?", opts:["Yes, both values meet every requirement","Yes, because only the relief valve matters","No, because the first check must hold at least 5.0 psid AND be 3 psid above the relief opening","No, because the relief valve opened too low"], correct:2, re:"The relief valve (2.0 psid) passes, but check No. 1 at 4.0 psid fails the 5.0 psid minimum and the 3-psid-buffer rule, so the assembly fails. Source: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:232, block:3, sec:"Testing RP Assemblies", q:"What must be done before starting an RP field test, with respect to the customer?", opts:["Nothing; testing never affects service","Disconnect the water meter","Shut off the customer's electricity","Notify the customer that water service will be interrupted during the test"], correct:3, re:"The tester must notify the customer because the downstream shutoff is closed and service is interrupted during testing. Source: USC FCCCHR Field Test Procedures; state RP procedures (e.g., GAWP)."},
  {id:233, block:3, sec:"Testing RP Assemblies", q:"If the relief valve of an RP opens at only 1.5 psid during the test, what is the result?", opts:["It fails because the opening point is below the 2.0 psid minimum","It passes because it opened","It passes if the checks are tight","The reading should be ignored"], correct:0, re:"An opening point below 2.0 psid fails the relief valve requirement and the assembly cannot pass until repaired. Source: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:234, block:3, sec:"Testing RP Assemblies", q:"On an RP, where is test cock No. 1 located?", opts:["Downstream of the second check valve","Upstream of the first check valve (supply side)","Inside the relief valve","On the downstream shutoff valve"], correct:1, re:"Test cock No. 1 is on the supply side, upstream of the first check, and is used to read supply line pressure. Source: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:235, block:3, sec:"Testing DC Assemblies", q:"For a double check (DC) assembly to pass, each check valve must hold a differential pressure of at least how much in the direction of flow?", opts:["5.0 psid","2.0 psid","1.0 psid","0.5 psid"], correct:2, re:"Each check of a DC assembly must hold a minimum of 1.0 psid in the normal direction of flow to pass. Source: AWWA Manual M14; USC FCCCHR Field Test Procedures."},
  {id:236, block:3, sec:"Testing DC Assemblies", q:"How many test cocks does a typical double check valve assembly have?", opts:["One","Two","Eight","Four"], correct:3, re:"A DC assembly has four test cocks: No. 1 upstream of check 1, No. 2 between the shutoff and check 1, No. 3 between the checks, and No. 4 downstream of check 2. Source: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:237, block:3, sec:"Testing DC Assemblies", q:"When testing check valve No. 1 of a DC for tightness, between which two test cocks is the differential measured?", opts:["Test cock No. 2 (high) and test cock No. 3 (low)","Test cock No. 1 and test cock No. 4","Only test cock No. 4","Test cock No. 3 only, vented"], correct:0, re:"Check No. 1 tightness is read with the high hose on the upstream side (test cock No. 2) and the low hose between the checks (test cock No. 3). Source: AWWA M14; PNW-AWWA DC test procedure."},
  {id:238, block:3, sec:"Testing DC Assemblies", q:"When testing check valve No. 2 of a DC for tightness, where are the gauge hoses commonly connected?", opts:["High hose to test cock No. 1 and low hose to test cock No. 2","High hose to test cock No. 3 and low hose to test cock No. 4","Both hoses to test cock No. 1","Neither hose; it is a visual test"], correct:1, re:"Check No. 2 tightness is read with the high hose between the checks (test cock No. 3) and the low hose downstream (test cock No. 4). Source: AWWA M14; PNW-AWWA DC test procedure."},
  {id:239, block:3, sec:"Testing DC Assemblies", q:"A DC check valve holds 1.0 psid in the direction of flow. What is concluded about its reverse-flow tightness?", opts:["It will leak in reverse and fails","Reverse flow cannot be inferred and a second test is mandatory","It is assumed it will also hold tight in the reverse direction of flow","It must hold 5.0 psid in reverse to pass"], correct:2, re:"AWWA M14 holds that if a check seals at 1.0 psid or more in the normal direction, it is assumed to hold tight against reverse flow. Source: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:240, block:3, sec:"Testing DC Assemblies", q:"Which shutoff valve is closed to isolate a DC assembly so a static differential can be read across the checks?", opts:["No shutoff is closed","The No. 1 (upstream) shutoff valve","Both shutoffs simultaneously","The No. 2 (downstream) shutoff valve"], correct:3, re:"The downstream (No. 2) shutoff is closed to remove downstream demand and establish a static condition for the differential readings. Source: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:241, block:3, sec:"Testing DC Assemblies", q:"When the gauge reading stabilizes and water stops flowing from the downstream test cock during a DC check test, what is recorded?", opts:["The stabilized psid reading, and the check is recorded as holding tight at that value","The supply line pressure","The flow rate in gpm","The water temperature"], correct:0, re:"When flow stops and the needle settles, the stabilized differential is recorded; if it is 1.0 psid or more the check is recorded as tight. Source: AWWA M14; PNW-AWWA DC test procedure."},
  {id:242, block:3, sec:"Testing DC Assemblies", q:"A DC's check No. 1 holds 0.8 psid and check No. 2 holds 2.5 psid. What is the overall test result?", opts:["Pass, because the two checks average above 1.0 psid","Fail, because check No. 1 is below the 1.0 psid minimum","Pass, because at least one check exceeds 1.0 psid","Fail, because check No. 2 held too much"], correct:1, re:"Each check is judged independently; check No. 1 at 0.8 psid is below the 1.0 psid minimum, so the assembly fails. Source: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:243, block:3, sec:"Testing DC Assemblies", q:"Which statement about a DC assembly is correct compared with an RP?", opts:["A DC has a relief valve like an RP","A DC has only one check valve","A DC has no relief valve; it relies on two independently operating check valves","A DC vents to atmosphere between the checks like an RP"], correct:2, re:"A DC has two independent spring-loaded checks and no atmospheric relief valve, so it does not dump to atmosphere as an RP does. Source: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:244, block:3, sec:"Testing DC Assemblies", q:"On a DC, what does test cock No. 1 read?", opts:["Pressure between the two checks","The relief valve discharge","Pressure downstream of the second check","Supply line pressure, upstream of the first check"], correct:3, re:"Test cock No. 1 is upstream of check No. 1 and is used to read the supply line pressure. Source: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:245, block:3, sec:"Testing DC Assemblies", q:"Why must air be bled from the gauge hoses before reading either DC check?", opts:["Because compressible air gives a false low or unstable differential reading","To raise the differential artificially","To cool the assembly","To open the second check valve"], correct:0, re:"Air in the lines compresses and corrupts the small differential being measured, so hoses must be purged before reading the check differential. Source: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:246, block:3, sec:"Testing DC Assemblies", q:"A 'leaking No. 2 shutoff valve' can affect a DC check No. 2 test. What feature protects the test against this?", opts:["Opening test cock No. 1 fully","Installing a bleed valve arrangement on the high-side test cock for the one-hose procedure","Removing the gauge entirely","Closing the upstream shutoff instead"], correct:1, re:"The USC procedure adds a bleed valve on the high-side test cock so that a leaking No. 2 shutoff does not invalidate the one-hose check No. 2 reading. Source: USC FCCCHR Field Test Procedures, 10th ed."},
  {id:247, block:3, sec:"Testing DC Assemblies", q:"During the DC check No. 2 test using the one-hose method, which test cock is opened to atmosphere on the downstream side?", opts:["Test cock No. 2","Test cock No. 1","Test cock No. 4","The relief valve port"], correct:2, re:"With the high hose on test cock No. 3, test cock No. 4 is opened so the downstream side senses atmosphere for the check No. 2 differential. Source: AWWA M14; PNW-AWWA DC test procedure."},
  {id:248, block:3, sec:"Testing DC Assemblies", q:"If, while testing DC check No. 1, the differential will not build and water keeps moving, what is a likely cause?", opts:["The first check is sealing perfectly","The downstream pressure is zero by design","The gauge range is too high","The first check is fouled/leaking or a shutoff is passing water"], correct:3, re:"An inability to build and hold a differential indicates a leaking first check or a passing shutoff valve, which must be diagnosed. Source: AWWA M14; USC FCCCHR Field Test Procedures troubleshooting."},
  {id:249, block:3, sec:"Testing DC Assemblies", q:"For a DC, the supply line pressure for the report is typically read at which point?", opts:["Test cock No. 1 with shutoff No. 1 open","Test cock No. 4 with both shutoffs closed","The relief valve","Test cock No. 3 only"], correct:0, re:"Supply/line pressure is read at test cock No. 1 on the supply side. Source: AWWA M14; state test report instructions (e.g., Denver Water)."},
  {id:250, block:3, sec:"Testing DC Assemblies", q:"Both checks of a DC must close 'drip-tight.' In testing terms, what does passing actually require?", opts:["Each check holds at least 5.0 psid","Each check holds at least 1.0 psid of static differential in the direction of flow","The checks together hold 1.0 psid","No measurable differential is allowed"], correct:1, re:"Each check passes when it holds a static differential of 1.0 psid or more in the direction of flow, confirming a tight seal. Source: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:251, block:3, sec:"Testing DC Assemblies", q:"In a double check DETECTOR assembly (DCDA), the small bypass meter line also contains what for testing?", opts:["No backflow protection at all","A relief valve identical to an RP","Its own double check assembly that must also be tested","A pressure vacuum breaker only"], correct:2, re:"A double check detector assembly has a metered bypass that contains its own double check, which is tested to the same 1.0-psid-per-check criteria. Source: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:252, block:3, sec:"Testing PVB & SVB", q:"For a pressure vacuum breaker (PVB) to pass, the air inlet valve must begin to open at a pressure of at least how much above atmospheric?", opts:["0.5 psi","2.0 psi","5.0 psi","1.0 psi"], correct:3, re:"The PVB air inlet must open when the internal pressure is no less than 1.0 psi above atmospheric to pass. Source: AWWA Manual M14; USC FCCCHR Field Test Procedures."},
  {id:253, block:3, sec:"Testing PVB & SVB", q:"For a PVB to pass, the single check valve must hold a differential pressure of at least how much?", opts:["1.0 psid","2.0 psid","5.0 psid","0.5 psid"], correct:0, re:"The PVB check valve must hold at least 1.0 psid to pass. Source: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:254, block:3, sec:"Testing PVB & SVB", q:"How many test cocks does a typical PVB have?", opts:["One","Two","Four","Six"], correct:1, re:"A PVB has two test cocks, one on each side, used to test the check valve and the air inlet opening point. Source: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:255, block:3, sec:"Testing PVB & SVB", q:"How does a spill-resistant vacuum breaker (SVB) differ structurally from a PVB for testing?", opts:["An SVB has four test cocks","An SVB has a relief valve like an RP","An SVB has a single test cock plus a vent (bleed) valve instead of two test cocks","An SVB has no air inlet"], correct:2, re:"An SVB has only a single test cock together with a vent/bleed valve, whereas a PVB has two test cocks. Source: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:256, block:3, sec:"Testing PVB & SVB", q:"For an SVB to pass, the air inlet must open at a minimum of how much, and must also do what?", opts:["5.0 psi minimum, and discharge water","2.0 psi minimum, and only crack open","0.5 psi minimum, and stay closed","1.0 psi minimum, and the air inlet must open fully"], correct:3, re:"The SVB air inlet must open at 1.0 psi or more and must open fully. Source: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:257, block:3, sec:"Testing PVB & SVB", q:"For an SVB, the check valve must hold a differential of at least how much to pass?", opts:["1.0 psid","2.0 psid","3.0 psid","0.5 psid"], correct:0, re:"The SVB check valve must hold at least 1.0 psid to pass. Source: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:258, block:3, sec:"Testing PVB & SVB", q:"On a PVB, which shutoff valve is closed when isolating the assembly to test the check valve and air inlet?", opts:["The upstream shutoff only","The downstream shutoff (with the upstream shutoff verified open)","Both shutoffs at once","Neither; PVBs have no shutoffs"], correct:1, re:"The downstream shutoff is closed (and the upstream shutoff confirmed open) so the body can be isolated for the air-inlet and check tests. Source: AWWA M14; PNW-AWWA PVB test procedure."},
  {id:259, block:3, sec:"Testing PVB & SVB", q:"Because of how a PVB works, where must it be installed relative to all downstream outlets?", opts:["Below the lowest outlet","At the same level as the outlets","At least 12 inches above all downstream piping and outlets it protects","Underground in a vault"], correct:2, re:"A PVB must be installed at least 12 inches above all downstream piping/outlets, because it only protects against backsiphonage, not backpressure. Source: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:260, block:3, sec:"Testing PVB & SVB", q:"Why can a PVB or SVB NOT be used where backpressure can occur?", opts:["It would read too high on the gauge","It only works on hot water","It has too many test cocks","Its air inlet provides backsiphonage protection only, not backpressure protection"], correct:3, re:"PVB and SVB assemblies protect against backsiphonage only; under backpressure the air inlet cannot prevent backflow, so they must not be used where backpressure can exist. Source: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:261, block:3, sec:"Testing PVB & SVB", q:"In the standard PVB/SVB test sequence, which is tested first?", opts:["The check valve first, then the air inlet opening point","The air inlet opening point, then the check valve","Both at the same time","The relief valve, then the check"], correct:0, re:"USC and AWWA procedures test the check valve first and then the air-inlet opening point. Source: AWWA M14; USC FCCCHR Field Test Procedures (SVB/PVB)."},
  {id:262, block:3, sec:"Testing PVB & SVB", q:"During the PVB air-inlet test, the reading is taken at what instant?", opts:["After the air inlet has been open for 10 minutes","When the air inlet first opens (the point at which air begins to enter / the poppet lifts)","When the gauge reaches 15 psid","When the check valve closes"], correct:1, re:"The differential is read at the instant the air inlet opens, observed visually as the poppet lifts or air enters. Source: AWWA M14; PNW-AWWA PVB test procedure."},
  {id:263, block:3, sec:"Testing PVB & SVB", q:"On a PVB check-valve test, the high-side hose is attached to which test cock?", opts:["Neither; it is read at the air inlet","Test cock No. 1","Test cock No. 2","Both test cocks at once"], correct:2, re:"For the PVB check test the high-side hose is connected to test cock No. 2 (downstream of the check), then the bleed is opened to read the check differential. Source: AWWA M14; PNW-AWWA PVB test procedure."},
  {id:264, block:3, sec:"Testing PVB & SVB", q:"On an SVB check-valve test, when is the gauge reading recorded?", opts:["When the supply pressure reaches 80 psi","As soon as the hose is connected","After the air inlet fails","When water stops draining from the vent valve"], correct:3, re:"For the SVB, the bleed-off is opened slowly until water stops draining from the vent valve; that stabilized reading (1.0 psi or more) is recorded for the check. Source: AWWA M14; Mid-West SVB test procedure."},
  {id:265, block:3, sec:"Testing PVB & SVB", q:"A PVB air inlet opens at 0.7 psi during the test. What is the result?", opts:["Fail, because the opening point is below the 1.0 psi minimum","Pass, because it opened at all","Pass, if the check holds 1.0 psid","The reading is discarded"], correct:0, re:"An air-inlet opening point below 1.0 psi fails the requirement; the PVB cannot pass until repaired. Source: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:266, block:3, sec:"Testing PVB & SVB", q:"What advantage does an SVB ('spill-resistant') have over a standard PVB?", opts:["It can be installed below grade","It is designed to resist spilling water from the air inlet during normal startup/pressurization","It provides backpressure protection","It needs no testing"], correct:1, re:"The SVB is engineered to minimize water spillage out the air inlet during pressurization, which a standard PVB can release. Source: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:267, block:3, sec:"Testing PVB & SVB", q:"For the PVB air-inlet test, the high-side bleed is opened slowly while observing what?", opts:["The customer's water meter","The supply main pressure gauge","The air inlet poppet, to catch the gauge reading the moment it opens","The relief valve discharge"], correct:2, re:"The tester slowly bleeds pressure while watching the air inlet and records the gauge reading at the moment the inlet opens. Source: AWWA M14; PNW-AWWA PVB test procedure."},
  {id:268, block:3, sec:"Testing PVB & SVB", q:"When testing an SVB, where must the test kit and hose be held?", opts:["At least 5 feet above the SVB","Elevation is irrelevant for an SVB","Below the SVB","At the same level (elevation) as the SVB"], correct:3, re:"The test kit and hose are held at the same level as the SVB so elevation does not add error to the readings. Source: AWWA M14; Mid-West SVB test procedure."},
  {id:269, block:3, sec:"Reading & Interpreting Results", q:"While reading a check valve differential, the gauge needle keeps drifting downward and will not stabilize. What does this most likely mean?", opts:["The check is leaking (not holding tight) or air remains in the lines","The check is sealing perfectly","The supply pressure is exactly correct","The relief valve passed"], correct:0, re:"A needle that will not hold and drifts down indicates a leaking check or residual air; a passing check holds a steady differential. Source: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:270, block:3, sec:"Reading & Interpreting Results", q:"A differential reading is described as 'apparent' if which condition exists?", opts:["The gauge is brand new","The hoses still contain trapped air affecting the reading","The water is cold","The assembly is an RP"], correct:1, re:"Trapped air makes a reading 'apparent' rather than true; the lines must be fully bled so the gauge shows the real differential. Source: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:271, block:3, sec:"Reading & Interpreting Results", q:"When the high-side bleed is opened during an RP check No. 1 test and the needle climbs and then holds steady, what does the held value represent?", opts:["The barometric pressure","The flow rate through the assembly","The static differential the first check is holding","The downstream shutoff leak rate"], correct:2, re:"The steady held value is the static differential across the first check; it must be 5.0 psid or more (and 3 psid above relief opening) to pass on an RP. Source: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:272, block:3, sec:"Reading & Interpreting Results", q:"If, during a DC check test, the gauge reads a negative or zero differential that cannot be raised, what is indicated?", opts:["The check is holding tight","The relief valve opened","The gauge is over-ranged","The check is not holding (it is passing water) or the hookup is wrong"], correct:3, re:"A differential that stays at or below zero signals the check is not sealing (passing) or the hoses are connected incorrectly. Source: AWWA M14; USC FCCCHR Field Test Procedures troubleshooting."},
  {id:273, block:3, sec:"Reading & Interpreting Results", q:"During the relief valve opening test on an RP, a steadily FALLING needle that you watch for the opening point represents what?", opts:["The zone differential decreasing toward the relief valve opening point","The supply pressure increasing","The check No. 2 leak rate","The air inlet opening"], correct:0, re:"As the tester bleeds the high side, the gauge shows the zone differential falling; the reading is captured when the relief valve opens (about 2 psid). Source: USC FCCCHR Field Test Procedures; AWWA M14."},
  {id:274, block:3, sec:"Reading & Interpreting Results", q:"Water continuously dripping from an RP relief port while attempting to read a check differential most directly tells the tester what?", opts:["The gauge is calibrated","The reduced-pressure zone is venting; the first check or relief seat may be passing","The second check is perfect","The supply is shut off"], correct:1, re:"Relief discharge during a check reading shows the zone is venting (commonly a fouled first check or leaking relief seat), which must be diagnosed before a valid result. Source: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:275, block:3, sec:"Reading & Interpreting Results", q:"On a PVB air-inlet test, if the needle drops to a value and the air inlet visibly opens there, what is that value recorded as?", opts:["The supply line pressure","The check valve tightness","The air inlet opening point","The relief valve setting"], correct:2, re:"The gauge value at the instant the air inlet opens is recorded as the air-inlet opening point and must be 1.0 psi or more. Source: AWWA M14; PNW-AWWA PVB test procedure."},
  {id:276, block:3, sec:"Reading & Interpreting Results", q:"Why must the tester read the differential at the FIRST sign of relief-valve discharge rather than later?", opts:["Because the supply pressure rises afterward","Because the gauge only works briefly","Because the customer is waiting","Because the opening point is defined by the moment the valve first relieves"], correct:3, re:"The opening point is by definition the differential at which the valve first opens; reading later understates the true opening point. Source: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:277, block:3, sec:"Reading & Interpreting Results", q:"A gauge that reads 2 to 3 psid of differential even when both hoses are on the same point indicates what?", opts:["Trapped air, a fouled gauge, or a gauge out of calibration","A correctly zeroed gauge","A passing RP relief valve","Normal behavior to be ignored"], correct:0, re:"A false static offset points to trapped air or a gauge that needs purging or recalibration before it can be trusted. Source: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:278, block:3, sec:"Reading & Interpreting Results", q:"During an RP test, a sudden jump of the needle toward zero when the relief opens is interpreted as what?", opts:["A failed gauge","The relief valve venting the zone (a normal event marking the opening)","The supply pressure doubling","Check No. 1 sealing"], correct:1, re:"When the relief opens it dumps the zone, and the differential collapses toward zero; this is the expected behavior used to mark the opening point. Source: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:279, block:3, sec:"Reading & Interpreting Results", q:"If a DC check holds well above 1.0 psid but the needle bounces erratically, the FIRST thing to suspect is what?", opts:["An over-tight downstream shutoff","A passing relief valve","Residual air in the hoses needing more bleeding","A miscalibrated air inlet"], correct:2, re:"Erratic needle motion usually means air remains in the lines; bleed again and re-read before judging the check. Source: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:280, block:3, sec:"Reading & Interpreting Results", q:"What does a stable, held differential of 1.0 psid or greater on a DC check tell you?", opts:["The check is leaking","The supply is shut off","The relief valve opened","The check is holding tight and passes that portion of the test"], correct:3, re:"A steady differential of 1.0 psid or more means the check is sealing tight and that check passes. Source: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:281, block:3, sec:"Reading & Interpreting Results", q:"On the relief-valve test, why is establishing a static (no-flow) condition important before reading?", opts:["So the differential reflects the assembly itself, not flow-induced pressure drop","So the gauge reads 15 psid","So the customer's water turns on","So the air inlet opens"], correct:0, re:"A static condition ensures the measured differential is from the assembly's springs/seats and not from flow, giving a valid opening-point reading. Source: USC FCCCHR Field Test Procedures; AWWA M14."},
  {id:282, block:3, sec:"Reading & Interpreting Results", q:"During an SVB check test, water that will NOT stop draining from the vent valve as you bleed indicates what?", opts:["The check is holding perfectly","The check is leaking/passing and may fail the 1.0 psid criterion","The gauge is over-ranged","The air inlet is stuck closed"], correct:1, re:"If draining will not stop, the check is passing water and likely fails; a tight check lets the vent stop draining at 1.0 psi or more. Source: AWWA M14; Mid-West SVB test procedure."},
  {id:283, block:3, sec:"Reading & Interpreting Results", q:"A reading taken with the gauge held well ABOVE the assembly, compared with a reading at the same elevation, will be affected how?", opts:["Not at all","By doubling the true value","By an elevation (head) error that shifts the differential","By turning negative always"], correct:2, re:"Holding the gauge off the assembly elevation adds a water-column head error to the differential, so the kit must be kept level with the assembly. Source: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:284, block:3, sec:"Reading & Interpreting Results", q:"If supply line pressure read at test cock No. 1 is unusually low or fluctuating, what should the tester do?", opts:["Record any value and pass the assembly","Ignore the supply pressure entirely","Increase the gauge range to 150 psid","Note it and resolve the supply condition, since unstable supply can corrupt the differential readings"], correct:3, re:"Unstable or abnormal supply pressure can distort the test, so the condition is noted and addressed before trusting the differential results. Source: AWWA M14; state test report guidance."},
  {id:285, block:3, sec:"Reading & Interpreting Results", q:"On an RP, if check No. 1 holds 6 psid but the relief valve opens at 4 psid, what does the 2-psid gap signify?", opts:["An insufficient buffer, because the buffer must be at least 3 psid","A healthy buffer well above the minimum","That the assembly is an SVB","That the gauge is broken"], correct:0, re:"Although both values exceed their own minimums, a 2-psid buffer is below the required 3-psid difference between first check and relief opening, so this point fails. Source: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:286, block:3, sec:"Pass/Fail Criteria & Recording", q:"Which set of minimum pass values is correct for an RP assembly?", opts:["Relief valve opens at >= 1.0 psid; each check holds >= 1.0 psid","Relief valve opens at >= 2.0 psid; check No. 1 holds >= 5.0 psid and >= 3 psid above relief opening","Relief valve opens at >= 5.0 psid; check No. 1 holds >= 2.0 psid","Air inlet opens at >= 1.0 psi; check holds >= 1.0 psid"], correct:1, re:"An RP passes when the relief opens at 2.0 psid or more and the first check holds 5.0 psid or more with at least a 3-psid buffer over the relief opening. Source: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:287, block:3, sec:"Pass/Fail Criteria & Recording", q:"Which set of minimum pass values is correct for a DC assembly?", opts:["Air inlet opens at >= 1.0 psi","Relief valve opens at >= 2.0 psid","Each check valve holds >= 1.0 psid in the direction of flow","Check No. 1 holds >= 5.0 psid"], correct:2, re:"A DC passes when each check independently holds 1.0 psid or more in the direction of flow. Source: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:288, block:3, sec:"Pass/Fail Criteria & Recording", q:"Which set of minimum pass values is correct for a PVB assembly?", opts:["Air inlet opens at >= 2.0 psi; no check test","Relief valve opens at >= 2.0 psid; check holds >= 5.0 psid","Each of two checks holds >= 1.0 psid","Air inlet opens at >= 1.0 psi; check valve holds >= 1.0 psid"], correct:3, re:"A PVB passes when the air inlet opens at 1.0 psi or more and the check valve holds 1.0 psid or more. Source: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:289, block:3, sec:"Pass/Fail Criteria & Recording", q:"Which set of minimum pass values is correct for an SVB assembly?", opts:["Check holds >= 1.0 psid; air inlet opens at >= 1.0 psi and opens fully","Relief valve opens at >= 2.0 psid","Two checks each hold >= 1.0 psid","Air inlet opens at >= 5.0 psi"], correct:0, re:"An SVB passes when the check holds 1.0 psid or more and the air inlet opens at 1.0 psi or more and opens fully. Source: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:290, block:3, sec:"Pass/Fail Criteria & Recording", q:"Which piece of information is REQUIRED on a backflow assembly test report?", opts:["The customer's favorite color","The assembly serial number, make, model, and size","The tester's home phone bill","The brand of the customer's water heater"], correct:1, re:"The report must identify the assembly by make, model, size and serial number (which should match the stamp on the device). Source: AWWA M14; state report forms (e.g., NY DOH, Denver Water)."},
  {id:291, block:3, sec:"Pass/Fail Criteria & Recording", q:"Why must the serial number recorded on the report match the one stamped on the assembly?", opts:["For decoration only","To set the supply pressure","To prove the correct, installed assembly was the one actually tested","To calibrate the gauge"], correct:2, re:"Matching serial numbers documents that the specific installed assembly was tested, preventing fraud or mix-ups. Source: AWWA M14; state cross-connection program report instructions."},
  {id:292, block:3, sec:"Pass/Fail Criteria & Recording", q:"Besides the test date, which date is normally required on the report regarding the tester's gauge?", opts:["No gauge date is required","The gauge purchase price date","The date the gauge was cleaned","The gauge's calibration date"], correct:3, re:"The gauge calibration date is recorded so the authority can confirm the gauge was within its annual calibration when used. Source: AWWA M14; state report forms (e.g., Denver Water)."},
  {id:293, block:3, sec:"Pass/Fail Criteria & Recording", q:"What identifies the person who performed the test on the report?", opts:["The certified tester's name and certification/license number","Only a first name","The customer's signature only","The manufacturer's logo"], correct:0, re:"The certified tester's name and certification (license) number must appear so the authority can verify the tester is qualified. Source: AWWA M14; state report forms."},
  {id:294, block:3, sec:"Pass/Fail Criteria & Recording", q:"If an assembly FAILS and is then repaired, what must the report also document?", opts:["Nothing further is needed","The repairs made, parts used, and a passing retest after the repair","Only the time of day","The customer's account password"], correct:1, re:"After repair the report documents what was repaired/replaced and the results of the passing retest. Source: AWWA M14; state report forms (repair section)."},
  {id:295, block:3, sec:"Pass/Fail Criteria & Recording", q:"A DC check No. 1 reads exactly 1.0 psid. How is it recorded?", opts:["As a fail, because it must exceed 1.0 psid","As needing no entry","As a pass, because it meets the 1.0 psid minimum (>= 1.0 psid)","As a relief valve reading"], correct:2, re:"The criterion is 1.0 psid or greater, so exactly 1.0 psid meets the minimum and the check passes. Source: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:296, block:3, sec:"Pass/Fail Criteria & Recording", q:"When recording an RP result, which readings are entered on the report?", opts:["Only the supply pressure","Only the air inlet value","Only the relief valve value","Check No. 1 differential, check No. 2 result, and the relief valve opening value"], correct:3, re:"An RP report records the first-check differential, the second-check result, and the relief-valve opening differential, plus pass/fail. Source: AWWA M14; sample field test forms (USC FCCCHR)."},
  {id:297, block:3, sec:"Pass/Fail Criteria & Recording", q:"For a PVB, which two results are recorded on the report?", opts:["The air-inlet opening value and the check valve differential","Two check valve differentials","A relief valve opening and a check","Only the supply pressure"], correct:0, re:"A PVB report records the air-inlet opening point and the check valve differential, with pass/fail. Source: AWWA M14; PNW-AWWA PVB test procedure / report fields."},
  {id:298, block:3, sec:"Pass/Fail Criteria & Recording", q:"What is the correct disposition if any single required reading on an assembly falls below its minimum?", opts:["Record the assembly as passing anyway","Record the assembly as FAILED until it is repaired and retested to passing","Average all readings to decide","Leave the report blank"], correct:1, re:"Any reading below its required minimum means the assembly fails and must be repaired and retested before it can be recorded as passing. Source: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:299, block:3, sec:"Pass/Fail Criteria & Recording", q:"Which condition of the shutoff valves is typically noted on the report?", opts:["Only their color","Their weight","Whether shutoff No. 1 and No. 2 are operable/holding (e.g., tight or leaking)","The torque used to open them"], correct:2, re:"Reports note the condition of shutoff valves (e.g., holding tight or leaking), since a passing shutoff affects test validity and isolation. Source: AWWA M14; state report forms."},
  {id:300, block:3, sec:"Pass/Fail Criteria & Recording", q:"After completing the test, what must the tester do before leaving the site?", opts:["Leave the downstream shutoff closed and the test cocks open","Drain the customer's water heater","Remove the assembly from the line","Restore the assembly to service (shutoffs and test cocks returned to their normal operating positions)"], correct:3, re:"The tester returns the assembly to normal service: test cocks closed/capped and shutoff valves restored to their proper operating positions. Source: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:301, block:4, sec:"Pressure & Flow Basics", q:"A column of water about how many feet tall produces 1 psi of pressure at its base?", opts:["2.31 ft","1.0 ft","0.433 ft","14.7 ft"], correct:0, re:"A 1 psi water column is 2.31 ft tall (1 / 0.433). This pressure-to-head conversion is fundamental hydraulics used throughout AWWA M14 and pump/elevation calculations."},
  {id:302, block:4, sec:"Pressure & Flow Basics", q:"How much pressure does each foot of vertical water column exert at its base?", opts:["1.0 psi","0.433 psi","2.31 psi","4.33 psi"], correct:1, re:"Water weighs 62.4 lb/ft3, so a 1 ft x 1 in2 column weighs about 0.433 lb, i.e. 0.433 psi per foot of head (the reciprocal of 2.31 ft/psi)."},
  {id:303, block:4, sec:"Pressure & Flow Basics", q:"One cubic foot of water weighs approximately:", opts:["8.34 lb","100 lb","62.4 lb","2.31 lb"], correct:2, re:"Fresh water weighs about 62.4 lb/ft3 (and 8.34 lb per gallon). This specific weight is the basis for the 0.433 psi/ft and 2.31 ft/psi head conversions."},
  {id:304, block:4, sec:"Pressure & Flow Basics", q:"Raising the outlet of an assembly 23 feet above the inlet adds roughly how much static pressure the supply must overcome?", opts:["About 5 psi","About 50 psi","About 23 psi","About 10 psi"], correct:3, re:"Elevation loss = height x 0.433 psi/ft. 23 ft x 0.433 = about 10 psi. Standard hydraulic head conversion (AWWA M14 hydraulics)."},
  {id:305, block:4, sec:"Pressure & Flow Basics", q:"Static water pressure is the pressure measured when the water is:", opts:["Not flowing (at rest)","Flowing at maximum demand","Being pumped uphill","Discharging from the relief valve"], correct:0, re:"Static pressure is the pressure in the line at no flow. Once water moves, friction and velocity reduce it to a lower dynamic (residual) pressure. Basic hydraulics, AWWA M14."},
  {id:306, block:4, sec:"Pressure & Flow Basics", q:"When water begins to flow through a pipe, the pressure downstream compared with the static pressure will normally:", opts:["Stay exactly the same","Decrease because of friction loss","Increase","Become atmospheric"], correct:1, re:"Flow creates friction and velocity head, so dynamic (residual) pressure is lower than static pressure. The faster the flow, the greater the drop. AWWA M14 hydraulics."},
  {id:307, block:4, sec:"Pressure & Flow Basics", q:"Friction loss in a given pipe increases most sharply when:", opts:["The water stops flowing","The pipe is shortened","The flow rate (velocity) increases","Pressure is removed"], correct:2, re:"Friction loss rises roughly with the square of velocity, so higher flow through a fixed pipe causes a much larger pressure drop. This is why oversizing reduces head loss. AWWA M14."},
  {id:308, block:4, sec:"Pressure & Flow Basics", q:"As water speeds up through a narrowed passage, its velocity rises and its static pressure:", opts:["Rises","Doubles","Stays constant","Falls"], correct:3, re:"By the energy/Bernoulli principle, faster-moving water trades pressure energy for velocity energy, so static pressure falls where velocity is highest. AWWA M14 hydraulics."},
  {id:309, block:4, sec:"Pressure & Flow Basics", q:"The pressure drop across the first check of an RP assembly during high flow is mainly the result of:", opts:["The spring load plus friction/velocity through the check","Thermal expansion","Gauge error","Atmospheric venting"], correct:0, re:"Water must push the loaded check open and flow past it; spring load plus flow friction creates the differential. If that drop exceeds the relief setting, the relief can weep. AWWA M14 / USC FCCCHR."},
  {id:310, block:4, sec:"Pressure & Flow Basics", q:"An assembly that is undersized for the building's demand will most likely cause:", opts:["Excess static pressure","Excessive head loss and low downstream pressure at peak flow","No flow at all times","Higher gauge accuracy"], correct:1, re:"Too small an assembly forces high velocity and large friction loss at peak demand, starving fixtures and sometimes lifting the RP relief valve. Size to demand per AWWA M14."},
  {id:311, block:4, sec:"Pressure & Flow Basics", q:"Differential pressure across a check valve is defined as the:", opts:["Supply pressure plus zone pressure","Atmospheric pressure only","Difference between upstream pressure and downstream pressure across that check","Pressure at the relief valve outlet"], correct:2, re:"Differential pressure is upstream minus downstream pressure across the check. The test kit gauge reads this directly when connected to the test cocks. AWWA M14 / USC FCCCHR."},
  {id:312, block:4, sec:"Pressure & Flow Basics", q:"Normal municipal water-service pressure delivered to most buildings is typically in the range of:", opts:["5 to 15 psi","Over 300 psi","150 to 200 psi","40 to 80 psi"], correct:3, re:"Public water systems commonly deliver roughly 40-80 psi; a PRV is added where street pressure is higher. Assemblies must seal across this working-pressure range. AWWA M14."},
  {id:313, block:4, sec:"Pressure & Flow Basics", q:"Backpressure backflow occurs when the downstream pressure becomes:", opts:["Higher than the supply pressure","Lower than the supply pressure","Equal to atmospheric","Exactly zero"], correct:0, re:"Backpressure is downstream pressure exceeding supply pressure (from pumps, boilers, elevation, thermal expansion), which can push water back toward the main. AWWA M14."},
  {id:314, block:4, sec:"Pressure & Flow Basics", q:"Standard atmospheric pressure at sea level is approximately:", opts:["7.0 psi","14.7 psi","29.9 psi","50.0 psi"], correct:1, re:"Standard atmospheric pressure at sea level is about 14.7 psia (1 atmosphere). Backsiphonage and vacuum effects are referenced against atmospheric pressure. — hydraulics fundamentals / AWWA M14."},
  {id:315, block:4, sec:"Pressure & Flow Basics", q:"The reduced-pressure zone between the two checks of an RP assembly is normally kept how, relative to the supply?", opts:["At a higher pressure than the supply","Exactly equal to the supply","At least about 2 psi lower than the supply","At full atmospheric pressure at all times"], correct:2, re:"The first check maintains the central zone at least about 2 psi below supply; if that buffer is lost, the relief valve opens to keep the zone below supply. USC FCCCHR / AWWA M14."},
  {id:316, block:4, sec:"Pressure & Flow Basics", q:"A pressure gauge that reads 'psig' is measuring pressure relative to:", opts:["Absolute vacuum","The relief valve setting","The supply pressure","Atmospheric pressure"], correct:3, re:"Gauge pressure (psig) is referenced to local atmospheric pressure; a reading of 0 psig means atmospheric. Backflow differential readings are gauge-based. General hydraulics."},
  {id:317, block:4, sec:"Pressure & Flow Basics", q:"Velocity in a pipe for a given flow rate increases when the pipe diameter is:", opts:["Made smaller","Made larger","Left unchanged","Insulated"], correct:0, re:"For a fixed flow rate, a smaller cross-section forces higher velocity (continuity). Higher velocity raises friction loss and can increase the check differential. AWWA M14 hydraulics."},
  {id:318, block:4, sec:"Why Assemblies Fail", q:"On an RP assembly, continuous relief-valve discharge while the system is at rest (no flow) most often indicates:", opts:["A perfectly sealing first check","A fouled first check that will not close tightly","Normal operation","An oversized assembly"], correct:1, re:"At static no-flow, continuous discharge means the first check leaks and cannot hold the zone below supply, so the relief opens. The first check needs service. USC FCCCHR / AWWA M14 troubleshooting."},
  {id:319, block:4, sec:"Why Assemblies Fail", q:"The single most common cause of a fouled check valve that will not seat is:", opts:["Correct spring tension","A calibrated gauge","Debris, sediment, or scale lodged on the seat or disc","Proper installation height"], correct:2, re:"Grit, pipe scale, and debris caught between disc and seat are the leading cause of a check that will not close tight; the fix is to clean or replace the affected parts. AWWA M14 / manufacturer guidance."},
  {id:320, block:4, sec:"Why Assemblies Fail", q:"Continuous relief discharge that appears only when the downstream side is under backpressure points to a fouled:", opts:["First check","Inlet shutoff","Gauge needle valve","Second check"], correct:3, re:"If the second check fouls and backpressure pushes water back into the zone, the zone pressure rises, the relief opens, and discharge continues under that backpressure. AWWA M14 troubleshooting."},
  {id:321, block:4, sec:"Why Assemblies Fail", q:"Intermittent relief discharge that starts and stops as supply pressure rises and falls is usually the assembly:", opts:["Correctly responding to fluctuating supply pressure","Failing and needing replacement","Suffering a cracked body","Reading a bad gauge"], correct:0, re:"When inlet pressure momentarily drops, the relief vents to keep the zone below supply, then reseats when pressure recovers. This nuisance discharge tracks supply fluctuation. AWWA M14 / USC FCCCHR."},
  {id:322, block:4, sec:"Why Assemblies Fail", q:"On a closed downstream system, an RP relief valve that drips after long hot-water use or overnight is commonly caused by:", opts:["A loose test cock","Thermal expansion raising downstream pressure","An oversized first check","Atmospheric pressure changes"], correct:1, re:"Heated water in a closed loop expands and raises downstream pressure, pushing back through the second check and lifting the relief. A properly charged expansion tank usually cures it. AWWA M14."},
  {id:323, block:4, sec:"Why Assemblies Fail", q:"A water-hammer shock wave reaching an RP assembly can cause the relief valve to:", opts:["Seal more tightly forever","Reverse the flow direction permanently","Momentarily open and discharge water","Recalibrate itself"], correct:2, re:"A sudden pressure surge can momentarily upset the zone differential and lift the relief; arrestors or a cushioning check are used to dampen it. AWWA M14 / field troubleshooting."},
  {id:324, block:4, sec:"Why Assemblies Fail", q:"Worn or hardened rubber check discs typically fail because they:", opts:["Become more flexible over time","Reduce friction loss","Grow larger and seal better","Lose their resilience and no longer seal against the seat"], correct:3, re:"Rubber takes a set, hardens, cracks, or tears with age and chlorine exposure, so the disc cannot conform to the seat and the check leaks. Replace the rubber. AWWA M14 / manufacturer."},
  {id:325, block:4, sec:"Why Assemblies Fail", q:"A relief valve that will not open at all (no discharge even when it should) is dangerous because it can:", opts:["Mask a backflow condition and allow contamination of the zone","Save water","Improve gauge accuracy","Increase supply pressure"], correct:0, re:"A stuck-closed relief defeats the RP's last line of defense; the zone could be contaminated without warning. Both checks and the relief must be proven on every test. USC FCCCHR / AWWA M14."},
  {id:326, block:4, sec:"Why Assemblies Fail", q:"Mineral scale building up on a check seat over time will most likely:", opts:["Have no effect","Prevent the disc from seating fully and cause leakage","Increase the relief opening pressure","Tighten the seal"], correct:1, re:"Hard-water scale on the seat holds the disc off its seat, creating a leak path; descaling or replacing the seat/disc restores the seal. AWWA M14 / manufacturer maintenance."},
  {id:327, block:4, sec:"Why Assemblies Fail", q:"Freezing weather most commonly damages an above-ground assembly by:", opts:["Improving the seals","Calibrating the gauge","Cracking the body, bonnet, or relief valve from ice expansion","Lowering the relief setting"], correct:2, re:"Water expands when it freezes and can split the cast body, bonnet, or relief housing. Freeze protection or draining for winter is required. AWWA M14 installation guidance."},
  {id:328, block:4, sec:"Why Assemblies Fail", q:"A broken or fatigued check-valve spring usually shows up on a test as:", opts:["A higher-than-normal check differential","No effect on the reading","A relief valve that opens later","A check that will not hold the minimum differential"], correct:3, re:"A weak or broken spring cannot load the disc onto the seat, so the check fails to hold its minimum hold pressure on test. Replace the spring/module. AWWA M14 / manufacturer."},
  {id:329, block:4, sec:"Why Assemblies Fail", q:"An assembly installed with the flow arrow pointing the wrong way will:", opts:["Fail to protect because the checks face the wrong direction","Work normally","Read a higher differential","Open the relief less often"], correct:0, re:"Installed backward, the checks oppose the intended flow and the assembly cannot perform; orientation must match the body flow arrow. AWWA M14 installation."},
  {id:330, block:4, sec:"Why Assemblies Fail", q:"Debris is most likely to foul an assembly right after:", opts:["A long period of no use","Nearby main work, repairs, or flushing that stirs up sediment","Calibrating the gauge","Painting the building"], correct:1, re:"Main breaks, repairs, hydrant flushing, and new construction dislodge scale and grit that travel downstream and lodge in checks and the relief. Expect post-disturbance fouling. AWWA M14."},
  {id:331, block:4, sec:"Why Assemblies Fail", q:"A pinhole or tear in the rubber diaphragm of a differential relief valve will typically cause the relief to:", opts:["Stay sealed permanently","Open at a higher pressure","Weep or discharge continuously because it cannot hold its differential","Have no symptom"], correct:2, re:"The relief diaphragm senses the supply-to-zone differential; a torn diaphragm cannot hold it, so the relief weeps. Replace the relief module/diaphragm. AWWA M14 / manufacturer."},
  {id:332, block:4, sec:"Why Assemblies Fail", q:"If an RP relief valve discharges only during the few minutes of peak morning demand, the most likely explanation is:", opts:["A cracked assembly body","An over-tight inlet shutoff","A frozen relief valve","High flow dropping the first-check differential below the relief setting (often undersizing)"], correct:3, re:"At peak flow the pressure drop across the first check can fall below the relief differential and the relief vents; correct sizing or a larger assembly resolves it. USC FCCCHR / AWWA M14."},
  {id:333, block:4, sec:"Why Assemblies Fail", q:"Both checks fouled and leaking on a high-hazard RP is most serious because it:", opts:["Removes the barrier against contamination, though the relief still vents the zone","Only wastes a little water","Improves protection","Has no consequence"], correct:0, re:"With both checks leaking the assembly cannot block reverse flow; the relief venting the zone to atmosphere is the remaining safeguard, but the assembly must be repaired at once. AWWA M14."},
  {id:334, block:4, sec:"Why Assemblies Fail", q:"A relief valve sensing line or passage plugged with debris will most likely make the relief:", opts:["Respond faster","Respond slowly or fail to open/close at the proper differential","Improve accuracy","Lower the supply pressure"], correct:1, re:"The relief reacts to pressure fed through its sensing passage; if that passage is fouled, the relief cannot sense the true differential and misbehaves. Clean the passage. AWWA M14 troubleshooting."},
  {id:335, block:4, sec:"Diagnosing Check Valve Faults", q:"On an RP field test, the first check is judged satisfactory when it holds a differential of at least:", opts:["1.0 psid","2.0 psid","5.0 psid","10.0 psid"], correct:2, re:"The first check of an RP must hold at least 5.0 psid (and the relief must not be open) to keep a safe buffer above the relief opening point. USC FCCCHR / AWWA M14 test criteria."},
  {id:336, block:4, sec:"Diagnosing Check Valve Faults", q:"Each check valve of a double check assembly (DCVA) must hold a differential of at least:", opts:["0.0 psid","2.0 psid","5.0 psid","1.0 psid"], correct:3, re:"On a DCVA, each check must hold at least 1.0 psid in the direction of flow; if it holds 1.0 psid forward it is assumed tight against reverse flow. AWWA M14 / USC FCCCHR."},
  {id:337, block:4, sec:"Diagnosing Check Valve Faults", q:"A first check that holds only 3.5 psid on an RP test should be recorded as:", opts:["Failing, because it is below the 5.0 psid minimum","Passing","Passing if the relief is closed","Not testable"], correct:0, re:"Below the 5.0 psid minimum the first check fails even if it is not visibly leaking; it no longer keeps the required buffer above relief opening. Repair and retest. USC FCCCHR / AWWA M14."},
  {id:338, block:4, sec:"Diagnosing Check Valve Faults", q:"During a check-valve test, water continues to flow out of the bleed/sight line and the gauge will not stabilize. This indicates the check is:", opts:["Holding tight","Leaking (not closing tight)","Over-tight","Frozen open by design"], correct:1, re:"A check is recorded as tight only when flow stops and the differential stabilizes. Continuing flow means the disc is not sealing - a leaking check. AWWA M14 test method."},
  {id:339, block:4, sec:"Diagnosing Check Valve Faults", q:"The assumption behind testing a check only in the direction of flow is that if it holds the minimum differential forward, it will:", opts:["Leak in reverse","Need replacement anyway","Hold tight in the reverse (no-flow) direction","Open the relief valve"], correct:2, re:"AWWA M14 test logic assumes a check holding its minimum differential in the flow direction will also seal against reverse flow, the condition that matters for backflow protection. AWWA M14."},
  {id:340, block:4, sec:"Diagnosing Check Valve Faults", q:"Trapped air in the test-kit hoses during a check test will most likely cause the differential reading to be:", opts:["Falsely low","Negative","Exactly correct","Falsely high"], correct:3, re:"Air in the hoses makes the gauge read a higher differential than truly exists, which can hide a leaking check (false pass). Bleed all air before reading. BAVCO / AWWA M14 test kit guidance."},
  {id:341, block:4, sec:"Diagnosing Check Valve Faults", q:"To isolate which check is leaking on a DCVA, the tester reads each check separately using:", opts:["The appropriate test cocks and the differential gauge for each check","Only the inlet shutoff","The relief valve discharge","A pressure gauge on the building side only"], correct:0, re:"The four test cocks let the tester read check 1 and check 2 independently with the differential gauge, identifying which check fails its 1.0 psid minimum. AWWA M14 / USC FCCCHR."},
  {id:342, block:4, sec:"Diagnosing Check Valve Faults", q:"A check valve that tests good one day but fails intermittently afterward most likely has:", opts:["A permanently torn disc","Intermittent debris that lodges and clears on the seat","A frozen body","A miscalibrated gauge only"], correct:1, re:"Loose grit that sometimes lands on the seat and sometimes flushes away produces an intermittent leak; the disc and seat should be inspected and cleaned. AWWA M14 troubleshooting."},
  {id:343, block:4, sec:"Diagnosing Check Valve Faults", q:"On an RP, if the first check fails but the second check is tight, the assembly:", opts:["Still fully passes","Needs no action","Fails and must be repaired and retested","Should have its relief removed"], correct:2, re:"Any failed component fails the assembly. A failed first check (even with a good second check) must be repaired and the assembly retested before return to service. USC FCCCHR / AWWA M14."},
  {id:344, block:4, sec:"Diagnosing Check Valve Faults", q:"A swinging or hinged check disc that no longer swings freely (binding on its pin) will most likely:", opts:["Seal perfectly","Have no effect on the test","Increase supply pressure","Stick partly open or closed and fail to seat properly"], correct:3, re:"A disc that binds on a corroded or fouled hinge/pin cannot fully seat or open, causing leakage or restriction. Free, clean, or replace the moving parts. AWWA M14 / manufacturer."},
  {id:345, block:4, sec:"Diagnosing Check Valve Faults", q:"When recording a check test, the value written down is the differential at the moment:", opts:["Flow stops and the gauge stabilizes (check closed tight)","Flow first starts","The relief opens","The shutoff is closed"], correct:0, re:"The recorded number is the stabilized differential after flow through the sight line stops, meaning the check has closed tight. AWWA M14 reporting method."},
  {id:346, block:4, sec:"Diagnosing Check Valve Faults", q:"A check disc that is correct but seated on a pitted or corroded seat will:", opts:["Hold tight anyway","Leak across the damaged seat surface","Raise the relief setting","Stop all flow"], correct:1, re:"Even a good disc cannot seal against a pitted, scratched, or corroded seat; the seat must be cleaned, resurfaced, or replaced. AWWA M14 / manufacturer repair guidance."},
  {id:347, block:4, sec:"Diagnosing Check Valve Faults", q:"If both checks of a DCVA read above 1.0 psid and hold steady, the tester records the assembly as:", opts:["Failed","Needing the relief replaced","Passing","Untestable"], correct:2, re:"Both checks holding at or above the 1.0 psid minimum with stable readings is a passing DCVA result. AWWA M14 / USC FCCCHR criteria."},
  {id:348, block:4, sec:"Diagnosing Check Valve Faults", q:"A leaking first check on an RP can sometimes be confirmed because the relief valve will:", opts:["Stay dry","Close the inlet","Read higher pressure","Discharge at static no-flow until the check is serviced"], correct:3, re:"A first check that leaks at rest lets the zone rise toward supply, so the relief discharges continuously at static condition - a telltale of first-check fouling. USC FCCCHR / AWWA M14."},
  {id:349, block:4, sec:"Diagnosing Check Valve Faults", q:"Before condemning a leaking check, the tester should first verify the leak is not caused by:", opts:["Air in the hoses or a not-fully-seated test-cock/needle valve","Correct gauge calibration","The building being occupied","Proper flow direction"], correct:0, re:"Trapped air or a leaking test connection can mimic a leaking check (false fail or odd reading); confirm the kit is bled and tight before judging the assembly. BAVCO / AWWA M14."},
  {id:350, block:4, sec:"Diagnosing Check Valve Faults", q:"The check valves in an RP or DC assembly are spring-loaded so they:", opts:["Open only with reverse flow","Close positively against reverse flow even at low differential","Stay open at all times","Throttle the flow continuously"], correct:1, re:"Spring loading drives the disc onto the seat so the check closes against reverse flow even before backpressure builds, unlike an unloaded swing check. AWWA M14 / USC FCCCHR."},
  {id:351, block:4, sec:"Diagnosing Check Valve Faults", q:"A check that holds far higher than normal differential (very stiff) may indicate:", opts:["Nothing wrong, always ideal","A torn diaphragm","A clogged passage or a binding/over-loaded disc adding restriction","A failed gauge battery"], correct:2, re:"An abnormally high differential can mean debris restriction or a binding disc adding head loss; inspect for fouling or mechanical binding even though it 'holds'. AWWA M14 troubleshooting."},
  {id:352, block:4, sec:"Diagnosing Relief Valve Faults", q:"On an RP field test, the relief valve must begin to open (relief opening point) at a differential of at least:", opts:["0.5 psid","1.0 psid","5.0 psid","2.0 psid"], correct:3, re:"The RP differential relief valve must open at no less than 2.0 psid between supply and zone. Below 2.0 psid opening it fails. USC FCCCHR / AWWA M14 test criteria."},
  {id:353, block:4, sec:"Diagnosing Relief Valve Faults", q:"A relief valve recorded as opening at 1.4 psid on an RP test should be marked:", opts:["Failing, because it is below the 2.0 psid minimum","Passing","Passing if the checks are good","Not applicable"], correct:0, re:"An opening point under 2.0 psid fails; the relief must open at 2.0 psid or higher to vent the zone before it can rise to supply pressure. USC FCCCHR / AWWA M14."},
  {id:354, block:4, sec:"Diagnosing Relief Valve Faults", q:"The relief valve must always open at a differential that is which way relative to the first check's hold value?", opts:["Higher than the check value","Lower than the check value, leaving a safety buffer","Exactly equal to it","Negative"], correct:1, re:"The relief opening point (>=2.0 psid) must stay below the first-check hold (>=5.0 psid) so the check keeps the zone safely above the relief setting. USC FCCCHR / AWWA M14 buffer requirement."},
  {id:355, block:4, sec:"Diagnosing Relief Valve Faults", q:"To prove the relief on a discharging RP is itself working, a tester can establish flow through test cock No. 4; if the discharge stops, it shows the relief:", opts:["Is broken","Opened too late","Closed and is functioning - the leak was from a fouled check","Has a torn diaphragm"], correct:2, re:"With both checks held open by the No. 4 flow, a relief that then seats proves the relief is good and the prior discharge came from a fouled check. If it still leaks, suspect the relief or its sensing passage. AWWA M14 / Backflow Prevention Journal."},
  {id:356, block:4, sec:"Diagnosing Relief Valve Faults", q:"If the RP relief still discharges while water flows out test cock No. 4 (both checks held open), the fault is most likely:", opts:["The first check","The second check","The inlet shutoff valve","Debris in the relief valve or its sensing line"], correct:3, re:"With both checks forced open by the No. 4 flow, the checks are out of the equation; continuing relief leakage points to debris in the relief or its sensing passage. AWWA M14 / Backflow Prevention Journal."},
  {id:357, block:4, sec:"Diagnosing Relief Valve Faults", q:"A relief valve that opens correctly but then will not reseat (stays open) is most likely:", opts:["Fouled or has worn rubber on its seat","Perfectly fine","Set too high","Frozen shut"], correct:0, re:"A relief that opens but cannot reseat usually has debris or worn/torn rubber on the relief seat; clean or replace the relief module. AWWA M14 / manufacturer repair guidance."},
  {id:358, block:4, sec:"Diagnosing Relief Valve Faults", q:"The differential relief valve of an RP senses the difference between the supply pressure and the:", opts:["Atmospheric pressure outside","Pressure in the zone between the two checks","Downstream building pressure","Gauge battery voltage"], correct:1, re:"The relief continuously compares supply pressure to the central-zone pressure; when the zone rises within about 2 psi of supply, the relief opens. USC FCCCHR / AWWA M14."},
  {id:359, block:4, sec:"Diagnosing Relief Valve Faults", q:"On a PVB (pressure vacuum breaker) test, the air-inlet valve must open at a differential of at least:", opts:["5.0 psid","2.0 psid","1.0 psid","0.0 psid"], correct:2, re:"A PVB air-inlet valve must open at 1.0 psid or greater (and the check must be loaded to at least 1.0 psid). USC FCCCHR / AWWA M14 PVB criteria."},
  {id:360, block:4, sec:"Diagnosing Relief Valve Faults", q:"A relief valve that 'spits' briefly then reseats during a supply pressure dip is:", opts:["Failing and must be replaced","Reading a bad gauge","Stuck open","Functioning normally by venting and reseating"], correct:3, re:"Brief venting then reseating as supply fluctuates is normal protective behavior, not a failure - it keeps the zone below supply. Persistent discharge is the problem to chase. AWWA M14 / USC FCCCHR."},
  {id:361, block:4, sec:"Diagnosing Relief Valve Faults", q:"To verify the relief opening point with a test kit, the tester slowly bleeds supply pressure and notes the differential at which the relief:", opts:["First begins to discharge (opens)","Fully closes","Reaches supply pressure","Reads zero"], correct:0, re:"The opening point is the differential at which the relief just begins to discharge as supply is bled down; it must be 2.0 psid or higher. USC FCCCHR / AWWA M14 procedure."},
  {id:362, block:4, sec:"Diagnosing Relief Valve Faults", q:"A relief valve module with a hardened, set rubber diaphragm will most commonly:", opts:["Open later and seal better","Fail to hold its differential and weep or open at the wrong point","Have no symptom","Increase the check differential"], correct:1, re:"A diaphragm that has lost resilience cannot accurately hold the supply-to-zone differential, so the relief weeps or opens off-spec. Replace the relief module. AWWA M14 / manufacturer."},
  {id:363, block:4, sec:"Diagnosing Relief Valve Faults", q:"The relief valve's discharge port (air gap) must be kept:", opts:["Capped tightly","Plugged with debris","Clear and not submerged or directly connected to a drain","Below the floor drain water line"], correct:2, re:"The relief must discharge through an open air gap; capping it or submerging the outlet defeats the air gap and can cause a cross-connection. AWWA M14 / USC FCCCHR installation."},
  {id:364, block:4, sec:"Diagnosing Relief Valve Faults", q:"An RP relief valve that opens at the correct point and reseats cleanly when flow is established is recorded as:", opts:["Failing","Untestable","Needing replacement","Passing"], correct:3, re:"A relief that opens at 2.0 psid or higher and reseats properly meets the criteria and is recorded as passing, provided both checks also pass. USC FCCCHR / AWWA M14."},
  {id:365, block:4, sec:"Diagnosing Relief Valve Faults", q:"A relief valve discharging steadily even though both checks separately test tight suggests the problem is:", opts:["Within the relief valve itself or its sensing passage","Definitely the first check","The downstream piping size","Gauge calibration only"], correct:0, re:"If both checks pass yet the relief keeps discharging, the relief module, its diaphragm, or its sensing passage is at fault and should be serviced. AWWA M14 troubleshooting."},
  {id:366, block:4, sec:"Diagnosing Relief Valve Faults", q:"The purpose of the relief valve opening when the differential falls toward 2 psi is to:", opts:["Increase downstream pressure","Dump the zone to atmosphere so contaminated water cannot reach the supply","Recalibrate the checks","Stop the gauge from reading"], correct:1, re:"By venting the central zone to atmosphere, the relief ensures any leakage past the second check spills out rather than backing into the potable supply. USC FCCCHR / AWWA M14."},
  {id:367, block:4, sec:"Diagnosing Relief Valve Faults", q:"A common field mistake that makes a good relief valve look like it is failing is:", opts:["Bleeding the hoses properly","Recording the opening point","Not noticing thermal expansion or a supply fluctuation causing legitimate discharge","Closing the inlet shutoff last"], correct:2, re:"Legitimate nuisance discharge from thermal expansion or supply swings can be mistaken for a defective relief; confirm the cause before condemning the relief. AWWA M14 / USC FCCCHR troubleshooting."},
  {id:368, block:4, sec:"Diagnosing Relief Valve Faults", q:"On a PVB, the check valve must be internally loaded and drip-tight in the direction of flow with at least:", opts:["10.0 psid","2.0 psid","5.0 psid","1.0 psid"], correct:3, re:"A PVB check must be loaded and drip-tight to at least 1.0 psid in the flow direction; the air inlet must open at 1.0 psid or greater. USC FCCCHR / AWWA M14 PVB criteria."},
  {id:369, block:4, sec:"Repair & Rebuild", q:"The correct first step before opening an assembly to replace internal parts is to:", opts:["Close the shutoff valves and relieve (depressurize) the assembly through a test cock","Open all test cocks fully","Remove the relief valve cover under pressure","Disconnect the gauge"], correct:0, re:"Always isolate with the shutoffs and bleed off pressure through a test cock before disassembly; opening a pressurized assembly is unsafe. AWWA M14 / manufacturer service procedure."},
  {id:370, block:4, sec:"Repair & Rebuild", q:"A manufacturer 'rubber kit' for an RP assembly typically contains:", opts:["A new gauge and hoses","Replacement check discs/seals, O-rings, and relief valve rubber","A new shutoff valve only","Calibration weights"], correct:1, re:"Rubber repair kits supply the wear items - check discs/seals, O-rings, and relief diaphragm/seat rubber - so worn or fouled rubber can be renewed. Manufacturer (Watts/Febco) repair-kit listings."},
  {id:371, block:4, sec:"Repair & Rebuild", q:"When rebuilding a check valve, a scored or pitted seat that the disc cannot seal against should be:", opts:["Left as is","Painted over","Cleaned, resurfaced, or replaced per the manufacturer","Tightened harder"], correct:2, re:"A damaged seat will leak even with a new disc; clean, reface (if designed for it), or replace it following manufacturer instructions. AWWA M14 / manufacturer repair guidance."},
  {id:372, block:4, sec:"Repair & Rebuild", q:"A weak or broken check spring is corrected by:", opts:["Stretching the old spring","Reversing the disc","Adding washers under the seat","Installing the manufacturer's replacement spring or check module"], correct:3, re:"Springs that have weakened or broken are replaced with the correct manufacturer spring/module so the check loads properly and holds its minimum differential. Manufacturer repair guidance."},
  {id:373, block:4, sec:"Repair & Rebuild", q:"When replacing parts, using non-OEM or mismatched components can:", opts:["Void the assembly's approval and cause it to fail or test incorrectly","Always improve performance","Have no effect","Raise the relief setting safely"], correct:0, re:"Only manufacturer-specified parts keep the assembly within its USC/ASSE approval; wrong parts can change spring loads and seating and invalidate the listing. USC FCCCHR / manufacturer."},
  {id:374, block:4, sec:"Repair & Rebuild", q:"Before reassembling a cleaned check, the technician should:", opts:["Leave debris in place","Flush out grit and inspect the disc, seat, and spring for damage","Skip inspection to save time","Apply pipe dope to the rubber"], correct:1, re:"Flushing remaining debris and inspecting each part ensures the rebuilt check will seat; petroleum products on rubber are avoided as they degrade it. AWWA M14 / manufacturer."},
  {id:375, block:4, sec:"Repair & Rebuild", q:"The relief valve assembly on an RP is serviced by:", opts:["Welding it shut","Removing it permanently","Replacing the relief module / diaphragm and seat rubber and cleaning the sensing passage","Capping its outlet"], correct:2, re:"Relief problems are cured by renewing the relief module rubber/diaphragm and seat and clearing the sensing passage so it senses the differential correctly. Manufacturer / AWWA M14 repair guidance."},
  {id:376, block:4, sec:"Repair & Rebuild", q:"A lubricant used on O-rings during a backflow rebuild should be:", opts:["Petroleum grease","Pipe thread sealant","Motor oil","An approved non-toxic, water-safe (FDA/NSF) lubricant compatible with rubber"], correct:3, re:"Only potable-water-safe, rubber-compatible lubricants are used; petroleum products swell and destroy the seals and can contaminate water. Manufacturer / NSF guidance."},
  {id:377, block:4, sec:"Repair & Rebuild", q:"If repair parts are no longer available or the body is cracked, the proper action is to:", opts:["Replace the entire assembly with an approved unit","Improvise parts","Leave it out of service indefinitely with no plan","Cap the relief and reuse it"], correct:0, re:"A cracked body or obsolete unit with no parts must be replaced with a currently approved assembly; field-improvised parts are not allowed. AWWA M14 / USC FCCCHR."},
  {id:378, block:4, sec:"Repair & Rebuild", q:"When reinstalling internal parts, tightening bolts unevenly or over-torquing can:", opts:["Improve the seal","Distort the cover/seat and cause leaks","Recalibrate the relief","Have no effect"], correct:1, re:"Uneven or excessive torque warps covers and seats and pinches O-rings, creating leaks; follow the manufacturer's torque pattern and values. Manufacturer service guidance."},
  {id:379, block:4, sec:"Repair & Rebuild", q:"After cleaning a fouled relief valve, water that still weeps from it usually means:", opts:["The job is done","The checks are bad","The relief seat or diaphragm rubber is worn and must be replaced, not just cleaned","The gauge is wrong"], correct:2, re:"If cleaning does not stop the weep, the relief's rubber has taken a set or is damaged and the module/diaphragm should be replaced. AWWA M14 / manufacturer."},
  {id:380, block:4, sec:"Repair & Rebuild", q:"The shutoff (resilient-seated gate or ball) valves of an assembly are tested before the checks because the tester must verify they:", opts:["Are painted","Read the gauge","Open the relief","Close drip-tight so they can isolate the assembly for an accurate test"], correct:3, re:"Shutoffs must seat tight; a leaking No. 1 or No. 2 shutoff lets supply or backpressure bypass the test and corrupts the readings. AWWA M14 / USC FCCCHR procedure."},
  {id:381, block:4, sec:"Repair & Rebuild", q:"During disassembly, keeping the parts organized and following the manufacturer's exploded view helps ensure:", opts:["Correct orientation and that no spring, disc, or O-ring is omitted on reassembly","A slower job","The relief opens lower","The gauge recalibrates"], correct:0, re:"Following the manufacturer's parts diagram prevents reversed discs, missing springs, or pinched O-rings that would make the rebuilt assembly fail. Manufacturer service guidance."},
  {id:382, block:4, sec:"Repair & Rebuild", q:"A worn first check that cannot be brought up to 5.0 psid after cleaning should be:", opts:["Returned to service as is","Rebuilt with new disc/seal and spring (or module) until it meets the minimum","Left leaking","Bypassed"], correct:1, re:"If cleaning alone will not restore the 5.0 psid minimum, renew the disc/seal and spring (or replace the check module) so the check meets criteria. AWWA M14 / manufacturer."},
  {id:383, block:4, sec:"Repair & Rebuild", q:"Petroleum-based oils or greases are kept off backflow rubber parts because they:", opts:["Help the rubber last longer","Improve the relief setting","Swell, soften, and deteriorate the rubber, causing leaks","Clean the seat"], correct:2, re:"Petroleum products are incompatible with the rubber used in checks and relief diaphragms; they cause swelling and failure. Use only approved water-safe lubricants. Manufacturer / NSF guidance."},
  {id:384, block:4, sec:"Repair & Rebuild", q:"When slowly returning a repaired assembly to service, the correct sequence is generally to:", opts:["Open the downstream (No. 2) shutoff first, fast","Leave the inlet closed","Open both fully at once","Open the upstream (No. 1) shutoff slowly first to fill, then open the downstream (No. 2)"], correct:3, re:"Open the upstream shutoff slowly to fill and pressurize the assembly, then open the downstream shutoff; this avoids surge and water hammer that could lift the relief. AWWA M14 / manufacturer startup."},
  {id:385, block:4, sec:"Repair & Rebuild", q:"Any leakage observed past a test cock or fitting after a rebuild should be corrected because it can:", opts:["Corrupt later test readings and indicate the assembly is not buttoned up","Be ignored","Improve accuracy","Lower the supply pressure safely"], correct:0, re:"Leaks at test cocks or fittings both waste water and skew future differential readings; reseal or replace the fitting so the assembly is tight. AWWA M14 / manufacturer."},
  {id:386, block:4, sec:"Gauge Calibration & Re-Test", q:"A backflow differential test gauge must maintain an accuracy of at least:", opts:["+/- 2.0 psid","+/- 0.2 psid","+/- 5.0 psid","+/- 10 psid"], correct:1, re:"The field test gauge must read within +/- 0.2 psid (per ASSE 1064 / industry guidance) so that 2 psid and 5 psid criteria can be judged reliably. BAVCO / TCEQ / ASSE 1064."},
  {id:387, block:4, sec:"Gauge Calibration & Re-Test", q:"How often is a backflow test kit normally required to be checked for accuracy / calibrated?", opts:["Every 5 years","Only when it breaks","At least once a year (annually)","Once in the life of the kit"], correct:2, re:"Most jurisdictions and industry guidance require the gauge to be accuracy-checked at least annually (and recalibrated if it drifts beyond +/- 0.2 psid). BAVCO / TCEQ."},
  {id:388, block:4, sec:"Gauge Calibration & Re-Test", q:"Calibration of a backflow test gauge should be traceable to:", opts:["The local water bill","The building's pressure","The manufacturer's paint code","A NIST-traceable reference standard"], correct:3, re:"Accuracy verification must trace back to a reference standard with calibration traceable to NIST so readings are defensible. TCEQ / BAVCO / ASSE 1064."},
  {id:389, block:4, sec:"Gauge Calibration & Re-Test", q:"A test gauge that reads 0.5 psid high will most dangerously cause a tester to:", opts:["Pass a relief or check that is actually below its minimum","Fail good assemblies only","Have no real effect","Read the supply pressure"], correct:0, re:"A gauge reading high can make a sub-minimum relief or check appear to meet the 2.0/5.0/1.0 psid criteria, passing an unsafe assembly. Hence the +/- 0.2 psid limit and annual check. BAVCO / TCEQ."},
  {id:390, block:4, sec:"Gauge Calibration & Re-Test", q:"Before each test, the tester should bleed all air from the kit hoses because trapped air:", opts:["Lowers the reading","Raises the differential reading and can hide a leaking check","Has no effect","Calibrates the gauge"], correct:1, re:"Air in the lines reads as extra differential (false high), masking a leaking check; bleeding the high and low hoses gives a true reading. BAVCO / AWWA M14 test kit guidance."},
  {id:391, block:4, sec:"Gauge Calibration & Re-Test", q:"After any repair or part replacement, the assembly must be:", opts:["Returned to service without testing","Painted","Retested and shown to pass before being placed back in service","Left for the next annual test"], correct:2, re:"Replacing a seal, spring, check, or relief changes internal dynamics; a passing retest and report are mandatory before the assembly goes back in service. AWWA M14 / regulatory requirement."},
  {id:392, block:4, sec:"Gauge Calibration & Re-Test", q:"A single 3-valve or 5-valve differential gauge is preferred over two separate pressure gauges because it:", opts:["Is cheaper to ship","Reads supply pressure only","Needs no calibration","Directly reads the small differential, avoiding the error of subtracting two large readings"], correct:3, re:"Subtracting two high-range gauges magnifies error at the small 1-5 psid values that matter; a differential gauge reads the difference directly and accurately. BAVCO / AWWA M14 test kit guidance."},
  {id:393, block:4, sec:"Gauge Calibration & Re-Test", q:"A test kit that has been dropped or shows erratic readings should be:", opts:["Removed from service and re-verified/calibrated before further testing","Kept in service","Used only on small assemblies","Painted and reused"], correct:0, re:"Physical shock can shift calibration; verify accuracy against a traceable standard before trusting the kit again. Erratic readings invalidate results. BAVCO / TCEQ."},
  {id:394, block:4, sec:"Gauge Calibration & Re-Test", q:"The test report after a repair-and-retest should record:", opts:["Only the tester's name","The final passing readings (check differentials and relief opening point) and that it passed","The paint color","The supply pressure only"], correct:1, re:"The retest report documents the actual final readings (each check differential and the relief opening point) proving the assembly meets criteria after repair. AWWA M14 / regulatory reporting."},
  {id:395, block:4, sec:"Gauge Calibration & Re-Test", q:"If a freshly calibrated gauge and a careful test still show the relief opening below 2.0 psid, the correct conclusion is the:", opts:["Gauge is wrong again","Test cannot be done","Relief valve is failing and must be repaired and retested","Supply pressure is too high"], correct:2, re:"Once gauge accuracy is confirmed, a sub-2.0 psid relief opening is a real failure of the relief, requiring service and a passing retest. USC FCCCHR / AWWA M14."},
  {id:396, block:4, sec:"Gauge Calibration & Re-Test", q:"A calibration record or sticker on the test kit serves to:", opts:["Decorate the kit","Replace the test report","Increase the relief setting","Document the last accuracy verification date and that the gauge is within tolerance"], correct:3, re:"The calibration sticker/certificate proves the gauge was verified within +/- 0.2 psid by a given date, which regulators and water purveyors require. TCEQ / BAVCO."},
  {id:397, block:4, sec:"Gauge Calibration & Re-Test", q:"During the relief opening-point test, the gauge needle valves (control valves) are used to:", opts:["Slowly bleed pressure so the exact opening differential can be read","Paint the gauge","Increase supply pressure","Close the relief permanently"], correct:0, re:"The kit's needle/control valves let the tester bleed pressure gradually and capture the differential at which the relief first opens. AWWA M14 / USC FCCCHR procedure."},
  {id:398, block:4, sec:"Gauge Calibration & Re-Test", q:"A retest that fails after a repair means the technician should:", opts:["Submit it as passing anyway","Diagnose and correct the remaining fault, then retest until it passes","Leave it in service","Remove the relief valve"], correct:1, re:"An assembly may only be returned to service after a passing test; a failed retest means more repair (e.g., a missed worn part) and another test. AWWA M14 / regulatory requirement."},
  {id:399, block:4, sec:"Gauge Calibration & Re-Test", q:"Connecting the high and low hoses of the differential gauge to a common point should ideally read:", opts:["About 2 psid","About 5 psid","About 0 psid (zero), confirming the gauge zeroes correctly","The supply pressure"], correct:2, re:"With both hoses on the same pressure there is no differential, so a correct gauge should read about zero; a non-zero reading flags a calibration or air-bleed problem. BAVCO / AWWA M14."},
  {id:400, block:4, sec:"Gauge Calibration & Re-Test", q:"The fundamental reason gauge accuracy and a passing retest matter so much is that:", opts:["They speed up paperwork","They raise supply pressure","They lower water bills","An inaccurate gauge or skipped retest can let a contaminated or failed assembly stay in service"], correct:3, re:"The entire point of testing is public-health protection; a wrong gauge or missing retest can leave a failed high-hazard assembly protecting drinking water. USC FCCCHR / AWWA M14."},
  {id:401, block:5, sec:"California Regulation (Title 17 / SWRCB)", q:"In California, which document adopted by the State Water Resources Control Board now governs cross-connection control and supersedes the older Title 17 cross-connection regulations?", opts:["The Cross-Connection Control Policy Handbook (CCCPH)","The Uniform Plumbing Code","The California Fire Code","OSHA 29 CFR 1910"], correct:0, re:"The SWRCB adopted the Cross-Connection Control Policy Handbook (CCCPH), which supersedes Title 17 CCR Sections 7583-7586 and 7601-7605 as they pertain to cross-connection control. Source: SWRCB CCCPH webpage; CCCPH (2023)."},
  {id:402, block:5, sec:"California Regulation (Title 17 / SWRCB)", q:"What is the effective date of California's Cross-Connection Control Policy Handbook (CCCPH)?", opts:["January 1, 2000","July 1, 2024","January 1, 1985","July 1, 2030"], correct:1, re:"The CCCPH was adopted December 19, 2023 and became effective July 1, 2024. Source: SWRCB Cross-Connection Control Policy Handbook rulemaking history."},
  {id:403, block:5, sec:"California Regulation (Title 17 / SWRCB)", q:"Which California state agency adopted and administers the Cross-Connection Control Policy Handbook?", opts:["The U.S. EPA","The California Department of Transportation","The State Water Resources Control Board (Division of Drinking Water)","The federal FMCSA"], correct:2, re:"The State Water Resources Control Board (SWRCB), through its Division of Drinking Water, adopted and administers the CCCPH. Source: SWRCB CCCPH webpage."},
  {id:404, block:5, sec:"California Regulation (Title 17 / SWRCB)", q:"Before the CCCPH, which sections of Title 17 of the California Code of Regulations contained the cross-connection control requirements?", opts:["Sections 1000-1100","Sections 5000-5050","Sections 60000-60050","Sections 7583-7605"], correct:3, re:"Title 17 CCR Sections 7583 through 7605 contained California's cross-connection control regulations; the CCCPH superseded Sections 7583-7586 and 7601-7605. Source: Title 17 CCR; SWRCB CCCPH."},
  {id:405, block:5, sec:"California Regulation (Title 17 / SWRCB)", q:"Under California cross-connection control rules, how often must a backflow prevention assembly be field tested at a minimum?", opts:["At least annually (every 12 months)","Only once at installation","Every five years","Every ten years"], correct:0, re:"California rules (Title 17 and now the CCCPH) require backflow prevention assemblies to be field tested upon installation and at least annually thereafter, or more often if the purveyor/health agency requires. Source: CCCPH; former Title 17 CCR §7605."},
  {id:406, block:5, sec:"California Regulation (Title 17 / SWRCB)", q:"In addition to testing at installation and annually, when else does California require a backflow prevention assembly to be tested?", opts:["Only when the property is sold","After repair, relocation, or replacement of the assembly","Only every leap year","Never again after installation"], correct:1, re:"California requires testing upon installation, after any repair, relocation, or replacement, and at least annually. A disturbed assembly must be re-verified before being returned to service. Source: CCCPH; AWWA M14."},
  {id:407, block:5, sec:"California Regulation (Title 17 / SWRCB)", q:"Which California statutes (Health & Safety Code) provide the legal authority for the state's cross-connection control and safe drinking water requirements?", opts:["Vehicle Code §1000-1100","Penal Code §187","Health & Safety Code §116800-116820","Civil Code §1500"], correct:2, re:"California Health & Safety Code Sections 116800-116820 (within the California Safe Drinking Water Act) authorize cross-connection control requirements implemented through Title 17/CCCPH. Source: CA Health & Safety Code §116800 et seq."},
  {id:408, block:5, sec:"California Regulation (Title 17 / SWRCB)", q:"Under California regulation, who has the primary legal duty to protect the public water system from contamination by cross-connections?", opts:["The county tax assessor","The individual tester only","The state fire marshal","The water supplier (public water system / purveyor)"], correct:3, re:"The water supplier (public water system) must protect the public water supply from contamination by implementing a cross-connection control program. Source: former Title 17 CCR §7584; CCCPH responsibilities of the PWS."},
  {id:409, block:5, sec:"California Regulation (Title 17 / SWRCB)", q:"Title 17 / CCCPH requires that the type of backflow protection installed be based on what factor?", opts:["The degree of hazard the customer's premises pose to the public water supply","The age of the building","The exterior paint color","The customer's monthly water bill"], correct:0, re:"The required type of protection (air gap, RP, DC, etc.) is determined by the degree of hazard posed by the user's premises to the public water system. Source: CCCPH hazard assessment provisions; former Title 17 CCR §7585."},
  {id:410, block:5, sec:"California Regulation (Title 17 / SWRCB)", q:"Under the CCCPH, certified backflow tester certifications must be recognized by which body beginning July 1, 2026?", opts:["The local chamber of commerce","The State Water Resources Control Board (SWRCB)","The U.S. Department of Labor","The county sheriff"], correct:1, re:"From July 1, 2026, testers must hold a certification from an organization recognized by the SWRCB to comply with the CCCPH. Source: SWRCB Backflow Tester and Cross-Connection Control Specialists Certification page."},
  {id:411, block:5, sec:"California Regulation (Title 17 / SWRCB)", q:"Under the CCCPH, beginning July 1, 2027, tester certifying organizations used for compliance must also be accredited to which standard?", opts:["NFPA 13","ISO 9001 only","ANSI accreditation to ISO/IEC 17024","ASME boiler code"], correct:2, re:"Effective July 1, 2027, only certifying organizations ANSI-accredited to ISO/IEC 17024 (certification of persons) may be used for CCCPH compliance. Source: SWRCB Backflow Tester Certification page."},
  {id:412, block:5, sec:"California Regulation (Title 17 / SWRCB)", q:"Which of the following is NOT a protection method recognized under California cross-connection control rules?", opts:["Air-gap separation (AG)","Reduced-pressure principle assembly (RP)","Double check valve assembly (DC)","A loosely wrapped rag over the pipe"], correct:3, re:"Recognized methods include air-gap separation, reduced-pressure principle assemblies, double check valve assemblies, and vacuum breakers. A rag is not an approved method. Source: CCCPH; former Title 17 CCR §7603-7604."},
  {id:413, block:5, sec:"California Regulation (Title 17 / SWRCB)", q:"Why did California replace the older Title 17 cross-connection provisions with the CCCPH?", opts:["Because Title 17 had remained largely unchanged since the 1980s and needed modernization","To remove all testing requirements","To eliminate the role of water purveyors","To make backflow assemblies optional"], correct:0, re:"The CCCPH modernizes requirements that had remained largely unchanged since the original Title 17 adoption in the 1980s, expanding and updating program standards. Source: SWRCB CCCPH adoption materials."},
  {id:414, block:5, sec:"California Regulation (Title 17 / SWRCB)", q:"Under California rules, who is responsible for ensuring a customer's backflow prevention assembly is tested and kept in proper working order?", opts:["The State Water Board directly","The water customer/owner of the assembly","The neighboring property owner","The assembly manufacturer"], correct:1, re:"It is the water customer's responsibility to ensure the assembly is tested annually and maintained in proper operating condition at all times. Source: CCCPH; California water purveyor cross-connection programs."},
  {id:415, block:5, sec:"California Regulation (Title 17 / SWRCB)", q:"For premises handling materials dangerous to health (a health hazard), what level of protection does California require at the service connection?", opts:["No protection is required","Only a hose-bibb vacuum breaker","An air gap (AG) or reduced-pressure principle assembly (RP)","A simple shutoff valve"], correct:2, re:"Premises that pose a health hazard (contaminant) must be protected by an approved air gap or reduced-pressure principle assembly. Source: CCCPH hazard provisions; former Title 17 CCR §7604 Table 1."},
  {id:416, block:5, sec:"California Regulation (Title 17 / SWRCB)", q:"Air gaps used for cross-connection control in California are required to meet the minimum dimensions of which referenced standard?", opts:["FMVSS 121 (air brakes)","NFPA 70 (National Electrical Code)","ASTM A36 (structural steel)","ASME A112.1.2 (minimum air gaps)"], correct:3, re:"The CCCPH references ASME A112.1.2 for minimum air gaps for plumbing fixtures. Source: CCCPH; ASME A112.1.2."},
  {id:417, block:5, sec:"California Regulation (Title 17 / SWRCB)", q:"Under the CCCPH, who may a public water system designate to carry out cross-connection control duties such as hazard surveys?", opts:["A certified cross-connection control specialist","Anyone, with no qualifications","Only the state Governor","Only out-of-state contractors"], correct:0, re:"The CCCPH requires the PWS to use certified cross-connection control specialists to carry out program duties such as surveys and hazard assessments. Source: CCCPH article on specialists; SWRCB specialists certification page."},
  {id:418, block:5, sec:"AWWA M14 & USC FCCCHR Roles", q:"What is AWWA Manual M14?", opts:["A federal law","AWWA's recommended-practices manual on backflow prevention and cross-connection control","A California state statute","An OSHA confined-space permit"], correct:1, re:"AWWA M14, 'Backflow Prevention and Cross-Connection Control: Recommended Practices,' is an industry manual of water-supply practice, not a law. Source: AWWA Manual M14."},
  {id:419, block:5, sec:"AWWA M14 & USC FCCCHR Roles", q:"What is the current edition of AWWA Manual M14?", opts:["First Edition","Second Edition","Fifth Edition (published 2024)","There is no edition system"], correct:2, re:"The Fifth Edition of AWWA M14 was published in 2024 (ANSI reference AWWA M14-2024). Source: AWWA store; ANSI webstore listing AWWA M14-2024."},
  {id:420, block:5, sec:"AWWA M14 & USC FCCCHR Roles", q:"Legally speaking, AWWA standards and manuals such as M14 are best described as which of the following?", opts:["Secret industry documents","Federal criminal statutes","Automatically mandatory in every state","Voluntary consensus documents that do not supersede applicable law"], correct:3, re:"AWWA standards are voluntary consensus documents and do not supersede or displace applicable laws, regulations, or codes; they become enforceable only when adopted by an authority. Source: AWWA standards program statement."},
  {id:421, block:5, sec:"AWWA M14 & USC FCCCHR Roles", q:"What does the USC FCCCHR (Foundation for Cross-Connection Control and Hydraulic Research) primarily do?", opts:["Evaluate and approve backflow prevention assemblies and publish field-test procedures","Set vehicle emission limits","Issue driver's licenses","Regulate electrical wiring"], correct:0, re:"The USC FCCCHR runs an approval program (lab and field evaluation) for backflow prevention assemblies and publishes the Manual of Cross-Connection Control with field-test procedures. Source: USC FCCCHR approval and list webpages."},
  {id:422, block:5, sec:"AWWA M14 & USC FCCCHR Roles", q:"For how long is a backflow prevention assembly approval valid on the USC FCCCHR List before it must be renewed?", opts:["One year","Three years","Ten years","Indefinitely; it is never renewed"], correct:1, re:"USC FCCCHR approvals are granted for a period of three years and are subject to renewal. Source: USC FCCCHR List of Approved Backflow Prevention Assemblies."},
  {id:423, block:5, sec:"AWWA M14 & USC FCCCHR Roles", q:"What distinctive requirement does the USC FCCCHR approval program include that many other approval programs do not?", opts:["A 50-year warranty","A requirement that the assembly be painted red","A mandatory one-year field evaluation before listing","Approval by the U.S. President"], correct:2, re:"The USC FCCCHR is noted as the only backflow approval program that mandates a one-year field evaluation, in addition to laboratory testing, before an assembly is listed. Source: USC FCCCHR approval program description."},
  {id:424, block:5, sec:"AWWA M14 & USC FCCCHR Roles", q:"The USC FCCCHR 'List' identifies each approved assembly by all of the following EXCEPT:", opts:["Type of assembly and manufacturer","Model and size","Approval and renewal dates","The home address of the property owner"], correct:3, re:"The List identifies each assembly by type, manufacturer, model, size, the manual edition under which it was approved, and approval/renewal dates - not customer addresses. Source: USC FCCCHR List."},
  {id:425, block:5, sec:"AWWA M14 & USC FCCCHR Roles", q:"Which document published by USC FCCCHR is widely used to standardize how testers perform backflow assembly field tests?", opts:["The Manual of Cross-Connection Control (field test procedures, e.g., 10th Edition)","The National Electrical Code","The federal tax code","The MUTCD"], correct:0, re:"USC FCCCHR's Manual of Cross-Connection Control (with field-test procedures, current 10th Edition) standardizes tester field-test methods used in many programs. Source: USC FCCCHR; USC 10th Edition manual."},
  {id:426, block:5, sec:"AWWA M14 & USC FCCCHR Roles", q:"AWWA M14 explains that the two basic types of backflow are which pair?", opts:["Forward flow and reverse osmosis","Backsiphonage and backpressure","Evaporation and condensation","Cavitation and surge"], correct:1, re:"AWWA M14 describes the two types of backflow as backsiphonage (caused by negative supply pressure) and backpressure (downstream pressure exceeding supply). Source: AWWA M14."},
  {id:427, block:5, sec:"AWWA M14 & USC FCCCHR Roles", q:"What is the primary purpose of AWWA Manual M14?", opts:["To set commercial driver hours-of-service limits","To regulate refrigerant handling","To describe the causes and prevention of backflow and cross-connections in potable water systems","To establish minimum wage rules"], correct:2, re:"M14 describes the causes and prevention of backflow and cross-connections and helps water systems build a cross-connection control program. Source: AWWA M14 description."},
  {id:428, block:5, sec:"AWWA M14 & USC FCCCHR Roles", q:"With what university is the USC FCCCHR (Foundation for Cross-Connection Control and Hydraulic Research) affiliated?", opts:["University of Texas","New York University","University of Florida","University of Southern California (in California)"], correct:3, re:"The Foundation is affiliated with the University of Southern California (USC) in California. Source: USC FCCCHR (fccchr.usc.edu)."},
  {id:429, block:5, sec:"AWWA M14 & USC FCCCHR Roles", q:"A backflow prevention assembly must successfully complete which two phases to earn USC FCCCHR approval?", opts:["Laboratory evaluation and field evaluation","Marketing review and sales quota","A taste test and a color test","A noise test and a weight test"], correct:0, re:"USC FCCCHR approval requires successful completion of both a laboratory evaluation and a field evaluation under Foundation supervision. Source: USC FCCCHR approval program."},
  {id:430, block:5, sec:"AWWA M14 & USC FCCCHR Roles", q:"Which statement best describes the relationship between AWWA M14 / USC FCCCHR documents and a local water purveyor?", opts:["They automatically replace all local rules","A purveyor or jurisdiction may adopt or reference them, giving them enforceable effect locally","They forbid purveyors from having any program","They apply only outside the United States"], correct:1, re:"These are reference documents; they gain enforceable effect where a purveyor, state, or jurisdiction adopts or references them in its rules. Source: AWWA standards program; USC FCCCHR program use by agencies."},
  {id:431, block:5, sec:"AWWA M14 & USC FCCCHR Roles", q:"According to AWWA M14, a complete cross-connection control program helps a water system do which of the following?", opts:["Design highway interchanges","File income taxes","Choose, install, and maintain appropriate backflow prevention","Certify welders"], correct:2, re:"M14 helps a water system choose, install, and maintain backflow prevention devices as part of a total cross-connection control program. Source: AWWA M14 description."},
  {id:432, block:5, sec:"AWWA M14 & USC FCCCHR Roles", q:"When a backflow assembly is shown on the USC FCCCHR List, the listing also notes the edition of which document under which the assembly was approved?", opts:["A vehicle owner's manual","The local newspaper","The federal budget","The USC Foundation Manual of Cross-Connection Control"], correct:3, re:"Each listed assembly notes the edition of the USC Foundation manual (specifications/field-test procedures) under which it was approved. Source: USC FCCCHR List."},
  {id:433, block:5, sec:"AWWA M14 & USC FCCCHR Roles", q:"Why is it important for a tester to use the USC FCCCHR List or the purveyor's approved list when verifying an assembly?", opts:["To confirm the assembly model is an approved type for the application","To find the manufacturer's stock price","To choose paint colors","To set the water bill amount"], correct:0, re:"The approved list confirms the make/model is an approved assembly type acceptable for the installation; non-approved devices may not satisfy the purveyor or regulation. Source: USC FCCCHR List; purveyor program rules."},
  {id:434, block:5, sec:"AWWA M14 & USC FCCCHR Roles", q:"AWWA M14 is published as part of which AWWA series?", opts:["The federal Code of Regulations","The Manual of Water Supply Practices (M-series)","The OSHA outreach series","The state vehicle code"], correct:1, re:"M14 is part of AWWA's Manual of Water Supply Practices (the 'M' series of recommended-practice manuals). Source: AWWA Manuals / M14 listing."},
  {id:435, block:5, sec:"Water Purveyor Programs", q:"Under California rules, which of the following is a required element of a public water system's cross-connection control program?", opts:["A ban on indoor plumbing","A requirement that all customers paint their houses","Adoption of operating rules or an ordinance to implement the program","Free bottled water for all residents"], correct:2, re:"A cross-connection control program must include operating rules, ordinances, or a resolution to implement it. Source: former Title 17 CCR §7584; CCCPH program elements."},
  {id:436, block:5, sec:"Water Purveyor Programs", q:"As part of its program, what must a water purveyor conduct to identify premises where cross-connections are likely to occur?", opts:["A credit check","A traffic study","A taste survey","Surveys / hazard assessments of customer premises"], correct:3, re:"Purveyors must survey their service area and conduct hazard assessments to identify actual or potential cross-connections and the degree of hazard. Source: CCCPH Chapter 3 hazard assessment; former Title 17 CCR §7584."},
  {id:437, block:5, sec:"Water Purveyor Programs", q:"A water purveyor's program must provide for at least one person who is trained/certified in which field?", opts:["Cross-connection control","Tax preparation","Highway design","Food service"], correct:0, re:"The program must provide at least one person trained/certified in cross-connection control to carry it out. Source: former Title 17 CCR §7584; CCCPH specialist requirement."},
  {id:438, block:5, sec:"Water Purveyor Programs", q:"Which of the following must a water purveyor establish as part of its cross-connection control program?", opts:["A fleet of delivery trucks","A procedure or system for testing backflow preventers","A retail store","A radio station"], correct:1, re:"The program must establish a procedure or system for testing backflow preventers (including tracking and annual test notices). Source: former Title 17 CCR §7584; CCCPH testing program."},
  {id:439, block:5, sec:"Water Purveyor Programs", q:"The CCCPH requires a public water system to keep program records that include details of each backflow prevention assembly. Which detail is required?", opts:["The owner's voting record","The owner's favorite color","Type, manufacturer, model, size, location, owner, install date, and serial number","The owner's vehicle make"], correct:2, re:"Records must include each assembly's hazard/application, location, owner, type, manufacturer, model, size, installation date, and serial number. Source: CCCPH recordkeeping requirements."},
  {id:440, block:5, sec:"Water Purveyor Programs", q:"Under the CCCPH, how many of the most recent hazard assessments at each premises must a purveyor retain in its records?", opts:["Fifty","None","Only the very first one ever done","The two most recent hazard assessments"], correct:3, re:"The CCCPH requires the program to keep the two most recent hazard assessments conducted at each premises. Source: CCCPH recordkeeping requirements."},
  {id:441, block:5, sec:"Water Purveyor Programs", q:"If a customer fails to have a required backflow assembly tested or repaired, what enforcement action may a water purveyor ultimately take under its ordinance?", opts:["Discontinue (shut off) water service until compliance is achieved","Tow the customer's car","Revoke the customer's driver's license","Raise the sales tax"], correct:0, re:"Purveyor ordinances typically authorize discontinuing water service for non-compliance with testing or installation requirements, after notice. Source: CCCPH/Title 17 program enforcement; purveyor cross-connection ordinances."},
  {id:442, block:5, sec:"Water Purveyor Programs", q:"A water purveyor's cross-connection control program is intended primarily to protect what?", opts:["The purveyor's advertising budget","The public potable water supply from contamination","The local sports team","The price of refrigerant"], correct:1, re:"The fundamental purpose of the program is to protect the public potable water supply from backflow contamination. Source: CCCPH; former Title 17 CCR §7584."},
  {id:443, block:5, sec:"Water Purveyor Programs", q:"Under California rules, who may a water supplier contract with to implement all or part of its cross-connection control program?", opts:["A foreign government","Any random unlicensed person","The local health agency or another agency approved by the health agency","An anonymous online account"], correct:2, re:"A water supplier may implement the program directly or by contract with the local health agency or another agency approved by the health agency. Source: former Title 17 CCR §7584; CCCPH."},
  {id:444, block:5, sec:"Water Purveyor Programs", q:"A water purveyor decides what backflow protection a customer needs based on a hazard assessment that classifies the premises as which of the following?", opts:["New construction or remodel only","Residential or commercial zoning only","Owner-occupied or rented only","A health hazard (contaminant) or a non-health hazard (pollutant)"], correct:3, re:"Hazard assessments classify the degree of hazard - health hazard (contaminant) vs. non-health hazard (pollutant) - which sets the required protection. Source: CCCPH; AWWA M14."},
  {id:445, block:5, sec:"Water Purveyor Programs", q:"Which type of backflow protection does a purveyor typically require for a premises classified only as a non-health hazard (pollutant)?", opts:["At minimum a double check valve assembly (DC)","No protection at all","An air gap only, never anything else","A simple gate valve"], correct:0, re:"Non-health (pollutant) hazards are commonly protected by an approved double check valve assembly, while health hazards require AG or RP. Source: CCCPH; former Title 17 CCR §7604 Table 1."},
  {id:446, block:5, sec:"Water Purveyor Programs", q:"Many purveyors send customers an annual reminder/notice for what purpose?", opts:["To advertise new water rates only","To remind the customer that the annual backflow assembly test is due","To request the customer mow the lawn","To collect the customer's email password"], correct:1, re:"Purveyors track assemblies and notify customers when the annual test is due, a core part of the testing procedure required of the program. Source: CCCPH testing program; purveyor programs."},
  {id:447, block:5, sec:"Water Purveyor Programs", q:"Within a public water system, the person who manages surveys, hazard assessments, and the overall program is generally a certified what?", opts:["Tax auditor","Heavy-equipment operator","Cross-connection control specialist","Pharmacist"], correct:2, re:"A certified cross-connection control specialist manages program functions such as surveys and hazard assessments; this is a distinct certification from the assembly tester. Source: SWRCB specialists certification; CCCPH."},
  {id:448, block:5, sec:"Water Purveyor Programs", q:"Under the CCCPH, the testers and specialists a public water system relies on must be what?", opts:["Licensed real-estate agents","Friends of the water board","Uncertified volunteers","Certified by an organization recognized (and later ANSI-accredited) under the CCCPH"], correct:3, re:"The PWS must ensure all backflow assembly testers and cross-connection control specialists it uses are certified per the CCCPH (recognized organizations, later ANSI/ISO 17024 accredited). Source: CCCPH Article on certification; SWRCB."},
  {id:449, block:5, sec:"Water Purveyor Programs", q:"A water purveyor's program must ensure actual and potential cross-connections are eliminated when possible or otherwise controlled by what?", opts:["Installation of approved backflow prevention assemblies or air gaps","Posting warning signs only","Painting the water meter","Sending an annual newsletter"], correct:0, re:"Programs must eliminate cross-connections where feasible, or control them with approved backflow prevention assemblies or air gaps consistent with the CCCPH. Source: CCCPH protection requirements."},
  {id:450, block:5, sec:"Water Purveyor Programs", q:"Which level of government most directly requires California water purveyors to operate a cross-connection control program?", opts:["The United Nations","The State of California (SWRCB), under state law and the CCCPH","A homeowners' association","A private insurance company"], correct:1, re:"State law (Health & Safety Code) and the SWRCB's CCCPH require California public water systems to implement cross-connection control programs. Source: CA Health & Safety Code §116800 et seq.; CCCPH."},
  {id:451, block:5, sec:"Water Purveyor Programs", q:"When a backflow assembly fails its annual test, what is the purveyor's program expectation of the customer?", opts:["Remove the assembly permanently","Ignore the failure until the next year","Have the assembly repaired and retested, then submit a passing report","Paint the assembly and do nothing else"], correct:2, re:"A failed assembly must be repaired (or replaced) and retested, with a passing report submitted to the purveyor to restore protection. Source: CCCPH testing/repair provisions; purveyor programs."},
  {id:452, block:5, sec:"Tester Duties & Reporting", q:"After completing a backflow assembly test, to whom must the certified tester's test report normally be submitted?", opts:["The local newspaper","The fire department dispatcher","The state parks department","The water purveyor (public water system)"], correct:3, re:"Test reports are submitted to the water purveyor responsible for the cross-connection control program (and a copy kept by the tester/owner). Source: CCCPH reporting; purveyor program rules."},
  {id:453, block:5, sec:"Tester Duties & Reporting", q:"Most water purveyors require that the test gauge used by a certified tester be calibrated within what timeframe?", opts:["Within the previous 12 months","Within the previous 10 years","Only once when purchased","Calibration is never required"], correct:0, re:"Most purveyors require the differential test gauge to have been calibrated within the previous 12 months, and the calibration date must be recorded on the report. Source: purveyor test-report requirements; AWWA M14/USC field-test procedures."},
  {id:454, block:5, sec:"Tester Duties & Reporting", q:"Which piece of information must a certified tester record on the test report to identify the specific assembly tested?", opts:["The tester's home phone bill","The assembly's serial number (matching the stamp on the device)","The customer's car license plate","The weather forecast"], correct:1, re:"The report must record the assembly serial number, which should match the serial number stamped on the assembly, along with type, make, model, and size. Source: standard backflow test-report fields; purveyor programs."},
  {id:455, block:5, sec:"Tester Duties & Reporting", q:"What identifying information about the tester must appear on a backflow assembly test report?", opts:["The tester's shoe size","The tester's favorite food","The tester's name and certification number (and its expiration)","The tester's vacation plans"], correct:2, re:"Reports must include the certified tester's name, certification number, and certification expiration date so the purveyor can verify credentials. Source: standard test-report fields; purveyor programs."},
  {id:456, block:5, sec:"Tester Duties & Reporting", q:"On a test report, the tester must clearly indicate which outcome of the test?", opts:["The phase of the moon","The stock market index","The tester's mood","Pass or Fail (and any repairs performed)"], correct:3, re:"The report must state the pass/fail result and document any cleaning or repairs performed before the final result. Source: standard backflow test-report fields."},
  {id:457, block:5, sec:"Tester Duties & Reporting", q:"What must a certified tester record on the report about the test equipment used?", opts:["The test kit make/model, serial number, and calibration date","The price the kit was purchased for","The store where the kit was bought","Nothing about the equipment"], correct:0, re:"The report must record the test kit/gauge make and model, its serial number, and its calibration date. Source: standard test-report fields; purveyor requirements."},
  {id:458, block:5, sec:"Tester Duties & Reporting", q:"If a tester discovers that an installed assembly is not an approved model for the application, what is the appropriate action?", opts:["Falsify the report to show it passed","Note it and report the deficiency to the purveyor; the assembly may need replacement","Ignore it because only the test result matters","Remove the serial-number stamp"], correct:1, re:"Testers must report deficiencies, including non-approved or wrong-application assemblies, to the purveyor; honest reporting protects public health. Source: CCCPH tester duties; USC FCCCHR approved-list use."},
  {id:459, block:5, sec:"Tester Duties & Reporting", q:"A certified backflow assembly tester's core ethical duty is best described as which of the following?", opts:["Test only assemblies that are easy to reach","Always pass every assembly to please the customer","Report test results truthfully and accurately","Keep all results secret from the purveyor"], correct:2, re:"Because the public's drinking water is at stake, a tester must report results truthfully and accurately; falsifying a backflow report can endanger health and is grounds for losing certification. Source: CCCPH; tester certification codes of conduct."},
  {id:460, block:5, sec:"Tester Duties & Reporting", q:"Before placing a repaired or newly installed assembly back into service, what must the certified tester do?", opts:["Wait one year before testing","Simply assume it works","Paint over the test cocks","Perform a field test to verify the assembly works correctly"], correct:3, re:"Newly installed, repaired, relocated, or replaced assemblies must be field tested to verify proper operation before being relied upon. Source: CCCPH; AWWA M14 field-test requirements."},
  {id:461, block:5, sec:"Tester Duties & Reporting", q:"To remain qualified to test in California under the CCCPH, a tester must do which of the following?", opts:["Keep a current certification from a recognized (and later ANSI-accredited) organization","Renew a fishing license","Register a new vehicle","Subscribe to a magazine"], correct:0, re:"Testers must maintain a current certification from a SWRCB-recognized organization (ANSI/ISO 17024-accredited from July 1, 2027) to test for CCCPH compliance. Source: SWRCB Backflow Tester Certification page; CCCPH."},
  {id:462, block:5, sec:"Tester Duties & Reporting", q:"Many tester certification programs require recertification on what cycle?", opts:["Once in a lifetime, never renewed","Periodically (commonly every three years)","Every week","Every 30 years"], correct:1, re:"Backflow tester certifications are time-limited and typically require recertification on a periodic cycle (commonly every three years). Source: California tester certification program descriptions (e.g., CA-NV AWWA, ASSE)."},
  {id:463, block:5, sec:"Tester Duties & Reporting", q:"Why must the serial number on the test report match the serial number stamped on the assembly?", opts:["To register the tester's car","To set the water bill","To confirm the correct, specific assembly was actually tested","To choose a paint color"], correct:2, re:"Matching serial numbers prove the report corresponds to the specific assembly in the field, preventing fraud and recordkeeping errors. Source: purveyor test-report requirements."},
  {id:464, block:5, sec:"Tester Duties & Reporting", q:"If a tester's test gauge is out of calibration, what should the tester do?", opts:["Borrow a customer's bathroom scale","Use it anyway and guess the readings","Round the readings up","Stop and have the gauge calibrated before reporting results as valid"], correct:3, re:"An out-of-calibration gauge yields unreliable readings; the tester must calibrate it before performing valid, reportable tests. Source: purveyor calibration requirements; field-test procedures."},
  {id:465, block:5, sec:"Tester Duties & Reporting", q:"A certified tester is generally expected to keep a copy of completed test reports for what reason?", opts:["For recordkeeping and to document compliance","To sell to advertisers","To wallpaper the office","There is no reason to keep them"], correct:0, re:"Testers keep copies of reports for recordkeeping and to document that required tests were performed and reported. Source: purveyor program/recordkeeping practice; CCCPH."},
  {id:466, block:5, sec:"Tester Duties & Reporting", q:"What should a certified tester do if a customer asks them to mark a failing assembly as 'passed'?", opts:["Mark it passed to keep the customer happy","Refuse; report the true failing result","Mark it passed but tell no one","Leave the report blank"], correct:1, re:"A tester must refuse to falsify a report; the true (failing) result must be reported so the assembly is repaired and the water supply protected. Source: tester certification codes of conduct; CCCPH."},
  {id:467, block:5, sec:"Tester Duties & Reporting", q:"On the test report, the date the gauge was last calibrated is required so the purveyor can confirm what?", opts:["The brand of the customer's car","The tester's age","That the gauge calibration is current (typically within 12 months)","The local weather"], correct:2, re:"The calibration date lets the purveyor verify the gauge was in current calibration (commonly within 12 months) when the test was performed. Source: purveyor test-report requirements."},
  {id:468, block:5, sec:"Tester Duties & Reporting", q:"Which information identifies the location the test applies to on a backflow assembly test report?", opts:["The state capital","The tester's birthday","The manufacturer's headquarters","The service address and the assembly's location on the premises"], correct:3, re:"Reports record the service address and the assembly's specific location so the purveyor can match it to program records. Source: standard test-report fields; CCCPH recordkeeping."},
  {id:469, block:5, sec:"Installation Standards & Approval", q:"For an air gap to be effective, what is the minimum vertical separation required between the supply outlet and the flood-level rim of the receiving vessel?", opts:["At least twice the diameter of the supply pipe, and never less than 1 inch","Exactly 1/8 inch","Equal to the pipe diameter only","Ten times the pipe diameter, minimum 3 feet"], correct:0, re:"An effective (approved) air gap must be at least twice the diameter of the supply pipe measured vertically above the flood-level rim, and in no case less than 1 inch. Source: AWWA M14; ASME A112.1.2."},
  {id:470, block:5, sec:"Installation Standards & Approval", q:"A reduced-pressure principle assembly (RP) should NOT be installed in which location?", opts:["Above grade in a well-drained area","A pit or any location subject to flooding/submersion","Indoors with adequate drainage","On a level pad above the relief-valve discharge point"], correct:1, re:"An RP assembly must not be submerged or installed where it can flood; its relief valve must discharge to air, and submersion would defeat protection and risk contamination. Source: AWWA M14; manufacturer/purveyor installation standards."},
  {id:471, block:5, sec:"Installation Standards & Approval", q:"A pressure vacuum breaker (PVB) must be installed at least how far above the highest downstream outlet/piping it serves?", opts:["At least 6 feet above","At or below grade","At least 12 inches above the highest downstream outlet","It does not matter where it is installed"], correct:2, re:"A PVB must be installed at least 12 inches above the highest downstream piping/outlet so the air inlet cannot be submerged and the air-break can function. Source: AWWA M14; ASSE 1020 / manufacturer instructions."},
  {id:472, block:5, sec:"Installation Standards & Approval", q:"Against which condition is a pressure vacuum breaker (PVB) NOT designed to protect?", opts:["Low downstream demand","Backsiphonage","Air entering the air inlet","Backpressure"], correct:3, re:"A PVB protects only against backsiphonage; it must not be used where backpressure can develop in the downstream piping. Source: AWWA M14; PVB application guidance."},
  {id:473, block:5, sec:"Installation Standards & Approval", q:"Why must a backflow prevention assembly be installed so that it is accessible?", opts:["So it can be tested annually and maintained or repaired","So it can be hidden from view","So children can play on it","So it can be buried completely"], correct:0, re:"Assemblies must be accessible for the required annual testing, maintenance, and repair; burying or enclosing them without access defeats the program. Source: AWWA M14; purveyor installation standards."},
  {id:474, block:5, sec:"Installation Standards & Approval", q:"For an installed backflow prevention assembly to be acceptable in a California program, it generally must be what?", opts:["The cheapest device available","An approved model (e.g., on the USC FCCCHR List or the purveyor's approved list)","Any homemade device","Painted a specific color regardless of approval"], correct:1, re:"Installed assemblies must be approved models acceptable to the purveyor - commonly those on the USC FCCCHR List or the agency's approved list. Source: USC FCCCHR List; CCCPH/purveyor requirements."},
  {id:475, block:5, sec:"Installation Standards & Approval", q:"The relief valve of a reduced-pressure principle assembly (RP) discharges to the atmosphere primarily to do what?", opts:["Increase downstream pressure","Cool the building","Dump water from the zone to prevent backflow when the checks are not sealing","Filter the water"], correct:2, re:"The RP relief valve opens to discharge the reduced-pressure zone to atmosphere, preventing contaminated water from backflowing when the check valves are not holding. Source: AWWA M14; USC field-test procedures."},
  {id:476, block:5, sec:"Installation Standards & Approval", q:"Because an RP assembly's relief valve can discharge water, the installation must provide for what?", opts:["No drainage at all","A sealed airtight chamber","Submersion in a sump","Adequate drainage/air gap at the relief-valve discharge"], correct:3, re:"RP installations must provide adequate drainage and an air gap at the relief-valve outlet to handle intermittent or catastrophic discharge without flooding or backflow. Source: AWWA M14; installation standards."},
  {id:477, block:5, sec:"Installation Standards & Approval", q:"A double check valve assembly (DC) is appropriate for which type of hazard?", opts:["Non-health (pollutant), low-hazard applications","High-hazard health applications such as chemical plants","Sewage treatment plant connections","Mortuary and hospital health hazards"], correct:0, re:"A DC assembly is used for non-health (pollutant) low-hazard applications; health hazards (contaminants) require an AG or RP. Source: AWWA M14; CCCPH/Title 17 hazard tables."},
  {id:478, block:5, sec:"Installation Standards & Approval", q:"Which assembly provides protection against both backsiphonage and backpressure for a health-hazard connection?", opts:["Pressure vacuum breaker (PVB)","Reduced-pressure principle assembly (RP)","Atmospheric (spill-resistant) vacuum breaker only","Hose-bibb vacuum breaker only"], correct:1, re:"An RP assembly protects against both backsiphonage and backpressure and is acceptable for health-hazard (contaminant) connections; PVB/AVB protect only against backsiphonage. Source: AWWA M14; CCCPH hazard provisions."},
  {id:479, block:5, sec:"Installation Standards & Approval", q:"The minimum dimensions of an air gap used for cross-connection control are defined in which standard referenced by California?", opts:["NFPA 70E","ASME boiler & pressure vessel code","ASME A112.1.2","FMVSS 121"], correct:2, re:"ASME A112.1.2 specifies minimum air gaps for plumbing fixtures and is referenced by the CCCPH for air-gap separations. Source: CCCPH; ASME A112.1.2."},
  {id:480, block:5, sec:"Installation Standards & Approval", q:"An air gap can be defeated (rendered ineffective) by which of the following?", opts:["Cleaning the basin","Painting the fixture","Increasing the gap well above the minimum","Submerging the supply outlet or reducing the gap below the minimum"], correct:3, re:"An air gap fails if the outlet is submerged or the vertical separation is reduced below the required minimum (2x pipe diameter, min 1 inch). Source: AWWA M14; ASME A112.1.2."},
  {id:481, block:5, sec:"Installation Standards & Approval", q:"Why must backflow prevention assemblies generally be installed in the correct orientation (e.g., RP and DC typically horizontal unless approved otherwise)?", opts:["Because approval and proper internal operation depend on installing per the listing/manufacturer instructions","Because vertical pipes are illegal","To match the building color","Orientation never matters"], correct:0, re:"Assemblies are approved and must be installed per their listing and manufacturer's instructions, including orientation; improper orientation can void approval and impair operation/testing. Source: USC FCCCHR approval; AWWA M14; manufacturer instructions."},
  {id:482, block:5, sec:"Installation Standards & Approval", q:"A new backflow prevention assembly installation in a California program generally requires what before it is relied upon?", opts:["Nothing at all","A permit/approval as required by the purveyor and an initial field test","Only a verbal agreement","A 10-year waiting period"], correct:1, re:"New installations are subject to purveyor approval/permitting as applicable and must pass an initial field test before being relied upon for protection. Source: CCCPH; purveyor installation/permit requirements."},
  {id:483, block:5, sec:"Installation Standards & Approval", q:"Which assembly is generally limited to low-to-moderate hazard backsiphonage-only situations and must be installed above the downstream piping?", opts:["Air gap on a sewage connection","Reduced-pressure principle assembly (RP)","Pressure vacuum breaker (PVB)","Double detector check (fire) on a chemical feed"], correct:2, re:"A PVB protects only against backsiphonage, is generally limited to lower-hazard applications, and must be installed at least 12 inches above the highest downstream outlet. Source: AWWA M14; PVB application/installation guidance."},
  {id:484, block:5, sec:"Installation Standards & Approval", q:"Installing a backflow prevention assembly below grade in a vault without proper drainage creates what risk?", opts:["Automatic compliance with all codes","Improved water taste","Lower water pressure that is always desirable","The assembly can be submerged in contaminated water, defeating protection and the relief function"], correct:3, re:"Below-grade/vault installations without drainage risk submerging the assembly (and an RP's relief vent) in contaminated water, defeating protection and creating a backflow hazard. Source: AWWA M14; installation standards."},
  {id:485, block:5, sec:"Job-Site Safety", q:"Under OSHA, an atmosphere is considered oxygen-deficient when the oxygen concentration falls below what level?", opts:["19.5 percent oxygen by volume","30 percent oxygen by volume","5 percent oxygen by volume","50 percent oxygen by volume"], correct:0, re:"OSHA defines an oxygen-deficient atmosphere as containing less than 19.5% oxygen by volume. Source: OSHA 29 CFR 1910.146 (Permit-required confined spaces)."},
  {id:486, block:5, sec:"Job-Site Safety", q:"A below-ground backflow assembly vault that is large enough to enter, has limited means of entry/exit, and is not designed for continuous occupancy is best classified as what?", opts:["An open field","A confined space","A standard office","A vehicle cab"], correct:1, re:"A vault/pit you can bodily enter, with limited entry/exit and not designed for continuous occupancy, meets OSHA's definition of a confined space (and may be permit-required). Source: OSHA 29 CFR 1910.146 definitions."},
  {id:487, block:5, sec:"Job-Site Safety", q:"Before entering a permit-required confined space, the internal atmosphere must be tested with a calibrated direct-reading instrument in which order?", opts:["Flammables first, then toxics, then oxygen","Toxics first, then oxygen, then flammables","Oxygen first, then flammable gases/vapors, then toxic contaminants","Order does not matter"], correct:2, re:"OSHA requires testing in the order: oxygen content first, then flammable gases and vapors, then potential toxic air contaminants. Source: OSHA 29 CFR 1910.146 App B."},
  {id:488, block:5, sec:"Job-Site Safety", q:"Why is oxygen tested first when evaluating a confined-space atmosphere?", opts:["It is an arbitrary tradition with no reason","Oxygen is the only hazard that matters","Toxics cannot be measured at all","Most combustible-gas meters are oxygen-dependent and give unreliable readings in low oxygen"], correct:3, re:"Oxygen is tested first because most combustible-gas (flammable) meters are oxygen-dependent and will not read reliably in an oxygen-deficient atmosphere. Source: OSHA 29 CFR 1910.146 App B."},
  {id:489, block:5, sec:"Job-Site Safety", q:"Which characteristic would make a confined space a 'permit-required' confined space under OSHA?", opts:["It contains or could contain a hazardous atmosphere","It has good lighting","It is freshly painted","It is near a parking lot"], correct:0, re:"A permit-required confined space has one or more hazards: a hazardous atmosphere, engulfment potential, an inwardly converging/entrapment configuration, or any other recognized serious hazard. Source: OSHA 29 CFR 1910.146 definitions."},
  {id:490, block:5, sec:"Job-Site Safety", q:"A worker testing a backflow assembly in a roadway must wear high-visibility safety apparel meeting which requirement?", opts:["No special clothing","ANSI/ISEA 107 Performance Class 2 or 3","A plain white t-shirt","Dark-colored clothing for stealth"], correct:1, re:"Workers exposed to traffic in the right-of-way must wear high-visibility apparel meeting ANSI/ISEA 107 Performance Class 2 or 3. Source: MUTCD Part 6 (Temporary Traffic Control); ANSI/ISEA 107."},
  {id:491, block:5, sec:"Job-Site Safety", q:"Temporary traffic control around a work zone in the public roadway is governed by which national document?", opts:["The AWWA M14 manual","The National Electrical Code","The Manual on Uniform Traffic Control Devices (MUTCD), Part 6","The EPA refrigerant rules"], correct:2, re:"MUTCD Part 6 establishes standards for temporary traffic control (work-zone) setups on roadways. Source: FHWA MUTCD Part 6."},
  {id:492, block:5, sec:"Job-Site Safety", q:"An RP assembly's relief valve can discharge a sudden spray or stream of water during testing. What does this hazard mean for the tester?", opts:["It guarantees the test passed","It is harmless and can be ignored","It means the gauge is broken","Be prepared for water discharge and avoid eye/face injury and slip hazards"], correct:3, re:"Water under pressure can discharge from the relief valve or test cocks; testers should protect their eyes/face, manage slip hazards, and control the discharge. Source: AWWA M14 safety guidance; manufacturer instructions."},
  {id:493, block:5, sec:"Job-Site Safety", q:"Why must a tester be cautious about backflow of contaminated water while servicing an assembly that protects a health-hazard premises?", opts:["Contaminated water can pose a serious health risk if it reaches the tester or potable supply","It only affects the water bill","Contaminated water is always safe to drink","It improves water quality"], correct:0, re:"Assemblies on health-hazard connections can hold contaminated water; mishandling during service can expose the tester or the potable supply, so caution and isolation are required. Source: AWWA M14; CCCPH hazard context."},
  {id:494, block:5, sec:"Job-Site Safety", q:"For a permit-required confined space entry, OSHA requires a person stationed outside the space to monitor entrants. What is this person called?", opts:["A bystander","An attendant","A customer","A flagger"], correct:1, re:"OSHA requires an attendant stationed outside a permit-required confined space to monitor entrants and order evacuation if needed. Source: OSHA 29 CFR 1910.146."},
  {id:495, block:5, sec:"Job-Site Safety", q:"If a permit-required confined space contains a hazardous atmosphere, what control does OSHA require before and during entry where feasible?", opts:["Adding a flammable gas","Sealing the space airtight","Forced-air ventilation to eliminate/control the hazardous atmosphere","Removing all monitoring equipment"], correct:2, re:"Where used, forced-air ventilation from a clean source must eliminate the hazardous atmosphere and continue while workers are inside; atmosphere must remain safe during occupancy. Source: OSHA 29 CFR 1910.146."},
  {id:496, block:5, sec:"Job-Site Safety", q:"To safely isolate a backflow assembly for repair, the tester should generally do what first?", opts:["Increase the supply pressure","Open all test cocks while under full pressure and walk away","Cut the pipe immediately","Close the upstream and downstream shutoff valves to depressurize the assembly"], correct:3, re:"Isolating the assembly by closing its shutoff valves depressurizes it for safe service and prevents uncontrolled water discharge. Source: AWWA M14; USC field-test/maintenance procedures."},
  {id:497, block:5, sec:"Job-Site Safety", q:"What is the primary purpose of an entry permit for a permit-required confined space?", opts:["To document hazards, controls, and authorization before entry","To collect a parking fee","To advertise the work","To replace atmospheric testing"], correct:0, re:"The entry permit documents the space, hazards, atmospheric test results, controls, and authorization, and must be completed before entry; it supplements, not replaces, testing. Source: OSHA 29 CFR 1910.146."},
  {id:498, block:5, sec:"Job-Site Safety", q:"When flaggers are used to control traffic in a work zone, what is their primary hand-signaling device under the MUTCD?", opts:["A flashlight only","A STOP/SLOW paddle (at least 18 inches)","Their bare hands only","A whistle only"], correct:1, re:"MUTCD requires flaggers to use a STOP/SLOW paddle (at least 18 inches) as the primary hand-signaling device and to wear high-visibility apparel. Source: FHWA MUTCD Part 6, Chapter 6E (Flagger Control)."},
  {id:499, block:5, sec:"Job-Site Safety", q:"Working with water under pressure, a tester should treat test cocks and fittings how?", opts:["Strike them with a hammer to loosen","Force them open as fast as possible","Open and close them carefully, anticipating pressurized water release","Assume they are never pressurized"], correct:2, re:"Test cocks and fittings can release pressurized water suddenly; opening/closing them slowly and deliberately prevents spray injuries and loss of control of the discharge. Source: AWWA M14 safety guidance; field-test procedures."},
  {id:500, block:5, sec:"Job-Site Safety", q:"Overall, the safety practices a certified tester follows (confined-space precautions, traffic control, and controlling pressurized/contaminated water) are intended to protect whom?", opts:["No one in particular","Only the water utility's profits","Only the equipment manufacturer","The tester, the public, and the potable water supply"], correct:3, re:"Job-site safety practices protect the tester, the public around the work zone, and the integrity of the potable water supply that backflow prevention exists to safeguard. Source: OSHA 29 CFR 1910.146; MUTCD Part 6; AWWA M14."}
];
